// ─── Conversation Search ────────────────────────────────────────────────
let convSearchTimer = null;

// Highlight every search token (case-insensitive) inside an already-escaped
// preview snippet. The output is HTML-safe because we esc() first, then
// inject only `<mark>` tags which we trust.
function highlightTokens(escaped, query) {
  if (!query) return escaped;
  const tokens = query.match(/[\w가-힣]+/gu) || [];
  if (!tokens.length) return escaped;
  // Sort longest first so 'queryparser' beats 'query' on overlap
  tokens.sort((a, b) => b.length - a.length);
  // Build a single regex with all tokens, escaping regex specials
  const pattern = tokens
    .map(t => t.replace(/[.*+?^${}()|[\]\\]/g, '\\$&'))
    .join('|');
  const re = new RegExp(`(${pattern})`, 'giu');
  return escaped.replace(re, '<mark class="bg-amber-400/30 text-amber-200 rounded px-0.5">$1</mark>');
}

function searchConversations(q) {
  clearTimeout(convSearchTimer);
  const box = document.getElementById('convSearchResults');
  if (!q || q.length < 2) { box.classList.add('hidden'); box.textContent=''; return; }
  convSearchTimer = setTimeout(async () => {
    try {
      if (state.convSource === 'claude-ai') {
        const d = await safeFetch(`/api/claude-ai/search?q=${encodeURIComponent(q)}&limit=20&_t=${Date.now()}`);
        box.textContent = '';
        if (!d.results?.length) {
          const empty = document.createElement('div');
          empty.className = 'px-3 py-2 text-[10px] text-white/15';
          empty.textContent = '결과 없음';
          box.appendChild(empty);
          box.classList.remove('hidden');
          return;
        }
        d.results.forEach(r => {
          const row = document.createElement('div');
          row.className = 'px-3 py-2 border-b border-white/[0.03] cursor-pointer spring hover:bg-white/[0.03]';
          const top = document.createElement('div');
          top.className = 'flex justify-between items-center';
          const name = document.createElement('span');
          name.className = 'text-[10px] font-semibold text-accent/60 truncate';
          name.textContent = r.conversation_name || '(unnamed)';
          const when = document.createElement('span');
          when.className = 'text-[9px] text-white/15 flex-shrink-0 ml-2';
          when.textContent = (r.sender === 'human' ? '사용자' : 'AI') + ' · ' + fmtTime(r.created_at);
          top.appendChild(name);
          top.appendChild(when);
          const preview = document.createElement('div');
          preview.className = 'text-[10px] text-white/35 mt-0.5 line-clamp-2';
          preview.textContent = (r.snippet || '').slice(0, 200);
          row.appendChild(top);
          row.appendChild(preview);
          row.onclick = () => openCaiConvFromSearch(r.conversation_uuid);
          box.appendChild(row);
        });
        box.classList.remove('hidden');
        return;
      }
      const d = await safeFetch(`/api/sessions/search?q=${encodeURIComponent(q)}&limit=20&_t=${Date.now()}`);
      if (!d.results?.length) { box.innerHTML='<div class="px-3 py-2 text-[10px] text-white/15">결과 없음</div>'; box.classList.remove('hidden'); return; }
      box.innerHTML = d.results.map(r => {
        const safeName = highlightTokens(esc(r.project_name || ''), q);
        const safePreview = highlightTokens(esc((r.content_preview || '').slice(0, 200)), q);
        return `<div class="px-3 py-2 border-b border-white/[0.03] cursor-pointer spring hover:bg-white/[0.03]" onclick="openConvFromSearch('${esc(r.session_id)}',${r.id})">
          <div class="flex justify-between items-center">
            <span class="text-[10px] font-semibold text-accent/60">${safeName}</span>
            <span class="text-[9px] text-white/15">${r.role==='user'?'사용자':'AI'} · ${fmtTime(r.timestamp)}</span>
          </div>
          <div class="text-[10px] text-white/35 mt-0.5 line-clamp-2">${safePreview}</div>
        </div>`;
      }).join('');
      box.classList.remove('hidden');
    } catch(e) {
      console.error('searchConv:', e);
      showToast('검색 실패: ' + (e.message || e), { type: 'error' });
    }
  }, 400);
}

async function openCaiConvFromSearch(uuid) {
  document.getElementById('convSearchResults').classList.add('hidden');
  try {
    const conv = await safeFetch(`/api/claude-ai/conversations/${encodeURIComponent(uuid)}`);
    openClaudeAiConversation(uuid, conv);
  } catch (e) { reportError('openCaiConvFromSearch', e); }
}
async function openConvFromSearch(sid, messageId) {
  const searchInput = document.getElementById('convSearch');
  const keyword = searchInput?.value || '';
  document.getElementById('convSearchResults').classList.add('hidden');
  try {
    const s = await safeFetch(`/api/sessions/${sid}`);
    if (messageId) {
      // Find the position of the target message, then load a window around it
      const pos = await safeFetch(`/api/sessions/${encodeURIComponent(sid)}/message-position?message_id=${messageId}`);
      const targetOffset = Math.max(0, pos.position - 50); // load 50 before target
      const data = await safeFetch(`/api/sessions/${encodeURIComponent(sid)}/messages?limit=500&offset=${targetOffset}`);
      const msgs = data.messages || [];
      // Render directly (bypass openConversation's default 200-limit load)
      await openConversation(sid, s);
      // If we loaded from a non-zero offset, the viewer already has the first 200.
      // We need to reload with the correct window. Clear and re-render.
      if (targetOffset > 0) {
        const c = document.getElementById('convMessages');
        c.textContent = '';
        state.convMessages = msgs;
        let prevBranch = null;
        let prevTs = null;
        msgs.forEach(m => {
          _renderTimeGap(c, prevTs, m.timestamp);
          _renderSingleMessage(c, m, msgs, prevBranch);
          if (m.git_branch) prevBranch = m.git_branch;
          prevTs = m.timestamp;
        });
        renderConvStats(msgs, s);
        const countLabel = document.getElementById('convMsgCount');
        if (countLabel) {
          const u = msgs.filter(m => m.role === 'user').length;
          const a = msgs.filter(m => m.role === 'assistant').length;
          countLabel.textContent = `${fmtN(msgs.length)}\uAC74 (\uC0AC\uC6A9\uC790 ${u} \u00b7 \uC5B4\uC2DC\uC2A4\uD134\uD2B8 ${a}) \u2014 \uC624\uD504\uC14B ${fmtN(targetOffset)}`;
        }
      }
      // Scroll to the target message
      const targetEl = document.querySelector(`#convMessages [data-msg-role]`);
      const allEls = document.querySelectorAll('#convMessages [data-msg-role]');
      const targetLocalIdx = pos.position - targetOffset;
      if (allEls[targetLocalIdx]) {
        allEls[targetLocalIdx].classList.add('conv-msg-focused');
        allEls[targetLocalIdx].scrollIntoView({ behavior: 'smooth', block: 'center' });
        _convFocusIdx = targetLocalIdx;
      }
    } else {
      await openConversation(sid, s);
    }
    // Auto-trigger inline search with the keyword
    if (keyword) {
      const inlineInput = document.getElementById('convInlineSearch');
      if (inlineInput) {
        inlineInput.value = keyword;
        _convInlineSearch(keyword);
      }
    }
  } catch(e) { console.error('openConvFromSearch:', e); }
}

// ─── Project Management ─────────────────────────────────────────────────
async function deleteProject(name, path) {
  try {
    const qs = path ? `?path=${encodeURIComponent(path)}` : '';
    const pv = await fetch(
      `/api/projects/${encodeURIComponent(name)}${qs}`,
      { method: 'DELETE' }
    ).then(r => r.json());
    openDeleteConfirm({
      target: name,
      message: `이 프로젝트의 ${fmtN(pv.sessions)}개 세션, ${fmtN(pv.messages)}건 메시지, ${fmt$(pv.cost)} 비용이 영구 삭제됩니다.`,
      onConfirm: async () => {
        try {
          const confirmQs = path
            ? `?path=${encodeURIComponent(path)}&confirm=true`
            : '?confirm=true';
          await fetch(
            `/api/projects/${encodeURIComponent(name)}${confirmQs}`,
            { method: 'DELETE' }
          );
          loadProjects(); loadStats(); loadPeriods(); loadTopProjects();
          showToast(`"${name}" 삭제 완료`, { type: 'success', duration: 2000 });
        } catch (e) {
          showToast('삭제 실패: ' + (e.message || e), { type: 'error' });
        }
      },
    });
  } catch (e) {
    console.error('deleteProject:', e);
    showToast('미리보기 실패: ' + (e.message || e), { type: 'error' });
  }
}
// Project modal state
let projectData = null;
let projectConvData = null;
let projectConvOrder = 'asc';
let projectSessSort = { key:'updated_at', order:'desc' };

function _projQs(path) {
  return path ? `?path=${encodeURIComponent(path)}` : '';
}

async function showProjectDetail(name, path) {
  const modal = document.getElementById('projectModal');
  document.getElementById('projModalTitle').textContent = name || '—';
  document.getElementById('projModalPath').textContent = path || '';
  modal.dataset.project = name;
  modal.dataset.projectPath = path || '';
  modal.style.display = 'flex';
  setTimeout(() => modal.querySelector('[role="tab"]')?.focus(), 100);
  projectData = null;
  projectConvData = null;
  projectSessSort = { key:'updated_at', order:'desc' };
  // Deep-link into this project via URL hash
  const hashPath = path ? `?path=${encodeURIComponent(path)}` : '';
  history.replaceState(null, '', `#/project/${encodeURIComponent(name)}${hashPath}`);
  setProjectTab('overview', false);
  document.getElementById('projTabContent').innerHTML = '<div class="text-center text-white/25 text-xs py-12 dots">로딩 중</div>';
  try {
    projectData = await safeFetch(
      `/api/projects/${encodeURIComponent(name)}/stats${_projQs(path)}`);
    renderProjectOverview();
  } catch (e) {
    document.getElementById('projTabContent').innerHTML =
      `<div class="text-center text-red-400/60 text-xs py-12">로딩 실패: ${esc(e.message)}</div>`;
  }
}

// Closing the modal should also clear the hash so refresh lands back on list
function closeProjectModal() {
  document.getElementById('projectModal').style.display = 'none';
  if (location.hash.startsWith('#/project/')) {
    history.replaceState(null, '', '#/projects');
  }
}

function setProjectTab(tab, reload = true) {
  document.querySelectorAll('#projectModal .proj-tab').forEach(t => {
    const active = t.dataset.tab === tab;
    t.classList.toggle('text-accent', active);
    t.classList.toggle('border-accent', active);
    t.classList.toggle('text-white/35', !active);
    t.classList.toggle('border-transparent', !active);
    t.setAttribute('aria-selected', active ? 'true' : 'false');
  });
  if (!reload) return;
  if (tab === 'overview') renderProjectOverview();
  else if (tab === 'sessions') renderProjectSessionsTab();
  else if (tab === 'conversations') loadProjectMessages();
}

// Bind tab clicks once (script runs at end of body, DOM is ready)
document.querySelectorAll('#projectModal .proj-tab').forEach(btn => {
  btn.addEventListener('click', () => setProjectTab(btn.dataset.tab));
});
// Arrow key navigation for project modal tab strip (LOW-2)
document.querySelectorAll('#projectModal [role="tab"]').forEach((tab, i, tabs) => {
  tab.addEventListener('keydown', (e) => {
    let target;
    if (e.key === 'ArrowRight') target = tabs[(i + 1) % tabs.length];
    else if (e.key === 'ArrowLeft') target = tabs[(i - 1 + tabs.length) % tabs.length];
    if (target) { e.preventDefault(); target.focus(); target.click(); }
  });
});

function renderProjectOverview() {
  if (!projectData) return;
  const s = projectData.summary;
  document.getElementById('projTabContent').innerHTML = `
    <div class="grid grid-cols-2 sm:grid-cols-4 gap-3">
      <div class="bg-white/5 ring-1 ring-white/[0.07] rounded-xl p-4">
        <div class="text-[10px] text-white/35 uppercase font-bold tracking-widest">세션</div>
        <div class="text-2xl font-extrabold text-white/90 mt-1 tabular-nums">${fmtN(s.sessions)}</div>
      </div>
      <div class="bg-white/5 ring-1 ring-white/[0.07] rounded-xl p-4">
        <div class="text-[10px] text-white/35 uppercase font-bold tracking-widest">메시지</div>
        <div class="text-2xl font-extrabold text-white/90 mt-1 tabular-nums">${fmtN(s.messages)}</div>
      </div>
      <div class="bg-white/5 ring-1 ring-white/[0.07] rounded-xl p-4">
        <div class="text-[10px] text-white/35 uppercase font-bold tracking-widest">비용</div>
        <div class="text-2xl font-extrabold text-amber-400/90 mt-1 tabular-nums">${fmt$(s.cost)}</div>
      </div>
      <div class="bg-white/5 ring-1 ring-white/[0.07] rounded-xl p-4">
        <div class="text-[10px] text-white/35 uppercase font-bold tracking-widest">캐시 읽기</div>
        <div class="text-2xl font-extrabold text-cyan-400/85 mt-1 tabular-nums">${fmtTok(s.cache_read_tokens)}</div>
      </div>
    </div>
    <div class="mt-5 text-[11px] text-white/45 flex flex-wrap gap-x-6 gap-y-1.5 px-1">
      <span>첫 활동: <span class="text-white/65">${fmtTime(s.first_active)}</span></span>
      <span>마지막 활동: <span class="text-white/65">${fmtTime(s.last_active)}</span></span>
      <span>입력: <span class="text-white/65 tabular-nums">${fmtTok(s.input_tokens)}</span></span>
      <span>출력: <span class="text-emerald-400/75 tabular-nums">${fmtTok(s.output_tokens)}</span></span>
    </div>
    ${projectData.models && projectData.models.length ? `
    <div class="mt-6">
      <div class="text-[10px] font-bold text-white/45 uppercase tracking-widest mb-2">모델별 사용량</div>
      <div class="space-y-1.5">
        ${projectData.models.map(m => `
          <div class="flex items-center justify-between text-[11px] bg-white/[0.03] ring-1 ring-white/[0.05] rounded-lg px-3 py-2">
            <span class="text-white/75 font-semibold">${esc(m.model)}</span>
            <div class="flex items-center gap-5">
              <span class="text-white/45 tabular-nums">${m.cnt}건</span>
              <span class="text-amber-400/85 font-bold tabular-nums">${fmt$(m.cost)}</span>
            </div>
          </div>
        `).join('')}
      </div>
    </div>` : ''}
    ${projectData.daily && projectData.daily.length ? `
    <div class="mt-6">
      <div class="text-[10px] font-bold text-white/45 uppercase tracking-widest mb-2">최근 일별 비용</div>
      <div class="bg-white/[0.02] ring-1 ring-white/[0.06] rounded-xl p-3">
        <div style="height:200px;position:relative"><canvas id="projDailyChart"></canvas></div>
      </div>
    </div>` : ''}
  `;
  // Draw the daily cost chart after the container is in the DOM.
  if (projectData.daily && projectData.daily.length) {
    renderProjectDailyChart(projectData.daily);
  }
}

function renderProjectDailyChart(daily) {
  const canvas = document.getElementById('projDailyChart');
  if (!canvas || typeof Chart === 'undefined') return;
  // daily comes in DESC order — reverse to show oldest → newest on the X axis
  const sorted = [...daily].reverse();
  const labels = sorted.map(d => d.date ? d.date.slice(5) : '');
  const costs = sorted.map(d => Number(d.cost) || 0);
  const msgs = sorted.map(d => Number(d.messages) || 0);
  // Destroy any prior instance on the same canvas (modal reopened)
  if (state.charts.projDaily) { try { state.charts.projDaily.destroy(); } catch {} state.charts.projDaily = null; }
  state.charts.projDaily = new Chart(canvas, {
    type: 'bar',
    data: {
      labels,
      datasets: [
        {
          type: 'bar',
          label: '비용',
          data: costs,
          backgroundColor: 'rgba(251,191,36,0.35)',
          borderColor: '#fbbf24',
          borderWidth: 1,
          borderRadius: 3,
          yAxisID: 'y',
        },
        {
          type: 'line',
          label: '메시지',
          data: msgs,
          borderColor: 'rgba(96,165,250,0.85)',
          backgroundColor: 'rgba(96,165,250,0.10)',
          borderWidth: 1.5,
          tension: 0.3,
          pointRadius: 1.5,
          yAxisID: 'y1',
        },
      ],
    },
    options: {
      responsive: true,
      maintainAspectRatio: false,
      animation: { duration: 350 },
      plugins: {
        legend: {
          display: true,
          position: 'top',
          align: 'end',
          labels: legendLabels({ boxWidth: 10, font: { size: 10, family: 'Pretendard' } }),
        },
        tooltip: tooltipOpts({
          callbacks: {
            label: ctx => ctx.dataset.label === '비용'
              ? ` ${fmt$(ctx.raw)}`
              : ` ${fmtN(ctx.raw)}건`,
          },
        }),
      },
      scales: {
        x: {
          grid: grd(),
          ticks: { ...tck(), font: { size: 9, family: 'Pretendard' }, maxTicksLimit: 10, maxRotation: 0 },
        },
        y: {
          position: 'left',
          grid: grd(),
          ticks: {
            color: 'rgba(251,191,36,.75)', font: { size: 9, family: 'Pretendard' },
            callback: v => '$' + v,
          },
        },
        y1: {
          position: 'right',
          grid: { display: false },
          ticks: {
            color: 'rgba(96,165,250,.75)', font: { size: 9, family: 'Pretendard' },
            callback: v => fmtTok(v),
          },
        },
      },
    },
  });
}

function renderProjectSessionsTab() {
  if (!projectData) { document.getElementById('projTabContent').innerHTML = '<div class="text-center text-white/25 text-xs py-12">데이터 없음</div>'; return; }
  const rows = [...(projectData.sessions || [])];
  const { key, order } = projectSessSort;
  const getVal = (s, k) => {
    if (k === 'updated_at' || k === 'created_at') return s[k] || '';
    if (k === 'cost')     return s.cost_usd || 0;
    if (k === 'messages') return s.message_count || 0;
    if (k === 'model')    return s.model || '';
    if (k === 'input')    return s.total_input_tokens || 0;
    if (k === 'output')   return s.total_output_tokens || 0;
    if (k === 'cache')    return s.total_cache_read_tokens || 0;
    return s[k] || 0;
  };
  rows.sort((a, b) => {
    const av = getVal(a, key), bv = getVal(b, key);
    const cmp = av < bv ? -1 : av > bv ? 1 : 0;
    return order === 'asc' ? cmp : -cmp;
  });
  const th = (col, label, cls='text-left') => {
    const active = projectSessSort.key === col;
    const arr = active
      ? (projectSessSort.order === 'asc' ? '<span class="text-accent ml-1">↑</span>' : '<span class="text-accent ml-1">↓</span>')
      : '<span class="text-white/15 ml-1">↕</span>';
    return `<th class="${cls} px-3 py-2.5 font-bold cursor-pointer select-none hover:text-white/70 spring" onclick="sortProjectSessions('${col}')">${label}${arr}</th>`;
  };
  document.getElementById('projTabContent').innerHTML = `
    <div class="overflow-x-auto bg-white/[0.02] ring-1 ring-white/[0.06] rounded-xl">
      <table class="w-full text-[12px]">
        <thead>
          <tr class="text-[10px] text-white/35 uppercase tracking-widest border-b border-white/[0.06]">
            ${th('updated_at', '시각', 'text-left')}
            ${th('model', '모델', 'text-left')}
            ${th('messages', '메시지', 'text-right')}
            ${th('input', '입력', 'text-right')}
            ${th('output', '출력', 'text-right')}
            ${th('cache', '캐시', 'text-right')}
            ${th('cost', '비용', 'text-right')}
            <th class="text-center px-3 py-2.5 font-bold text-white/35 w-20">대화</th>
          </tr>
        </thead>
        <tbody class="text-white/70">
          ${rows.length === 0 ? `<tr><td colspan="8" class="text-center py-10 text-white/25">세션 없음</td></tr>` : rows.map(s => {
            const sTagList = (s.tags || '').split(',').map(t => t.trim()).filter(Boolean);
            const sTagRow = sTagList.length
              ? `<div class="mt-1 flex flex-wrap gap-1">${sTagList.map(t => `<span class="tag-badge">#${esc(t)}</span>`).join('')}</div>`
              : '';
            return `
            <tr class="border-b border-white/[0.03] hover:bg-white/[0.04] spring">
              <td class="px-3 py-3">
                <div class="text-[11px] font-semibold text-white/80">${fmtTime(s.updated_at)}</div>
                <div class="text-[9px] text-white/30 font-mono mt-0.5">${esc((s.id||'').slice(0,8))}${s.pinned ? ' <span class="text-accent">★</span>' : ''}</div>
                ${sTagRow}
              </td>
              <td class="px-3 py-3"><span class="text-[10px] px-2 py-0.5 rounded-full bg-white/5 text-white/50 whitespace-nowrap">${esc(shortModel(s.model||''))}</span></td>
              <td class="px-3 py-3 text-right tabular-nums">${fmtN(s.message_count||0)}</td>
              <td class="px-3 py-3 text-right text-white/55 tabular-nums">${fmtTok(s.total_input_tokens||0)}</td>
              <td class="px-3 py-3 text-right text-emerald-400/75 tabular-nums">${fmtTok(s.total_output_tokens||0)}</td>
              <td class="px-3 py-3 text-right text-cyan-400/75 tabular-nums">${fmtTok(s.total_cache_read_tokens||0)}</td>
              <td class="px-3 py-3 text-right"><span class="text-[11px] px-2 py-0.5 rounded-full bg-amber-500/10 text-amber-400/85 font-bold tabular-nums">${fmt$(s.cost_usd)}</span></td>
              <td class="px-3 py-3 text-center">
                <button onclick="openConvFromProject('${s.id}')" title="대화 보기" class="text-white/30 hover:text-accent spring"><iconify-icon icon="solar:arrow-right-linear" width="14"></iconify-icon></button>
              </td>
            </tr>
          `;
          }).join('')}
        </tbody>
      </table>
    </div>
  `;
}

function sortProjectSessions(col) {
  if (projectSessSort.key === col) projectSessSort.order = projectSessSort.order === 'asc' ? 'desc' : 'asc';
  else { projectSessSort.key = col; projectSessSort.order = 'desc'; }
  renderProjectSessionsTab();
}

async function openConvFromProject(sid) {
  document.getElementById('projectModal').style.display = 'none';
  const cn = document.querySelector('[data-view="conversations"]');
  if (cn && !cn.classList.contains('active')) cn.click();
  try {
    const s = await safeFetch(`/api/sessions/${sid}`);
    openConversation(sid, s);
  } catch (e) { console.error('openConvFromProject:', e); }
}

const PROJ_MSG_PAGE = 300;
let projectConvOffset = 0;

async function loadProjectMessages(reset = true) {
  const modal = document.getElementById('projectModal');
  const name = modal.dataset.project;
  const path = modal.dataset.projectPath || '';
  if (!name) return;
  const content = document.getElementById('projTabContent');
  if (reset) {
    projectConvOffset = 0;
    projectConvData = null;
    content.innerHTML = '<div class="text-center text-white/25 text-xs py-12 dots">대화 불러오는 중</div>';
  }
  const pathQs = path ? `&path=${encodeURIComponent(path)}` : '';
  try {
    const data = await safeFetch(
      `/api/projects/${encodeURIComponent(name)}/messages` +
      `?limit=${PROJ_MSG_PAGE}&offset=${projectConvOffset}&order=${projectConvOrder}${pathQs}`);
    if (reset || !projectConvData) {
      projectConvData = data;
    } else {
      // append
      projectConvData.messages = (projectConvData.messages || []).concat(data.messages || []);
      projectConvData.total = data.total;
    }
    projectConvOffset += (data.messages || []).length;
    renderProjectMessages();
  } catch (e) {
    content.innerHTML = `<div class="text-center text-red-400/60 text-xs py-12">로딩 실패: ${esc(e.message)}</div>`;
  }
}

function setProjConvOrder(o) {
  if (projectConvOrder === o) return;
  projectConvOrder = o;
  loadProjectMessages(true);
}

function loadMoreProjectMessages() {
  loadProjectMessages(false);
}

function renderProjectMessages() {
  const content = document.getElementById('projTabContent');
  if (!projectConvData) { content.innerHTML = '<div class="text-center text-white/25 text-xs py-12">데이터 없음</div>'; return; }
  const msgs = projectConvData.messages || [];
  const total = projectConvData.total || 0;
  const header = `
    <div class="sticky top-0 bg-[#0f0f0f]/95 backdrop-blur-sm -mx-6 -mt-6 px-6 pt-4 pb-3 mb-4 border-b border-white/[0.05] flex items-center justify-between z-10">
      <div class="text-[11px] text-white/55">
        <span class="font-bold tabular-nums text-white/80">${fmtN(msgs.length)}</span>
        <span class="text-white/30"> / ${fmtN(total)}</span>
        <span class="ml-1">건 표시</span>
      </div>
      <div class="flex items-center gap-1.5">
        <span class="text-[9px] text-white/30 uppercase font-bold tracking-widest mr-1">정렬</span>
        <button onclick="setProjConvOrder('asc')" class="px-3 py-1 rounded-full border spring text-[10px] font-bold ${projectConvOrder==='asc'?'bg-accent/15 text-accent border-accent/30':'text-white/45 border-white/[0.07] hover:text-white/70'}">오래된 순</button>
        <button onclick="setProjConvOrder('desc')" class="px-3 py-1 rounded-full border spring text-[10px] font-bold ${projectConvOrder==='desc'?'bg-accent/15 text-accent border-accent/30':'text-white/45 border-white/[0.07] hover:text-white/70'}">최신 순</button>
      </div>
    </div>`;
  if (!msgs.length) { content.innerHTML = header + '<div class="text-center text-white/25 text-xs py-12">메시지 없음</div>'; return; }
  let html = header + '<div class="space-y-3">';
  let lastSid = null;
  msgs.forEach(m => {
    if (m.session_id !== lastSid) {
      html += `
        <div class="flex items-center gap-3 pt-4 pb-2">
          <div class="h-px bg-white/[0.08] flex-1"></div>
          <span class="text-[9px] font-mono text-white/45 px-2.5 py-1 rounded-full bg-white/[0.04] ring-1 ring-white/[0.06] whitespace-nowrap">세션 ${esc((m.session_id||'').slice(0,8))} · ${fmtTime(m.timestamp)}</span>
          <div class="h-px bg-white/[0.08] flex-1"></div>
        </div>`;
      lastSid = m.session_id;
    }
    const align = m.role === 'user' ? 'items-end' : 'items-start';
    const bg = m.role === 'user'
      ? 'bg-accent/10 ring-1 ring-accent/20 text-white/85'
      : 'bg-white/[0.04] ring-1 ring-white/[0.06] text-white/75';
    const body = renderContent(m);
    const parts = [`<span>${m.role === 'user' ? '사용자' : '어시스턴트'}</span>`, `<span>${fmtTime(m.timestamp)}</span>`];
    if (m.role === 'assistant') {
      if (m.input_tokens || m.output_tokens) parts.push(`<span class="text-cyan-400/60">↑${fmtTok(m.input_tokens)} ↓${fmtTok(m.output_tokens)}</span>`);
      if (m.cost_usd) parts.push(`<span class="text-amber-400/75">${fmt$(m.cost_usd)}</span>`);
      if (m.model) parts.push(`<span class="text-purple-400/60">${esc(shortModel(m.model))}</span>`);
    }
    html += `
      <div class="flex flex-col ${align}">
        <div class="max-w-[92%] px-4 py-3 rounded-2xl text-[12px] leading-relaxed ${bg}">${body}</div>
        <div class="text-[9px] text-white/30 mt-1 flex gap-2 items-center px-1">${parts.join(' · ')}</div>
      </div>`;
  });
  html += '</div>';
  if (total > msgs.length) {
    html += `
      <div class="text-center py-4">
        <button onclick="loadMoreProjectMessages()"
                class="px-4 py-1.5 rounded-full text-[11px] font-bold bg-accent/10 text-accent border border-accent/25 hover:scale-[1.02] active:scale-[0.98] spring">
          더 보기 (${fmtN(msgs.length)} / ${fmtN(total)})
        </button>
      </div>`;
  } else if (total > 0) {
    html += `<div class="text-center text-[10px] text-white/25 py-4">전체 ${fmtN(total)}건 모두 표시됨</div>`;
  }
  content.innerHTML = html;
}

// ─── Subagent analysis ─────────────────────────────────────────────────
// Moved to static/subagents.js. Exposes: loadSubagentHeatmap,
// loadSubagentSuccessMatrix (both called from #/subagents view).

// ─── TOP 5 projects ───────────────────────────────────────────────────
// Moved to static/overview.js (loadTopProjects).

// ─── Utilities ──────────────────────────────────────────────────────────
// set() auto-clears the .skeleton class on first write so placeholder
// shimmer blocks disappear as soon as real data arrives.
function set(id,val){
  const el=document.getElementById(id);
  if(!el)return;
  el.textContent=val;
  if(el.classList.contains('skeleton'))el.classList.remove('skeleton');
}
function esc(s){return String(s||'').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;').replace(/'/g,'&#39;');}

// ─── Safe DOM builder ───────────────────────────────────────────────
// XSS-safe replacement for innerHTML template-literal building. Prefer
// this in all NEW code. Existing innerHTML sites are being migrated
// incrementally.
//
// Signature:
//   h(tag, attrs, children)
//   h('div', {class: 'foo', onClick: fn}, ['text', h('span', {}, 'child')])
//
// attrs special keys:
//   class     → className (string or array)
//   style     → inline style (string or object)
//   onClick / onInput / on<Event> → addEventListener(event.lower, handler)
//   dataset   → dataset assignment (object)
//   html      → DANGEROUS: set innerHTML directly. Avoid; use children.
// children:
//   string    → textContent node
//   Node      → appendChild
//   array     → each item recursively
//   null/undefined → skipped
function h(tag, attrs, children) {
  const el = document.createElement(tag);
  if (attrs) {
    for (const k of Object.keys(attrs)) {
      const v = attrs[k];
      if (v == null || v === false) continue;
      if (k === 'class') {
        el.className = Array.isArray(v) ? v.filter(Boolean).join(' ') : String(v);
      } else if (k === 'style') {
        if (typeof v === 'string') el.style.cssText = v;
        else Object.assign(el.style, v);
      } else if (k === 'dataset') {
        Object.assign(el.dataset, v);
      } else if (k.startsWith('on') && typeof v === 'function') {
        el.addEventListener(k.slice(2).toLowerCase(), v);
      } else if (k === 'html') {
        // intentionally allowed escape hatch — use only with trusted literals
        el.innerHTML = v;
      } else if (v === true) {
        el.setAttribute(k, '');
      } else {
        el.setAttribute(k, String(v));
      }
    }
  }
  const append = (c) => {
    if (c == null || c === false) return;
    if (Array.isArray(c)) { c.forEach(append); return; }
    if (c instanceof Node) { el.appendChild(c); return; }
    el.appendChild(document.createTextNode(String(c)));
  };
  append(children);
  return el;
}
function fmtN(n){return(Number(n)||0).toLocaleString('ko-KR');}
function fmtTok(n){n=Number(n)||0;if(n>=1e6)return(n/1e6).toFixed(1)+'M';if(n>=1e3)return(n/1e3).toFixed(1)+'K';return String(n);}
function fmt$(n){
  n = Number(n);
  if (!isFinite(n)) return '$—';   // NaN/Infinity guard
  if (n === 0) return '$0';
  if (Math.abs(n) < 0.01) return '<$0.01';
  // Thousands separator for readability at $1,000+; 2 decimals ≥$1, 4 below.
  const frac = Math.abs(n) >= 1 ? 2 : 4;
  return '$' + n.toLocaleString('en-US', { minimumFractionDigits: frac, maximumFractionDigits: frac });
}
function shortModel(m){if(!m)return'—';return m.replace('claude-','').replace(/-\d{8}$/,'');}
function trimPath(p){if(!p)return'';return p.split('/').filter(Boolean).slice(-2).join('/');}
function relTime(ts){if(!ts)return'—';const d=new Date(ts);if(isNaN(d))return ts;const df=Date.now()-d.getTime();if(df<6e4)return'방금';if(df<36e5)return Math.floor(df/6e4)+'분 전';if(df<864e5)return Math.floor(df/36e5)+'시간 전';if(df<6048e5)return Math.floor(df/864e5)+'일 전';return d.toLocaleDateString('ko-KR');}
function fmtTime(ts){if(!ts)return'—';const d=new Date(ts);if(isNaN(d))return ts;return d.toLocaleString('ko-KR',{month:'short',day:'numeric',hour:'2-digit',minute:'2-digit'});}

// ─── Keyboard shortcuts ────────────────────────────────────────────────
// Combos:
//   /           → focus session search (sessions view) or conv search
//   Esc         → close modal, clear search, unfocus input
//   g o/s/c/m/p/e → jump to view
//   ?           → show help overlay
const NAV_KEY_MAP = {
  o: 'overview', b: 'cost', s: 'sessions', c: 'conversations',
  m: 'models', p: 'projects', u: 'subagents', t: 'timeline', e: 'export',
};
let _gPending = false;

function _inEditable(el) {
  if (!el) return false;
  const tag = el.tagName;
  return tag === 'INPUT' || tag === 'TEXTAREA' || el.isContentEditable;
}

function _closeModals() {
  document.querySelectorAll('.fixed[id$="Modal"]').forEach(m => {
    if (m.style.display !== 'none' && m.id === 'projectModal') closeProjectModal();
    else if (m.style.display !== 'none') m.style.display = 'none';
  });
  const help = document.getElementById('kbdHelp');
  if (help) help.classList.add('hidden');
}

function showKbdHelp() {
  const help = document.getElementById('kbdHelp');
  if (help) help.classList.toggle('hidden');
}

document.addEventListener('keydown', (e) => {
  // Plain Esc: universal close
  if (e.key === 'Escape') {
    if (_inEditable(document.activeElement)) {
      document.activeElement.blur();
      return;
    }
    // Close preview drawer on Esc
    if (typeof topPreviewClose === 'function') {
      const panel = document.getElementById('topPreviewPanel');
      if (panel && panel.getAttribute('aria-hidden') !== 'true') {
        topPreviewClose();
        return;
      }
    }
    _closeModals();
    return;
  }
  if (_inEditable(document.activeElement)) return;

  // g <key> two-stroke combo
  if (_gPending) {
    _gPending = false;
    const target = NAV_KEY_MAP[e.key.toLowerCase()];
    if (target) { e.preventDefault(); showView(target); }
    return;
  }
  if (e.key === 'g') { _gPending = true; setTimeout(() => _gPending = false, 900); return; }

  // Conversation viewer: j/k message navigation, Ctrl+F inline search
  if (location.hash.startsWith('#/conversations') && state.currentSession) {
    // Trace mode: ← → navigate tool_use steps
    if (state.convTraceMode) {
      if (e.key === 'ArrowLeft')  { e.preventDefault(); convTracePrev(); return; }
      if (e.key === 'ArrowRight') { e.preventDefault(); convTraceNext(); return; }
    }
    if (e.key === 'j' || e.key === 'ArrowDown') {
      e.preventDefault(); convFocusMessage(_convFocusIdx + 1); return;
    }
    if (e.key === 'k' || e.key === 'ArrowUp') {
      e.preventDefault(); convFocusMessage(_convFocusIdx - 1); return;
    }
  }
  if ((e.ctrlKey || e.metaKey) && e.key === 'f' && location.hash.startsWith('#/conversations')) {
    e.preventDefault();
    const inp = document.getElementById('convInlineSearch');
    if (inp) { inp.focus(); inp.select(); }
    return;
  }

  // Single-key shortcuts
  if (e.key === '/') {
    e.preventDefault();
    const focusables = [
      document.getElementById('sessionSearch'),
      document.getElementById('convSearch'),
    ].filter(Boolean);
    // Prefer the one visible in the current view
    const current = document.querySelector('.view:not(.hidden)');
    const first = focusables.find(f => current && current.contains(f)) || focusables[0];
    if (first) first.focus();
    return;
  }
  if (e.key === '?' && e.shiftKey) {
    e.preventDefault();
    showKbdHelp();
    return;
  }
});

// ─── Conversation inline search ──────────────────────────────────────────
document.getElementById('convInlineSearch')?.addEventListener('input', (e) => {
  clearTimeout(_convSearchTimer);
  _convSearchTimer = setTimeout(() => _convInlineSearch(e.target.value), 200);
});
document.getElementById('convInlineSearch')?.addEventListener('keydown', (e) => {
  if (e.key === 'Enter') { e.preventDefault(); e.shiftKey ? convSearchPrev() : convSearchNext(); }
  if (e.key === 'Escape') { e.preventDefault(); e.target.value = ''; _convInlineSearch(''); e.target.blur(); }
});

function _convInlineSearch(q) {
  const container = document.getElementById('convMessages');
  if (!container) return;
  const all = container.querySelectorAll('[data-msg-role]');
  // Clear previous
  all.forEach(el => el.classList.remove('conv-search-hit', 'conv-search-current', 'conv-search-dim'));
  _convSearchMatches = [];
  _convSearchIdx = -1;
  const info = document.getElementById('convSearchMatchInfo');

  if (!q.trim()) {
    if (info) info.textContent = '';
    return;
  }
  const lq = q.toLowerCase();
  // Search both DOM textContent AND the raw content_preview from message data
  const msgs = state.convMessages || [];
  all.forEach((el, i) => {
    const domMatch = el.textContent.toLowerCase().includes(lq);
    const dataMatch = i < msgs.length && (msgs[i].content_preview || '').toLowerCase().includes(lq);
    if (domMatch || dataMatch) {
      el.classList.add('conv-search-hit');
      _convSearchMatches.push(el);
    } else {
      el.classList.add('conv-search-dim');
    }
  });
  if (info) info.textContent = _convSearchMatches.length ? `0/${_convSearchMatches.length}` : '\uACB0\uACFC \uC5C6\uC74C';
  if (_convSearchMatches.length) convSearchNext();
}

function convSearchNext() {
  if (!_convSearchMatches.length) return;
  if (_convSearchIdx >= 0) _convSearchMatches[_convSearchIdx].classList.remove('conv-search-current');
  _convSearchIdx = (_convSearchIdx + 1) % _convSearchMatches.length;
  _convSearchMatches[_convSearchIdx].classList.add('conv-search-current');
  _convSearchMatches[_convSearchIdx].scrollIntoView({ behavior: 'smooth', block: 'center' });
  const info = document.getElementById('convSearchMatchInfo');
  if (info) info.textContent = `${_convSearchIdx + 1}/${_convSearchMatches.length}`;
}

function convSearchPrev() {
  if (!_convSearchMatches.length) return;
  if (_convSearchIdx >= 0) _convSearchMatches[_convSearchIdx].classList.remove('conv-search-current');
  _convSearchIdx = (_convSearchIdx - 1 + _convSearchMatches.length) % _convSearchMatches.length;
  _convSearchMatches[_convSearchIdx].classList.add('conv-search-current');
  _convSearchMatches[_convSearchIdx].scrollIntoView({ behavior: 'smooth', block: 'center' });
  const info = document.getElementById('convSearchMatchInfo');
  if (info) info.textContent = `${_convSearchIdx + 1}/${_convSearchMatches.length}`;
}

// ─── Conversation keyboard navigation ───────────────────────────────────
function convFocusMessage(idx) {
  const container = document.getElementById('convMessages');
  if (!container) return;
  const all = container.querySelectorAll('[data-msg-role]');
  if (!all.length) return;
  // Remove previous focus
  if (_convFocusIdx >= 0 && _convFocusIdx < all.length) all[_convFocusIdx].classList.remove('conv-msg-focused');
  _convFocusIdx = Math.max(0, Math.min(idx, all.length - 1));
  all[_convFocusIdx].classList.add('conv-msg-focused');
  all[_convFocusIdx].scrollIntoView({ behavior: 'smooth', block: 'nearest' });
}

// ─── Markdown export ─────────────────────────────────────────────────────
function _buildConvMarkdown() {
  const msgs = state.convMessages;
  const session = state.convSession;
  if (!msgs || !session) return '';
  const lines = [];
  lines.push('# ' + (session.project_name || 'Conversation'));
  lines.push('');
  lines.push('**Model**: ' + (session.model || '\u2014'));
  lines.push('**Date**: ' + fmtTime(session.created_at) + ' ~ ' + fmtTime(session.updated_at));
  lines.push('**Cost**: ' + fmt$(session.total_cost_usd));
  lines.push('**Messages**: ' + fmtN(msgs.length));
  lines.push('');
  lines.push('---');
  lines.push('');
  for (const m of msgs) {
    const role = m.role === 'user' ? '\uD83D\uDC64 User' : '\uD83E\uDD16 Assistant';
    lines.push('## ' + role);
    if (m.role === 'assistant' && m.model) lines.push('*' + shortModel(m.model) + (m.cost_usd ? ' \u00b7 ' + fmt$(m.cost_usd) : '') + '*');
    lines.push('');
    // Extract text content
    let text = '';
    try {
      const content = typeof m.content === 'string' ? JSON.parse(m.content) : m.content;
      if (Array.isArray(content)) {
        for (const block of content) {
          if (block.type === 'text') text += (block.text || '') + '\n\n';
          else if (block.type === 'thinking') text += '<details><summary>Thinking</summary>\n\n' + (block.thinking || '') + '\n\n</details>\n\n';
          else if (block.type === 'tool_use') text += '```json\n// Tool: ' + (block.name || '') + '\n' + JSON.stringify(block.input || {}, null, 2) + '\n```\n\n';
          else if (block.type === 'tool_result') {
            const rc = Array.isArray(block.content) ? block.content.map(c => c.text || '').join('\n') : (block.content || '');
            text += '> **Tool Result**\n> ' + rc.split('\n').join('\n> ') + '\n\n';
          }
        }
      } else {
        text = m.content_preview || '';
      }
    } catch {
      text = m.content_preview || '';
    }
    lines.push(text.trim());
    lines.push('');
    lines.push('---');
    lines.push('');
  }
  return lines.join('\n');
}

function convCopyMarkdown() {
  const md = _buildConvMarkdown();
  if (!md) { showToast('\uB300\uD654\uB97C \uBA3C\uC800 \uC5F4\uC5B4\uC8FC\uC138\uC694', { type: 'warning' }); return; }
  navigator.clipboard.writeText(md).then(
    () => showToast('\uD074\uB9BD\uBCF4\uB4DC\uC5D0 \uBCF5\uC0AC\uB428', { type: 'success', duration: 1500 }),
    () => showToast('\uBCF5\uC0AC \uC2E4\uD328', { type: 'error' })
  );
}

function convDownloadMarkdown() {
  const md = _buildConvMarkdown();
  if (!md) { showToast('\uB300\uD654\uB97C \uBA3C\uC800 \uC5F4\uC5B4\uC8FC\uC138\uC694', { type: 'warning' }); return; }
  const session = state.convSession;
  const name = (session.project_name || 'conversation').replace(/[^a-zA-Z0-9가-힣_-]/g, '_');
  const filename = name + '_' + (session.id || '').slice(0, 8) + '.md';
  const blob = new Blob([md], { type: 'text/markdown;charset=utf-8' });
  const url = URL.createObjectURL(blob);
  const a = document.createElement('a');
  a.href = url; a.download = filename;
  document.body.appendChild(a); a.click();
  setTimeout(() => { document.body.removeChild(a); URL.revokeObjectURL(url); }, 100);
  showToast(filename + ' \uB2E4\uC6B4\uB85C\uB4DC', { type: 'success', duration: 2000 });
}

// ─── WebSocket: auto-append new messages for open session ────────────────
state.convNeedsRefresh = false;

function convRefreshTail() {
  if (_convLoading) return;
  if (!state.convNeedsRefresh || !state.currentSession || !state.convMessages) return;
  _convLoading = true;
  state.convNeedsRefresh = false;
  const sid = state.currentSession;
  const currentCount = state.convMessages.length;
  safeFetch('/api/sessions/' + encodeURIComponent(sid) + '/messages?limit=50&offset=' + currentCount)
    .then(data => {
      const more = data.messages || [];
      if (!more.length) return;
      const c = document.getElementById('convMessages');
      if (!c) return;
      const msgs = state.convMessages;
      const nearBottom = c.scrollTop + c.clientHeight >= c.scrollHeight - 100;
      let prevT = msgs.length ? msgs[msgs.length - 1].timestamp : null;
      let prevBr = null;
      for (let i = msgs.length - 1; i >= 0; i--) {
        if (msgs[i].git_branch) { prevBr = msgs[i].git_branch; break; }
      }
      more.forEach(m => {
        _renderTimeGap(c, prevT, m.timestamp);
        _renderSingleMessage(c, m, msgs, prevBr);
        if (m.git_branch) prevBr = m.git_branch;
        prevT = m.timestamp;
        msgs.push(m);
      });
      renderConvStats(msgs, state.convSession);
      // Update message count
      const countLabel = document.getElementById('convMsgCount');
      if (countLabel) {
        const u = msgs.filter(m => m.role === 'user').length;
        const a = msgs.filter(m => m.role === 'assistant').length;
        countLabel.textContent = fmtN(msgs.length) + '\uAC74 (\uC0AC\uC6A9\uC790 ' + u + ' \u00b7 \uC5B4\uC2DC\uC2A4\uD134\uD2B8 ' + a + ')';
      }
      if (nearBottom) c.scrollTop = c.scrollHeight;
    })
    .catch(() => {}) // silent — next WS batch will retry
    .finally(() => { _convLoading = false; });
}

// ─── Scroll reveal (Supanova) ────────────────────────────────────────────
// IntersectionObserver-based staggered reveal for .reveal elements.
// Called once on load and re-called each time a view becomes visible.
// Uses --i CSS variable on each element for stagger delay (0–n * 80ms).
// Elements already marked .visible are skipped (idempotent).
const _revealObs = typeof IntersectionObserver !== 'undefined'
  ? new IntersectionObserver((entries) => {
      entries.forEach(entry => {
        if (!entry.isIntersecting) return;
        const el = entry.target;
        const idx = +(getComputedStyle(el).getPropertyValue('--i').trim() || el.dataset.revealI || 0);
        setTimeout(() => el.classList.add('visible'), idx * 80);
        _revealObs.unobserve(el);
      });
    }, { threshold: 0.06, rootMargin: '0px 0px -32px 0px' })
  : null;

function scrollRevealView(container) {
  if (!_revealObs) return;
  (container || document).querySelectorAll('.reveal:not(.visible)').forEach(el => {
    _revealObs.observe(el);
  });
}

// ─── Init ───────────────────────────────────────────────────────────────
// Single source of truth for initial state: the URL hash decides the view
// (and triggers `onViewChange` → chart loading for overview). The WS onopen
// handler refreshes scalar data on every (re)connect. No other boot calls.
// Defer applyHash to 'load' so that all deferred modules (sessions.js,
// timeline.js, etc.) are parsed before the first view is activated.
window.addEventListener('load', () => {
  checkAuth();
  applyHash();
  if (typeof renderPresetSelect === 'function') renderPresetSelect();
  loadNodes();
  // Initial scroll reveal for whatever view is active at load
  requestAnimationFrame(() => scrollRevealView(document));
});
connectWS();
setInterval(()=>{if(state.ws&&state.ws.readyState===WebSocket.OPEN)state.ws.send('ping');},25000);

// Clean up timers and resources on page unload
window.addEventListener('beforeunload', () => {
  if (_refreshTimer) clearTimeout(_refreshTimer);
  if (_connBannerTimer) clearTimeout(_connBannerTimer);
  if (typeof clearPlanTimer === 'function') clearPlanTimer();
  if (_audioCtx) { try { _audioCtx.close(); } catch {} }
  if (state.ws) { try { state.ws.close(); } catch {} }
});


// ═══ charts.js ═══
// Claude Dashboard — chart module.
// Extracted from app.js for modularity. This file is loaded as a regular
// (non-module) script after app.js, so top-level `function foo(){}`
// declarations become window.foo. It depends on these globals defined in
// app.js: state, getChart, setChart, destroyChart, safeFetch, fmtTok,
// shortModel, savePrefs, projectData, renderProjectDailyChart, bus.

const CC={emerald:'#34d399',blue:'#60a5fa',amber:'#fbbf24',rose:'#fb7185',cyan:'#22d3ee',purple:'#a78bfa'};
// Theme-aware chart palette. All chart instances consult these at render
// time, and refreshChartsForTheme() rebuilds any live instance on toggle.
function themeColors() {
  if (document.body.classList.contains('theme-light')) return {
    gridColor:    'rgba(0,0,0,.06)',
    tickColor:    'rgba(0,0,0,.55)',
    legendColor:  'rgba(0,0,0,.65)',
    tooltipBg:    '#ffffff',
    tooltipBorder:'rgba(0,0,0,.12)',
    tooltipTitle: 'rgba(0,0,0,.80)',
    tooltipBody:  'rgba(0,0,0,.60)',
  };
  return {
    gridColor:    'rgba(255,255,255,.03)',
    tickColor:    'rgba(255,255,255,.35)',
    legendColor:  'rgba(255,255,255,.45)',
    tooltipBg:    '#111',
    tooltipBorder:'rgba(255,255,255,.08)',
    tooltipTitle: 'rgba(255,255,255,.7)',
    tooltipBody:  'rgba(255,255,255,.5)',
  };
}
const _prefersReducedMotion = window.matchMedia('(prefers-reduced-motion: reduce)').matches;
const CHART_D={responsive:true,maintainAspectRatio:false,plugins:{legend:{display:false}},animation:{duration:_prefersReducedMotion?0:400}};
// Color-blind friendly: add distinct border dash patterns per dataset.
// Applied to line charts where overlapping series can be hard to distinguish.
const CB_DASHES = [[], [6,3], [2,2], [8,4,2,4], [4,4]];
function grd(){return{color:themeColors().gridColor,drawBorder:false};}
function tck(){return{color:themeColors().tickColor,font:{size:11,family:'Pretendard'}};}
function legendLabels(extra={}){return{color:themeColors().legendColor,boxWidth:10,font:{size:11,family:'Pretendard'},...extra};}
function tooltipOpts(extra={}){
  const c=themeColors();
  return{backgroundColor:c.tooltipBg,borderColor:c.tooltipBorder,borderWidth:1,titleColor:c.tooltipTitle,bodyColor:c.tooltipBody,...extra};
}
// Per-chart error overlay. Inject on top of the canvas wrapper so a
// failing chart doesn't render as a silent blank canvas.
function chartError(canvasId, err, retryFn) {
  const canvas = document.getElementById(canvasId);
  if (!canvas || !canvas.parentElement) return;
  const wrap = canvas.parentElement;
  wrap.querySelectorAll('.chart-err-overlay').forEach(n => n.remove());
  const overlay = document.createElement('div');
  overlay.className = 'chart-err-overlay absolute inset-0 flex flex-col items-center justify-center text-center bg-white/[0.02] ring-1 ring-red-500/20 rounded-lg';
  const icon = document.createElement('iconify-icon');
  icon.setAttribute('icon', 'solar:danger-triangle-linear');
  icon.setAttribute('width', '24');
  icon.className = 'text-red-400/60 mb-1';
  const title = document.createElement('div');
  title.className = 'text-[11px] font-bold text-red-300/80';
  title.textContent = '차트 로딩 실패';
  const msg = document.createElement('div');
  msg.className = 'text-[10px] text-white/40 mt-0.5 max-w-[80%] truncate';
  msg.textContent = (err && err.message) || String(err || '');
  msg.title = msg.textContent;
  overlay.append(icon, title, msg);
  if (retryFn) {
    const btn = document.createElement('button');
    btn.className = 'mt-2 px-2.5 py-0.5 rounded-full bg-accent/15 text-accent border border-accent/30 text-[10px] font-bold spring hover:scale-[1.02]';
    btn.textContent = '다시 시도';
    btn.addEventListener('click', () => { overlay.remove(); retryFn(); });
    overlay.appendChild(btn);
  }
  // parent needs relative positioning for absolute overlay
  if (getComputedStyle(wrap).position === 'static') wrap.style.position = 'relative';
  wrap.appendChild(overlay);
}
async function loadCharts(){
  await Promise.allSettled([
    loadUsageChart().catch(e => { console.error('usage chart:', e); chartError('chartUsage', e, loadUsageChart); }),
    loadModelChart().catch(e => { console.error('models chart:', e); chartError('chartModels', e, loadModelChart); }),
    loadDailyCostChart().catch(e => { console.error('daily cost chart:', e); chartError('chartDailyCost', e, loadDailyCostChart); }),
    loadCacheChart().catch(e => { console.error('cache chart:', e); chartError('chartCache', e, loadCacheChart); }),
    loadStopReasonChart().catch(e => { console.error('stop reason chart:', e); chartError('chartStopReason', e, loadStopReasonChart); }),
    loadModelCacheChart().catch(e => { console.error('model cache chart:', e); chartError('chartModelCache', e, loadModelCacheChart); }),
  ]);
}
// Theme toggle hook: destroy + rebuild active chart instances so colors flip.
function refreshChartsForTheme(){
  const hasCostCharts=['usage','models','dailyCost','cache','stopReason','modelCache'].some(k=>getChart(k));
  if(hasCostCharts)loadCharts();
  if(getChart('projDaily')&&typeof projectData!=='undefined'&&projectData?.daily?.length){
    renderProjectDailyChart(projectData.daily);
  }
}

async function loadUsageChart(){
  const h=state.usageRange==='24h'?24:state.usageRange==='7d'?168:720;
  const ep=h<=168?`/api/usage/hourly?hours=${h}`:`/api/usage/daily?days=30`;
  const data=await safeFetch(ep);const rows=data.data||[];
  const labels=rows.map(r=>r.hour||r.date||''),inp=rows.map(r=>r.input_tokens||0),out=rows.map(r=>r.output_tokens||0),cr=rows.map(r=>r.cache_read_tokens||0);
  setChart('usage', new Chart(document.getElementById('chartUsage'),{type:'line',data:{labels,datasets:[
    {label:'입력',data:inp,borderColor:CC.blue,backgroundColor:'rgba(96,165,250,.08)',fill:true,tension:.3,pointRadius:2,pointStyle:'circle',borderWidth:1.5,borderDash:CB_DASHES[0]},
    {label:'출력',data:out,borderColor:CC.emerald,backgroundColor:'rgba(52,211,153,.06)',fill:true,tension:.3,pointRadius:2,pointStyle:'rect',borderWidth:1.5,borderDash:CB_DASHES[1]},
    {label:'캐시',data:cr,borderColor:CC.cyan,backgroundColor:'rgba(34,211,238,.04)',fill:true,tension:.3,pointRadius:2,pointStyle:'triangle',borderWidth:1,borderDash:CB_DASHES[2]},
  ]},options:{...CHART_D,plugins:{legend:{display:true,position:'top',align:'end',labels:legendLabels()},tooltip:tooltipOpts({callbacks:{label:c=>`${c.dataset.label}: ${fmtTok(c.raw)}`}})},scales:{x:{grid:grd(),ticks:{...tck(),maxTicksLimit:8,maxRotation:0}},y:{grid:grd(),ticks:{...tck(),callback:v=>fmtTok(v)}}}}}));
}
async function loadModelChart(){
  const data=await safeFetch('/api/models');const rows=data.models||[];
  const labels=rows.map(r=>shortModel(r.model)),vals=rows.map(r=>parseFloat((r.cost_usd||0).toFixed(4)));
  const pal=[CC.emerald,CC.blue,CC.amber,CC.rose,CC.cyan,CC.purple];
  setChart('models', new Chart(document.getElementById('chartModels'),{type:'doughnut',data:{labels,datasets:[{data:vals,backgroundColor:pal.map(c=>c+'66'),borderColor:pal,borderWidth:1,hoverOffset:4}]},options:{...CHART_D,cutout:'65%',plugins:{legend:{display:true,position:'right',labels:legendLabels({boxWidth:8,padding:6})},tooltip:tooltipOpts({callbacks:{label:c=>` ${c.label}: $${c.raw.toFixed(2)}`}})}}}));
}
async function loadDailyCostChart(){
  const data=await safeFetch('/api/usage/daily?days=30');const rows=data.data||[];
  const labels=rows.map(r=>r.date?r.date.slice(5):''),costs=rows.map(r=>parseFloat((r.cost_usd||0).toFixed(4)));
  setChart('dailyCost', new Chart(document.getElementById('chartDailyCost'),{type:'bar',data:{labels,datasets:[{label:'비용',data:costs,backgroundColor:'rgba(52,211,153,.25)',borderColor:CC.emerald,borderWidth:1,borderRadius:3}]},options:{...CHART_D,plugins:{tooltip:tooltipOpts({callbacks:{label:c=>` $${c.raw.toFixed(4)}`}})},scales:{x:{grid:grd(),ticks:{...tck(),maxTicksLimit:10}},y:{grid:grd(),ticks:{...tck(),callback:v=>'$'+v}}}}}));
}
async function loadCacheChart(){
  const data=await safeFetch('/api/stats');const a=data.all_time||{};
  const d=[a.input_tokens||0,a.cache_creation_tokens||0,a.cache_read_tokens||0,a.output_tokens||0];
  setChart('cache', new Chart(document.getElementById('chartCache'),{type:'doughnut',data:{labels:['입력','캐시 생성','캐시 읽기','출력'],datasets:[{data:d,backgroundColor:[CC.blue+'66',CC.purple+'66',CC.cyan+'66',CC.emerald+'66'],borderColor:[CC.blue,CC.purple,CC.cyan,CC.emerald],borderWidth:1,hoverOffset:4}]},options:{...CHART_D,cutout:'60%',plugins:{legend:{display:true,position:'right',labels:legendLabels({boxWidth:8,padding:5})},tooltip:tooltipOpts({callbacks:{label:c=>` ${c.label}: ${fmtTok(c.raw)}`}})}}}));
}
async function loadStopReasonChart(){
  const data=await safeFetch('/api/stats');const rows=data.stop_reasons||[];
  if(!rows.length)return;
  const SR_LABELS={'end_turn':'정상 종료','tool_use':'도구 호출','max_tokens':'토큰 초과','(unknown)':'미분류'};
  const labels=rows.map(r=>SR_LABELS[r.stop_reason]||r.stop_reason);
  const counts=rows.map(r=>r.count||0);
  const pal=[CC.emerald,CC.blue,CC.amber,CC.rose,CC.cyan,CC.purple];
  setChart('stopReason', new Chart(document.getElementById('chartStopReason'),{type:'doughnut',data:{labels,datasets:[{data:counts,backgroundColor:pal.map(c=>c+'66'),borderColor:pal,borderWidth:1,hoverOffset:4}]},options:{...CHART_D,cutout:'60%',plugins:{legend:{display:true,position:'right',labels:legendLabels({boxWidth:8,padding:5})},tooltip:tooltipOpts({callbacks:{label:c=>{const total=c.dataset.data.reduce((a,b)=>a+b,0);const pct=total>0?(c.raw/total*100).toFixed(1):'0';return ` ${c.label}: ${fmtN(c.raw)} (${pct}%)`;}}})}}}));
}
async function loadModelCacheChart(){
  const data=await safeFetch('/api/stats');const rows=data.model_cache||[];
  if(!rows.length)return;
  const labels=rows.map(r=>shortModel(r.model));
  const hitRates=rows.map(r=>{const total=(r.input_tokens||0)+(r.cache_read_tokens||0);return total>0?((r.cache_read_tokens||0)/total*100):0;});
  setChart('modelCache', new Chart(document.getElementById('chartModelCache'),{type:'bar',data:{labels,datasets:[{label:'캐시 히트율 %',data:hitRates,backgroundColor:'rgba(34,211,238,.3)',borderColor:CC.cyan,borderWidth:1,borderRadius:3}]},options:{...CHART_D,indexAxis:'y',plugins:{tooltip:tooltipOpts({callbacks:{label:c=>` ${c.raw.toFixed(1)}%`}})},scales:{x:{grid:grd(),ticks:{...tck(),callback:v=>v+'%'},max:100},y:{grid:grd(),ticks:tck()}}}}));
}
function setUsageRange(btn,range){
  document.querySelectorAll('.chart-range').forEach(b=>{b.classList.remove('active');b.classList.add('text-white/20');b.classList.remove('text-white/40');});
  btn.classList.add('active','text-white/40');btn.classList.remove('text-white/20');
  state.usageRange=range;
  savePrefs({ usageRange: range });
  loadUsageChart();
}


// ═══ sessions.js ═══
// Claude Dashboard — sessions module.
// Extracted from app.js. Contains: filter presets, bulk operations,
// loadSessions/renderSessions, advanced filter UI, session delete/pin/tag
// management, tag edit modal.
//
// Loaded as a regular script after app.js. All functions become window.*
// globals. Depends on app.js globals: state, sortState, savePrefs, loadPrefs,
// _prefs, safeFetch, reportError, showToast, renderError, set, esc, fmt$,
// fmtN, fmtTok, shortModel, trimPath, fmtDuration, fmtDurationSec,
// fmtTime, relTime, openDeleteConfirm, sortArrowHtml, sortThHtml,
// sortPillHtml, stopReasonBadge, markUpdated, showNewDataBadge, showView,
// drillToSessionsToday, drillToSessionsWeek, openConversation.

// ─── Filter presets (B2) ─────────────────────────────────────────────
// Each preset captures the sessions view's sort + advanced filters under
// a user-supplied name, persisted via savePrefs().
function getPresets() {
  return _prefs.presets || loadPrefs().presets || {};
}
function saveCurrentPreset() {
  const name = (prompt('이 필터 조합의 이름:', '') || '').trim();
  if (!name) return;
  const presets = getPresets();
  presets[name] = {
    sort: { ...getSortState('sessions') },
    advFilters: { ...getAdvFilters() },
  };
  savePrefs({ presets });
  Object.assign(_prefs, { presets });
  renderPresetSelect();
  showToast(`"${name}" 저장됨`, { type: 'success', duration: 1800 });
}
function applyPreset(name) {
  if (!name) return;
  const presets = getPresets();
  const p = presets[name];
  if (!p) return;
  setSortState('sessions', p.sort || {});
  setAdvFilters({ ...(p.advFilters || {}) });
  savePrefs({
    [`sort_sessions`]: getSortState('sessions'),
    advFilters: getAdvFilters(),
  });
  setPage(1);
  loadSessions();
  showToast(`"${name}" 적용`, { type: 'info', duration: 1500 });
}
function deletePreset(name) {
  const presets = getPresets();
  if (!presets[name]) return;
  delete presets[name];
  savePrefs({ presets });
  Object.assign(_prefs, { presets });
  renderPresetSelect();
  showToast(`"${name}" 삭제`, { type: 'info', duration: 1500 });
}
function renderPresetSelect() {
  const sel = document.getElementById('presetSelect');
  if (!sel) return;
  const presets = getPresets();
  const names = Object.keys(presets).sort();
  sel.innerHTML = '<option value="">프리셋 선택…</option>'
    + names.map(n => `<option value="${esc(n)}">${esc(n)}</option>`).join('');
}


// ─── Bulk operations (B1) ────────────────────────────────────────────
function bulkToggleOne(sid, on) {
  if (on) state.bulkSelected.add(sid);
  else state.bulkSelected.delete(sid);
  renderBulkBar();
}
function bulkToggleAll(on) {
  document.querySelectorAll('[data-bulk-sid]').forEach(cb => {
    cb.checked = on;
    const sid = cb.dataset.bulkSid;
    if (on) state.bulkSelected.add(sid); else state.bulkSelected.delete(sid);
  });
  renderBulkBar();
}
function bulkClear() {
  state.bulkSelected.clear();
  document.querySelectorAll('[data-bulk-sid]').forEach(cb => { cb.checked = false; });
  const all = document.getElementById('bulkSelectAll');
  if (all) all.checked = false;
  renderBulkBar();
}
function renderBulkBar() {
  const bar = document.getElementById('bulkActionBar');
  const count = state.bulkSelected.size;
  if (!bar) return;
  if (count === 0) { bar.classList.add('hidden'); return; }
  bar.classList.remove('hidden');
  const label = bar.querySelector('[data-bulk-count]');
  if (label) label.textContent = `${fmtN(count)}개 선택됨`;
}

async function bulkPin(pin) {
  if (state.bulkSelected.size === 0) return;
  const ids = [...state.bulkSelected];
  const results = await Promise.all(ids.map(sid =>
    fetch(`/api/sessions/${encodeURIComponent(sid)}/pin`,
      { method: pin ? 'POST' : 'DELETE' })
      .then(() => true).catch(() => false)
  ));
  const ok = results.filter(Boolean).length;
  const fail = results.length - ok;
  showToast(`${pin ? '핀' : '핀 해제'}: ${ok}건 성공${fail ? `, ${fail}건 실패` : ''}`,
    { type: fail ? 'warning' : 'success' });
  bulkClear();
  loadSessions();
}

async function bulkTag() {
  if (state.bulkSelected.size === 0) return;
  // Reuse the existing tag edit modal but route the submit through a bulk path.
  const ids = [...state.bulkSelected];
  _tagEditPending = { sid: null, bulkIds: ids };
  document.getElementById('tagEditTarget').textContent = `${ids.length}개 세션 일괄 태그`;
  const input = document.getElementById('tagEditInput');
  input.value = '';
  input.onkeydown = (e) => {
    if (e.key === 'Enter') { e.preventDefault(); submitTagEdit(); }
    if (e.key === 'Escape') { e.preventDefault(); closeTagEdit(); }
  };
  document.getElementById('tagEditModal').classList.remove('hidden');
  setTimeout(() => input.focus(), 50);
}

async function bulkCompare() {
  if (state.bulkSelected.size !== 2) {
    showToast('정확히 2개의 세션을 선택하세요', { type: 'warning' });
    return;
  }
  const [a, b] = [...state.bulkSelected];
  try {
    const [sa, sb] = await Promise.all([
      safeFetch(`/api/sessions/${encodeURIComponent(a)}`),
      safeFetch(`/api/sessions/${encodeURIComponent(b)}`),
    ]);
    renderCompareModal(sa, sb);
  } catch (e) {
    reportError('bulkCompare', e);
  }
}

function renderCompareModal(a, b) {
  // Build a side-by-side row for every comparable metric. Tints highlight
  // the larger of each pair so the diff is glanceable.
  const rows = [
    ['프로젝트', a.project_name, b.project_name, 'string'],
    ['모델', a.model, b.model, 'string'],
    ['생성', fmtTime(a.created_at), fmtTime(b.created_at), 'string'],
    ['최근 활동', fmtTime(a.updated_at), fmtTime(b.updated_at), 'string'],
    ['메시지 수', a.message_count, b.message_count, 'num'],
    ['사용자 메시지', a.user_message_count, b.user_message_count, 'num'],
    ['입력 토큰', a.total_input_tokens, b.total_input_tokens, 'num'],
    ['출력 토큰', a.total_output_tokens, b.total_output_tokens, 'num'],
    ['캐시 읽기', a.total_cache_read_tokens, b.total_cache_read_tokens, 'num'],
    ['캐시 생성', a.total_cache_creation_tokens, b.total_cache_creation_tokens, 'num'],
    ['총 비용', a.cost_micro * 1.0 / 1000000, b.cost_micro * 1.0 / 1000000, 'cost'],
    ['종료 사유', a.final_stop_reason || '—', b.final_stop_reason || '—', 'string'],
    ['핀', a.pinned ? '★' : '—', b.pinned ? '★' : '—', 'string'],
    ['Subagent', a.is_subagent ? 'YES' : 'NO', b.is_subagent ? 'YES' : 'NO', 'string'],
  ];
  const cell = (val, isMax, type) => {
    let display = val ?? '—';
    if (type === 'num' && typeof val === 'number') display = fmtN(val);
    if (type === 'cost' && typeof val === 'number') display = fmt$(val);
    const cls = isMax ? 'text-emerald-300/90 font-bold' : 'text-white/65';
    return `<td class="px-4 py-2 ${cls} tabular-nums">${esc(String(display))}</td>`;
  };
  const html = rows.map(([label, av, bv, type]) => {
    let aMax = false, bMax = false;
    if (type === 'num' || type === 'cost') {
      const an = Number(av) || 0, bn = Number(bv) || 0;
      if (an > bn) aMax = true;
      else if (bn > an) bMax = true;
    }
    return `<tr class="border-b border-white/[0.04]">
      <td class="px-4 py-2 text-[10px] text-white/40 uppercase tracking-widest font-bold">${esc(label)}</td>
      ${cell(av, aMax, type)}
      ${cell(bv, bMax, type)}
    </tr>`;
  }).join('');

  const ov = document.createElement('div');
  ov.className = 'fixed inset-0 z-50 flex items-center justify-center bg-black/70 backdrop-blur-sm p-4';
  ov.onclick = (e) => { if (e.target === ov) ov.remove(); };
  ov.innerHTML = `
    <div class="bg-[#0f0f0f] ring-1 ring-white/[0.08] rounded-2xl w-[820px] max-w-[96vw] max-h-[90vh] overflow-y-auto shadow-[0_20px_60px_rgba(0,0,0,.6)] anim-in">
      <div class="px-5 py-3 border-b border-white/[0.06] flex items-center justify-between sticky top-0 bg-[#0f0f0f]">
        <span class="text-sm font-bold text-white/85">세션 비교</span>
        <button onclick="this.closest('.fixed').remove()" class="text-white/30 hover:text-white/70 spring text-2xl leading-none">&times;</button>
      </div>
      <table class="w-full text-[12px]">
        <thead>
          <tr class="text-[10px] text-white/35 uppercase tracking-widest border-b border-white/[0.06]">
            <th class="px-4 py-2 text-left font-bold w-32">항목</th>
            <th class="px-4 py-2 text-left font-bold">A · ${esc(a.id.slice(0,8))}</th>
            <th class="px-4 py-2 text-left font-bold">B · ${esc(b.id.slice(0,8))}</th>
          </tr>
        </thead>
        <tbody>${html}</tbody>
      </table>
    </div>`;
  document.body.appendChild(ov);
}

function bulkDelete() {
  if (state.bulkSelected.size === 0) return;
  const ids = [...state.bulkSelected];
  openDeleteConfirm({
    target: `DELETE ${ids.length}`,
    message: `선택한 ${fmtN(ids.length)}개 세션이 영구 삭제됩니다. 복구할 수 없습니다.`,
    onConfirm: async () => {
      const results = await Promise.all(ids.map(sid =>
        fetch(`/api/sessions/${encodeURIComponent(sid)}?confirm=true`, { method: 'DELETE' })
          .then(() => true).catch(() => false)
      ));
      const ok = results.filter(Boolean).length;
      const fail = results.length - ok;
      showToast(`삭제 완료: ${ok}건${fail ? `, ${fail}건 실패` : ''}`,
        { type: fail ? 'warning' : 'success' });
      bulkClear();
      loadSessions(); loadStats(); loadPeriods();
    },
  });
}


// ─── Sessions ───────────────────────────────────────────────────────────
let searchTimer=null;
function searchSessions(q){clearTimeout(searchTimer);setSearchQuery(q);searchTimer=setTimeout(()=>{setPage(1);state.bulkSelected.clear();loadSessions();},300);}
async function loadSessions(page=getPage()){
  const tb=document.getElementById('sessionsBody');
  tb.innerHTML='<tr><td colspan="10" class="text-center py-8 text-white/15 text-xs dots">로딩 중</td></tr>';
  try{
    setPage(page);
    const ss=getSortState('sessions');
    const p=new URLSearchParams({page,per_page:25,sort:ss.key,order:ss.order});
    if(getSearchQuery())p.set('search',getSearchQuery());
    if(ss.pinned_only)p.set('pinned_only','true');
    const af = getAdvFilters();
    if(af.date_from)p.set('date_from',af.date_from);
    if(af.date_to)p.set('date_to',af.date_to);
    if(af.cost_min)p.set('cost_min',af.cost_min);
    if(af.cost_max)p.set('cost_max',af.cost_max);
    if(af.node)p.set('node',af.node);
    if(af.ai_tag)p.set('ai_tag',af.ai_tag);
    if(af.tool)p.set('tool',af.tool);
    if(af.min_turns)p.set('min_turns',af.min_turns);
    const d=await safeFetch('/api/sessions?'+p);
    state.totalPages=d.pages||1; // TODO: accessor
    renderSessionsThead();
    renderSessions(d);
    const pinToggle=document.getElementById('sessionsPinToggle');
    if(pinToggle){
      pinToggle.classList.toggle('bg-accent/20', ss.pinned_only);
      pinToggle.classList.toggle('text-accent', ss.pinned_only);
      pinToggle.classList.toggle('text-white/30', !ss.pinned_only);
    }
    renderAdvFiltersSummary();
  }catch(e){
    console.error('loadSessions:',e);
    const tb=document.getElementById('sessionsBody');
    if(tb) tb.innerHTML='<tr><td colspan="10" class="text-center py-8 text-red-400/60 text-xs">세션 로드 실패 — 재시도하려면 새로고침</td></tr>';
  }
}

// ─── Advanced filter UI helpers (U11 + U12) ──────────────────────────
function toggleAdvFilters() {
  const panel = document.getElementById('advFiltersPanel');
  if (!panel) return;
  panel.classList.toggle('hidden');
  if (!panel.classList.contains('hidden')) {
    // Restore persisted values on open
    const af = getAdvFilters();
    const g = id => document.getElementById(id);
    if (g('advDateFrom')) g('advDateFrom').value = af.date_from || '';
    if (g('advDateTo'))   g('advDateTo').value   = af.date_to || '';
    if (g('advCostMin'))  g('advCostMin').value  = af.cost_min || '';
    if (g('advCostMax'))  g('advCostMax').value  = af.cost_max || '';
    if (g('advAiTagFilter')) g('advAiTagFilter').value = af.ai_tag || '';
    if (g('advToolFilter'))  g('advToolFilter').value  = af.tool || '';
    if (g('advMinTurns'))    g('advMinTurns').value    = af.min_turns || '';
  }
}
function applyAdvFilters() {
  const g = id => document.getElementById(id);
  setAdvFilters({
    date_from: g('advDateFrom')?.value || '',
    date_to:   g('advDateTo')?.value || '',
    cost_min:  g('advCostMin')?.value || '',
    cost_max:  g('advCostMax')?.value || '',
    node:      g('advNodeFilter')?.value || '',
    ai_tag:    g('advAiTagFilter')?.value || '',
    tool:      g('advToolFilter')?.value || '',
    min_turns: g('advMinTurns')?.value || '',
  });
  savePrefs({ advFilters: getAdvFilters() });
  setPage(1);
  state.bulkSelected.clear();
  loadSessions();
}
function clearAdvFilters() {
  setAdvFilters({});
  savePrefs({ advFilters: {} });
  ['advDateFrom','advDateTo','advCostMin','advCostMax','advNodeFilter','advAiTagFilter','advToolFilter','advMinTurns'].forEach(id => {
    const el = document.getElementById(id);
    if (el) el.value = '';
  });
  setPage(1);
  state.bulkSelected.clear();
  loadSessions();
}
function renderAdvFiltersSummary() {
  const af = getAdvFilters();
  const has = Object.values(af).some(Boolean);
  const btn = document.getElementById('advFiltersToggle');
  if (btn) {
    btn.classList.toggle('text-accent', has);
    btn.classList.toggle('border-accent/40', has);
  }
  const sum = document.getElementById('advFiltersSummary');
  if (sum) {
    if (!has) { sum.textContent = ''; return; }
    const parts = [];
    if (af.date_from || af.date_to) parts.push(`기간: ${af.date_from || '∞'} ~ ${af.date_to || '∞'}`);
    if (af.cost_min || af.cost_max)  parts.push(`비용: $${af.cost_min || 0} ~ $${af.cost_max || '∞'}`);
    if (af.node)  parts.push(`노드: ${af.node}`);
    if (af.ai_tag) parts.push(`AI태그: ${af.ai_tag}`);
    if (af.tool) parts.push(`툴: ${af.tool}`);
    if (af.min_turns) parts.push(`최소메시지: ${af.min_turns}`);
    sum.textContent = parts.join(' · ');
  }
}
function renderSessionsThead(){
  document.getElementById('sessionsThead').innerHTML=`
    <tr class="text-[10px] text-white/35 uppercase tracking-widest border-b border-white/[0.05]">
      <th class="text-center px-3 py-2.5 font-bold w-8">
        <input type="checkbox" id="bulkSelectAll" onclick="bulkToggleAll(this.checked)"
               aria-label="전체 선택" class="cursor-pointer">
      </th>
      ${sortThHtml('sessions','project','프로젝트','text-left','px-5')}
      ${sortThHtml('sessions','model','모델','text-left hide-sm')}
      ${sortThHtml('sessions','input','입력','text-right hide-sm')}
      ${sortThHtml('sessions','output','출력','text-right hide-sm')}
      ${sortThHtml('sessions','cache','캐시','text-right hide-sm')}
      ${sortThHtml('sessions','cost','비용','text-right')}
      ${sortThHtml('sessions','messages','메시지','text-right hide-sm')}
      ${sortThHtml('sessions','updated_at','활동','text-right')}
      <th class="text-center px-3 py-2.5 font-bold text-white/35 w-16 hide-sm">관리</th>
    </tr>`;
}
function renderSessions(data){
  const tb=document.getElementById('sessionsBody');tb.innerHTML='';
  if(!data.sessions?.length){tb.innerHTML=`<tr><td colspan="9" class="text-center py-12 text-white/25 text-xs">데이터 없음</td></tr>`;return;}
  data.sessions.forEach(s=>{
    const tr=document.createElement('tr');
    const _isRemoteNode = s.source_node && s.source_node !== 'local';
    tr.className='cursor-pointer border-b border-white/[0.03] hover:bg-white/[0.04] spring';
    if (_isRemoteNode) tr.style.background = 'rgba(34,211,238,.04)';
    tr.setAttribute('tabindex', '0');
    tr.setAttribute('role', 'row');
    tr.onclick=()=>openConversation(s.id,s);
    tr.addEventListener('keydown', (e) => {
      if (e.key === 'Enter' || e.key === ' ') { e.preventDefault(); openConversation(s.id, s); }
      if (e.key === 'ArrowDown') { e.preventDefault(); const next = tr.nextElementSibling; if (next) next.focus(); }
      if (e.key === 'ArrowUp') { e.preventDefault(); const prev = tr.previousElementSibling; if (prev) prev.focus(); }
    });
    const subCount = s.subagent_count || 0;
    const subCost = s.subagent_cost || 0;
    const subBadge = subCount > 0
      ? `<span class="inline-block mt-1 text-[10px] px-2 py-0.5 rounded-full bg-purple-500/15 text-purple-300/85 font-bold" title="${fmtN(subCount)}개 subagent (${fmt$(subCost)})">🤖 ${fmtN(subCount)} · ${fmt$(subCost)}</span>`
      : '';
    // Interactivity ratio — how much of the session was user-driven
    const mc = s.message_count || 0;
    const umc = s.user_message_count || 0;
    const ratio = mc > 0 ? Math.round((umc / (mc + umc)) * 100) : 0;
    const msgSubtext = mc > 0
      ? `<div class="text-[9px] text-white/30 tabular-nums" title="${umc}건 user / ${mc}건 assistant">${umc} user · ${ratio}%</div>`
      : '';
    // Session duration badge (parents — subagents already had this elsewhere)
    const dur = s.duration_seconds || 0;
    const durLabel = dur > 0 ? fmtDurationSec(dur) : '';
    const stopBadge = stopReasonBadge(s.final_stop_reason);
    const tagList = (s.tags || '').split(',').map(t => t.trim()).filter(Boolean);
    const tagBadges = tagList.length
      ? tagList.map(t => `<span class="tag-badge">#${esc(t)}</span>`).join(' ')
      : '';
    let aiTagBadges = '';
    if (s.ai_tags) {
      try {
        const parsed = JSON.parse(s.ai_tags);
        const aiTags = parsed.tags || [];
        const AI_TAG_CLS = {
          permission_loop: 'bg-amber-500/15 text-amber-300/90 border border-amber-500/30',
          cost_spike:      'bg-red-500/15 text-red-300/90 border border-red-500/30',
          agent_loop:      'bg-orange-500/15 text-orange-300/90 border border-orange-500/30',
          task_complete:   'bg-emerald-500/15 text-emerald-300/90 border border-emerald-500/30',
          task_abandoned:  'bg-white/10 text-white/40 border border-white/10',
          error_recovery:  'bg-cyan-500/15 text-cyan-300/90 border border-cyan-500/30',
        };
        const conf = parsed.confidence ? ` (${Math.round(parsed.confidence * 100)}%)` : '';
        const tip = parsed.summary ? esc(parsed.summary) : '';
        aiTagBadges = aiTags.map(t => {
          const cls = AI_TAG_CLS[t] || 'bg-white/10 text-white/40 border border-white/10';
          return `<span class="inline-block text-[9px] px-1.5 py-0.5 rounded-full font-semibold ${cls}" title="AI${conf}: ${tip || esc(t)}">✦ ${esc(t.replace(/_/g,' '))}</span>`;
        }).join(' ');
      } catch(e) {}
    }
    const isRemote = s.source_node && s.source_node !== 'local';
    const nodeBadge = isRemote
      ? `<span class="node-badge" style="display:inline-block;font-size:9px;padding:2px 7px;border-radius:9999px;background:rgba(34,211,238,.18);color:#67e8f9;border:1px solid rgba(34,211,238,.4);font-weight:700" title="\uC6D0\uACA9 \uB178\uB4DC: ${esc(s.source_node)}">${esc(s.source_node)}</span>`
      : '';
    tr.setAttribute('data-sid', s.id);
    const checked = state.bulkSelected && state.bulkSelected.has(s.id) ? 'checked' : '';
    tr.innerHTML=`
      <td class="px-3 py-3 text-center" onclick="event.stopPropagation()"${_isRemoteNode ? ' style="border-left:3px solid #22d3ee"' : ''}>
        <input type="checkbox" data-bulk-sid="${esc(s.id)}" ${checked}
               onclick="event.stopPropagation();bulkToggleOne('${esc(s.id)}',this.checked)"
               aria-label="선택" class="cursor-pointer">
      </td>
      <td class="px-5 py-3">
        <div class="font-semibold text-white/85 truncate max-w-xs flex items-center gap-1.5">${s.pinned?'<span class="text-accent text-[11px]">★</span>':''}${esc(s.project_name||'—')}${stopBadge?'<span class="ml-1">'+stopBadge+'</span>':''}</div>
        <div class="text-[10px] text-white/30 mt-0.5 truncate max-w-xs">${esc(trimPath(s.cwd||''))}</div>
        <div class="mt-1 flex flex-wrap gap-1 items-center">
          ${nodeBadge}
          ${s.is_subagent?'<span class="text-[9px] px-1.5 py-0.5 rounded-full bg-purple-500/10 text-purple-400/70">subagent</span>'+(s.is_subagent&&!s.parent_tool_use_id?'<span class="inline-block text-[9px] px-2 py-0.5 rounded-full bg-amber-500/10 text-amber-400/75 border border-amber-500/25 font-semibold">orphan</span>':''):''}

          ${tagBadges}
          ${aiTagBadges}
          ${subBadge}
        </div>
      </td>
      <td class="px-3 py-3 hide-sm"><span class="text-[10px] px-2 py-0.5 rounded-full bg-white/5 text-white/45 whitespace-nowrap">${esc(shortModel(s.model||''))}</span></td>
      <td class="px-3 py-3 text-right text-white/55 tabular-nums hide-sm">${fmtTok(s.total_input_tokens||0)}</td>
      <td class="px-3 py-3 text-right text-emerald-400/75 tabular-nums hide-sm">${fmtTok(s.total_output_tokens||0)}</td>
      <td class="px-3 py-3 text-right text-cyan-400/75 tabular-nums hide-sm" title="읽기 ${fmtN(s.total_cache_read_tokens||0)} / 생성 ${fmtN(s.total_cache_creation_tokens||0)}">${fmtTok(s.total_cache_read_tokens||0)}</td>
      <td class="px-3 py-3 text-right"><span class="text-[11px] px-2 py-0.5 rounded-full bg-amber-500/10 text-amber-400/85 font-bold tabular-nums">${fmt$(s.total_cost_usd)}</span>${(()=>{const ms=s.turn_duration_ms||0;if(ms<=0||!(s.total_cost_usd>0))return '';const perHr=s.total_cost_usd/(ms/3600000);return '<div class="text-[9px] text-white/25 tabular-nums mt-0.5" title="비용 효율 ($/시간)">'+fmt$(perHr)+'/hr</div>';})()}</td>
      <td class="px-3 py-3 text-right hide-sm">
        <div class="tabular-nums text-white/70">${fmtN(mc)}</div>
        ${msgSubtext}
      </td>
      <td class="px-3 py-3 text-right">
        <div class="text-white/35">${relTime(s.updated_at)}</div>
        ${durLabel?`<div class="text-[9px] text-white/25 tabular-nums">${durLabel}</div>`:''}
      </td>
      <td class="px-3 py-3 text-center whitespace-nowrap hide-sm"></td>`;
    // Action buttons via DOM API — safe against name/id injection
    const actionTd = tr.lastElementChild;
    const pinBtn = document.createElement('button');
    pinBtn.className = (s.pinned ? 'text-accent' : 'text-white/20') + ' hover:text-accent spring text-sm mr-1';
    pinBtn.title = s.pinned ? '핀 해제' : '핀 고정';
    pinBtn.textContent = s.pinned ? '★' : '☆';
    pinBtn.addEventListener('click', (e) => {
      e.stopPropagation();
      pinSession(s.id, s.pinned ? 0 : 1);
    });
    const tagBtn = document.createElement('button');
    tagBtn.className = 'text-white/20 hover:text-cyan-300 spring text-sm mr-1';
    tagBtn.title = '태그 편집';
    tagBtn.textContent = '🏷';
    tagBtn.addEventListener('click', (e) => {
      e.stopPropagation();
      editSessionTags(s.id, s.tags || '');
    });
    const delBtn = document.createElement('button');
    delBtn.className = 'text-white/20 hover:text-red-400 spring text-sm';
    delBtn.title = '삭제';
    delBtn.textContent = '✕';
    delBtn.addEventListener('click', (e) => {
      e.stopPropagation();
      deleteSession(s.id, s.project_name);
    });
    actionTd.appendChild(pinBtn);
    actionTd.appendChild(tagBtn);
    actionTd.appendChild(delBtn);
    tb.appendChild(tr);
  });
  renderPagination(data.page,data.pages,data.total);
}
function renderPagination(page,pages,total){
  const el=document.getElementById('sessionsPagination');el.innerHTML='';
  if(pages<=1){el.innerHTML=`<span class="text-[10px] text-white/15 ml-auto">${fmtN(total)} 세션</span>`;return;}
  const mk=(t,p,dis)=>{const b=document.createElement('button');b.className='px-2 py-0.5 rounded text-[10px] font-semibold spring '+(p===page?'bg-accent/15 text-accent':'text-white/20 hover:text-white/40');b.textContent=t;b.disabled=dis;b.onclick=()=>loadSessions(p);return b;};
  el.appendChild(mk('‹',page-1,page<=1));
  for(let i=1;i<=pages;i++){if(pages>7&&i>2&&i<pages-1&&Math.abs(i-page)>1){if(i===3||i===pages-2){const s=document.createElement('span');s.textContent='…';s.className='text-white/10 text-[10px] px-1';el.appendChild(s);}continue;}el.appendChild(mk(i,i,false));}
  el.appendChild(mk('›',page+1,page>=pages));
  const info=document.createElement('span');info.className='text-[10px] text-white/15 ml-auto';info.textContent=`${fmtN(total)} 세션`;el.appendChild(info);
}


// ─── Session Management ─────────────────────────────────────────────────
// S1/S2: require the user to retype the session's project name before the
// delete executes. The preview DELETE call (without confirm) surfaces the
// message count so the user sees the blast radius.
async function deleteSession(sid, name) {
  const displayName = name || sid;
  try {
    const pv = await fetch(`/api/sessions/${encodeURIComponent(sid)}`, { method: 'DELETE' }).then(r => r.json());
    openDeleteConfirm({
      target: displayName,
      message: `이 세션과 ${fmtN(pv.message_count || 0)}건 메시지가 영구 삭제됩니다. 복구할 수 없습니다.`,
      onConfirm: async () => {
        try {
          await fetch(`/api/sessions/${encodeURIComponent(sid)}?confirm=true`, { method: 'DELETE' });
          loadSessions(); loadPeriods(); loadStats();
          showToast(`"${displayName}" 삭제 완료`, { type: 'success', duration: 2000 });
        } catch (e) {
          showToast('삭제 실패: ' + (e.message || e), { type: 'error' });
        }
      },
    });
  } catch (e) {
    console.error('deleteSession:', e);
    showToast('미리보기 실패: ' + (e.message || e), { type: 'error' });
  }
}
async function pinSession(sid, pin) {
  try {
    if (pin) await fetch(`/api/sessions/${sid}/pin`, {method:'POST'});
    else await fetch(`/api/sessions/${sid}/pin`, {method:'DELETE'});
    loadSessions();
    showToast(pin ? '핀 고정됨' : '핀 해제됨', { type: 'success', duration: 1500 });
  } catch(e) { console.error('pinSession:', e); showToast('핀 토글 실패', { type: 'error' }); }
}

// Inline tag-edit modal (replaces window.prompt). Native prompt() blocks
// the JS thread and on some browsers swallows the immediate post-prompt
// toast render — using a real DOM modal makes the toast pipeline reliable.
let _tagEditPending = null;

function editSessionTags(sid, current) {
  const modal = document.getElementById('tagEditModal');
  if (modal && !modal.classList.contains('hidden')) return;
  _tagEditPending = { sid };
  const target = document.getElementById('tagEditTarget');
  const input  = document.getElementById('tagEditInput');
  if (target) target.textContent = `세션 ${sid.slice(0, 12)}`;
  if (input) {
    input.value = current || '';
    input.onkeydown = (e) => {
      if (e.key === 'Enter') { e.preventDefault(); submitTagEdit(); }
      if (e.key === 'Escape') { e.preventDefault(); closeTagEdit(); }
    };
  }
  if (modal) modal.classList.remove('hidden');
  setTimeout(() => input && input.focus(), 50);
}

function closeTagEdit() {
  document.getElementById('tagEditModal')?.classList.add('hidden');
  _tagEditPending = null;
}

async function submitTagEdit() {
  if (!_tagEditPending) return;
  const { sid, bulkIds } = _tagEditPending;
  const raw = document.getElementById('tagEditInput')?.value || '';
  const clean = raw.split(',').map(t => t.trim()).filter(Boolean).join(',');
  closeTagEdit();
  try {
    if (bulkIds && bulkIds.length) {
      // Bulk mode — apply the same tag string to every selected session
      const results = await Promise.all(bulkIds.map(id =>
        fetch(`/api/sessions/${encodeURIComponent(id)}/tags`, {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({ tags: clean }),
        }).then(r => r.ok).catch(() => false)
      ));
      const ok = results.filter(Boolean).length;
      const fail = results.length - ok;
      showToast(
        `일괄 태그: ${ok}건 적용${fail ? `, ${fail}건 실패` : ''}${clean ? ' → ' + clean : ' (비움)'}`,
        { type: fail ? 'warning' : 'success', duration: 2800 }
      );
      bulkClear();
      loadSessions();
    } else {
      const r = await fetch(`/api/sessions/${encodeURIComponent(sid)}/tags`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ tags: clean }),
      });
      if (!r.ok) throw new Error('HTTP ' + r.status);
      showToast(clean ? `태그 저장됨: ${clean}` : '태그 비움', { type: 'success', duration: 2400 });
      loadSessions();
    }
  } catch (e) {
    console.error('submitTagEdit:', e);
    showToast('태그 저장 실패: ' + (e.message || e), { type: 'error' });
  }
}



// ═══ overview.js ═══
// Claude Dashboard — overview module.
// Extracted from app.js. Contains:
//   1. loadStats + renderStats (hero + secondary cost chips)
//   2. loadPeriods + renderPeriod (day/week/month cards)
//   3. loadForecast + burn-rate (hero 3 + secondary burn-out)
//   4. loadTopProjects (TOP 5 list with drill-down)
//   5. drill helpers (drillToSessionsToday/Week)
//
// Loaded as a regular script after app.js. All functions become window.*
// globals. Depends on app.js globals: state, safeFetch, reportError,
// markUpdated, set, esc, fmt$, fmtN, fmtTok, savePrefs, showView,
// showProjectDetail.

// ─── Stats (hero cost totals + secondary chips) ────────────────────────
async function loadStats() {
  try {
    const d = await safeFetch('/api/stats');
    state.stats = d;
    renderStats(d);
    markUpdated('stats');
    reportSuccess('loadStats');
  } catch (e) { reportError('loadStats', e); }
}
function renderStats(data) {
  const t = data.today || {}, a = data.all_time || {};
  set('statTodayCost', fmt$(t.cost_usd));
  set('statTodayMsg', `${fmtN(t.messages || 0)} 메시지`);
  set('statTodayTokens', fmtTok((t.input_tokens || 0) + (t.output_tokens || 0)));
  set('statTodaySessions', `${fmtN(t.sessions || 0)} 세션`);
  set('statAllCost', fmt$(a.cost_usd));
  set('statAllSessions', `${fmtN(a.total_sessions || 0)} 세션`);
  set('statAllTokens', fmtTok((a.input_tokens || 0) + (a.output_tokens || 0)));
  set('statAllMessages', `${fmtN(a.messages || 0)} 메시지`);
  const rIn = (a.input_tokens || 0) + (a.cache_read_tokens || 0);
  const cEff = rIn > 0 ? ((a.cache_read_tokens || 0) / rIn * 100) : 0;
  set('statCacheEff', cEff.toFixed(1) + '%');
  set('statCacheSaved', `${fmtTok(a.cache_read_tokens || 0)} 읽기 · ${fmtTok(a.cache_creation_tokens || 0)} 생성`);
  set('hdrToday', `오늘: ${fmt$(t.cost_usd)}`);
  set('hdrTotal', `전체: ${fmt$(a.cost_usd)}`);
}

// ─── Period usage (day / week / month) ────────────────────────────────
async function loadPeriods() {
  try {
    const d = await safeFetch('/api/usage/periods');
    renderPeriod('Day', d.day);
    renderPeriod('Week', d.week);
    renderPeriod('Month', d.month);
  } catch (e) { reportError('loadPeriods', e); }
}
function renderPeriod(key, p) {
  set(`pd${key}Cost`, fmt$(p.cost));
  const tok = (p.input_tokens || 0) + (p.output_tokens || 0);
  set(`pd${key}Detail`,
    `${fmtTok(tok)} tok · ${fmtN(p.messages)}건 · 캐시 ${fmtTok(p.cache_read_tokens || 0)}`);
  const el = document.getElementById(`pd${key}Delta`);
  if (!el) return;
  if (p.prev_cost > 0) {
    const s = p.delta_pct >= 0 ? '▲' : '▼';
    el.textContent = `${s} ${Math.abs(p.delta_pct).toFixed(0)}% vs 이전 (${fmt$(p.prev_cost)})`;
    el.className = 'text-[10px] font-semibold mt-1 ' +
      (p.delta_pct >= 0 ? 'text-emerald-400/60' : 'text-red-400/60');
  } else {
    el.textContent = p.cost > 0 ? '신규' : '';
    el.className = 'text-[10px] font-semibold mt-1 text-white/15';
  }
}

// ─── Cost forecasting + burn-rate ─────────────────────────────────────
async function loadForecast() {
  try {
    const d = await safeFetch('/api/forecast?days=14');
    // IMPORTANT: use the global set() from app.js (which also removes the
    // .skeleton class on write). A local setEl helper that only touches
    // textContent leaves the shimmer animation running OVER the real text —
    // looks identical to a loading failure.
    set('forecastEOM', fmt$(d.projected_eom_cost));
    set('forecastEOMDetail',
      `MTD ${fmt$(d.mtd_cost)} · ${d.days_left_in_month}일 남음`);
    set('forecastAvg', fmt$(d.avg_cost_per_day));
    set('forecastAvgDetail', `${fmtN(d.avg_msgs_per_day || 0)} 메시지/일`);

    // Humanise seconds-until-burn-out as "N일 N시간 후" / "N시간 후" / "N분 후"
    // with urgency color coding. DOM-builder form (no innerHTML templates) so
    // upstream values can't leak markup.
    const buildBurnoutSpan = (sec, limit, used) => {
      const span = document.createElement('span');
      if (sec === null || sec === undefined) {
        span.className = 'text-white/30';
        span.textContent = '예산 미설정';
        return span;
      }
      if (used >= limit) {
        span.className = 'text-red-400 font-bold';
        span.textContent = `초과 (${fmt$(used)}/${fmt$(limit)})`;
        return span;
      }
      const days = Math.floor(sec / 86400);
      const hours = Math.floor((sec % 86400) / 3600);
      const label = days >= 1 ? `${days}일 ${hours}시간 후`
        : hours >= 1 ? `${hours}시간 후`
        : `${Math.floor(sec / 60)}분 후`;
      span.className = 'font-bold ' + (sec < 3600 ? 'text-red-400'
        : sec < 86400 ? 'text-amber-400'
        : 'text-emerald-400/85');
      span.textContent = label;
      return span;
    };
    const setBurnout = (elId, prefix, sec, limit, used) => {
      const el = document.getElementById(elId);
      if (!el) return;
      el.textContent = prefix + ' ';
      el.appendChild(buildBurnoutSpan(sec, limit, used));
      el.classList.remove('skeleton');
    };
    setBurnout('forecastBurnoutDaily', '일간',
      d.daily_budget_burnout_seconds, d.daily_limit, d.daily_used);
    setBurnout('forecastBurnoutWeekly', '주간',
      d.weekly_budget_burnout_seconds, d.weekly_limit, d.weekly_used);
  } catch (e) {
    reportError('loadForecast', e);
  }
}

// ─── Overview drill-down helpers ──────────────────────────────────────
function _todayISO() {
  const d = new Date();
  const mm = String(d.getMonth() + 1).padStart(2, '0');
  const dd = String(d.getDate()).padStart(2, '0');
  return `${d.getFullYear()}-${mm}-${dd}`;
}
function _isoDaysAgo(n) {
  const d = new Date();
  d.setDate(d.getDate() - n);
  const mm = String(d.getMonth() + 1).padStart(2, '0');
  const dd = String(d.getDate()).padStart(2, '0');
  return `${d.getFullYear()}-${mm}-${dd}`;
}
function drillToSessionsToday() {
  const today = _todayISO();
  setAdvFilters({ date_from: today, date_to: today, cost_min: '', cost_max: '' });
  savePrefs({ advFilters: getAdvFilters() });
  setPage(1);
  showView('sessions');
  const g = id => document.getElementById(id);
  if (g('advDateFrom')) g('advDateFrom').value = today;
  if (g('advDateTo'))   g('advDateTo').value   = today;
}
function drillToSessionsWeek() {
  const to = _todayISO(), from = _isoDaysAgo(6);
  setAdvFilters({ date_from: from, date_to: to, cost_min: '', cost_max: '' });
  savePrefs({ advFilters: getAdvFilters() });
  setPage(1);
  showView('sessions');
  const g = id => document.getElementById(id);
  if (g('advDateFrom')) g('advDateFrom').value = from;
  if (g('advDateTo'))   g('advDateTo').value   = to;
}

// ─── TOP 5 projects ───────────────────────────────────────────────────
// Preview cleanup is now done server-side (main.py:summarize_preview) and
// delivered as last_message.summary_line. The frontend just renders it.
async function loadTopProjects() {
  try {
    const data = await safeFetch('/api/projects/top?limit=5&with_last_message=true');
    const projects = data.projects || [];
    const c = document.getElementById('topProjectsList');
    if (!projects.length) {
      c.innerHTML = '<div class="text-center text-white/10 text-xs py-8">데이터 없음</div>';
      return;
    }
    const mx = Math.max(...projects.map(p => p.total_cost || 0), 1);
    const cols = ['#34d399', '#60a5fa', '#fbbf24', '#22d3ee', '#a78bfa', '#fb7185', '#34d399', '#60a5fa', '#fbbf24', '#22d3ee'];
    c.textContent = '';
    projects.forEach((p, i) => {
      const pct = ((p.total_cost || 0) / mx * 100).toFixed(1);
      const rc = i < 3 ? ['text-amber-400', 'text-white/40', 'text-orange-400'][i] : 'text-white/15';
      const lm = p.last_message;
      const cleaned = lm ? (lm.summary_line || lm.preview || '') : '';
      const previewLine = cleaned
        ? `<div class="text-[11px] text-white/35 mt-2 leading-relaxed whitespace-normal" style="display:-webkit-box;-webkit-line-clamp:4;-webkit-box-orient:vertical;overflow:hidden" title="${esc(lm.preview || '')}"><iconify-icon icon="solar:chat-round-line-linear" width="10" class="inline text-white/25 mr-0.5 align-[-1px]"></iconify-icon>${esc(cleaned)}</div>`
        : '';
      const liveBadge = p.is_active
        ? `<span class="ml-1.5 inline-flex items-center gap-1 px-1.5 py-0.5 rounded-full bg-emerald-500/15 text-emerald-300/90 ring-1 ring-emerald-500/40 text-[9px] font-bold uppercase tracking-wider align-middle" title="최근 30분 이내 활동"><span class="w-1 h-1 rounded-full bg-emerald-400 animate-pulse"></span>LIVE</span>`
        : '';
      // Status badge — shown to the LEFT of the project name. Different
      // styles for different states: idle (amber), active tool (cyan),
      // active subagent (blue).
      const idleKey = (p.project_name || '') + '|' + (p.project_path || '');
      const idleEntry = (state.idleProjects && state.idleProjects[idleKey]) || null;
      let idleBadge = '';
      if (idleEntry) {
        const STATUS_BADGE = {
          'end_turn':        { label: '입력 대기',       icon: 'solar:hourglass-line-linear',    bg: 'bg-amber-500/15', text: 'text-amber-300/95', ring: 'ring-amber-500/40',   pulse: true  },
          'tool_use':        { label: '권한 승인 대기',  icon: 'solar:shield-check-linear',      bg: 'bg-amber-500/15', text: 'text-amber-300/95', ring: 'ring-amber-500/40',   pulse: true  },
          'active_subagent': { label: '에이전트 작업 중', icon: 'solar:cpu-bolt-linear',          bg: 'bg-blue-500/15',  text: 'text-blue-300/90',  ring: 'ring-blue-500/40',    pulse: true  },
          'active_tool':     { label: '도구 실행 중',    icon: 'solar:settings-minimalistic-linear', bg: 'bg-cyan-500/15',  text: 'text-cyan-300/90',  ring: 'ring-cyan-500/30',    pulse: false },
        };
        const cfg = STATUS_BADGE[idleEntry.reason] || STATUS_BADGE['end_turn'];
        const title = esc(idleEntry.preview || cfg.label);
        idleBadge = `<span class="mr-1.5 inline-flex items-center gap-1 px-1.5 py-0.5 rounded-full ${cfg.bg} ${cfg.text} ring-1 ${cfg.ring} text-[9px] font-bold uppercase tracking-wider align-middle${cfg.pulse ? ' animate-pulse' : ''}" title="${title}"><iconify-icon icon="${cfg.icon}" width="10" class="inline"></iconify-icon>${cfg.label}</span>`;
      }
      const row = document.createElement('div');
      row.className = 'grid grid-cols-[28px_1fr_auto_auto_auto] items-start gap-2 py-4 border-b border-white/[0.03] last:border-b-0 cursor-pointer hover:bg-white/[0.03] rounded-md px-2 spring' + (p.is_active ? ' bg-emerald-500/[0.02]' : '');
      row.title = '클릭하여 프로젝트 상세 보기';
      row.setAttribute('tabindex', '0');
      row.setAttribute('role', 'button');
      row.addEventListener('keydown', (e) => { if (e.key === 'Enter' || e.key === ' ') { e.preventDefault(); row.click(); } });
      // NOTE: innerHTML here is safe — all dynamic values pass through esc() or
// are numeric (pct, i, cols[i], fmt$, fmtTok). No raw user input.
row.innerHTML = `<span class="text-sm font-extrabold text-center pt-0.5 ${rc}">#${i+1}</span><div class="min-w-0"><div class="text-sm font-semibold text-white/60 truncate">${idleBadge}${esc(p.project_name||'—')}${liveBadge}</div><div class="h-1.5 bg-white/5 rounded-full mt-2 overflow-hidden"><div class="h-full rounded-full" style="width:${pct}%;background:${cols[i%cols.length]}"></div></div>${previewLine}</div><button data-peek-btn type="button" title="마지막 대화 미리보기" aria-label="마지막 대화 미리보기" class="flex items-center gap-1 self-start mt-0.5 px-2 py-1 rounded-full bg-accent/10 hover:bg-accent/25 text-accent/80 hover:text-accent ring-1 ring-accent/30 hover:ring-accent/60 text-[10px] font-bold spring"><iconify-icon icon="solar:eye-linear" width="13" style="pointer-events:none"></iconify-icon><span style="pointer-events:none">미리보기</span></button><span class="text-sm font-bold text-amber-400/70 whitespace-nowrap pt-0.5">${fmt$(p.total_cost)}</span><span class="text-[11px] text-white/20 whitespace-nowrap w-16 text-right pt-0.5">${fmtTok(p.total_tokens||0)}</span>`;
      row.dataset.projectName = p.project_name || '';
      row.dataset.projectPath = p.project_path || '';
      // 행 본체: 기존 프로젝트 상세 모달로 드릴
      row.addEventListener('click', (ev) => {
        if (ev.target.closest('[data-peek-btn]')) return;  // peek 버튼은 패스
        showProjectDetail(p.project_name, p.project_path);
      });
      // 눈 아이콘 버튼: 우측 drawer 슬라이드 in
      const peekBtn = row.querySelector('[data-peek-btn]');
      if (peekBtn) {
        peekBtn.addEventListener('click', (ev) => {
          ev.stopPropagation();
          topPreviewOpen(p);
        });
      }
      c.appendChild(row);
    });
    // Real-time refresh: if the preview panel is currently showing one of
    // these projects, rebuild it with the fresh last_message.
    if (typeof topPreviewMaybeRefresh === 'function') topPreviewMaybeRefresh(projects);
  } catch (e) { reportError('loadTopProjects', e); }
}


// ─── TOP 5 preview panel (right slide-in) ──────────────────────────────
// State: which project is currently shown. When loadTopProjects runs via
// debouncedRefresh, we re-populate the panel if its project is still in
// the new list (so the content reflects the latest assistant message).
let topPreviewState = { projectName: null, projectPath: null };

function topPreviewOpen(project) {
  if (!project) return;
  topPreviewState = {
    projectName: project.project_name || '',
    projectPath: project.project_path || '',
  };
  const panel    = document.getElementById('topPreviewPanel');
  const backdrop = document.getElementById('topPreviewBackdrop');
  const title    = document.getElementById('topPreviewProject');
  const meta     = document.getElementById('topPreviewMeta');
  const body     = document.getElementById('topPreviewBody');
  const updAt    = document.getElementById('topPreviewUpdatedAt');
  if (!panel) return;

  // Title row
  if (title) title.textContent = project.project_name || '—';
  if (meta) {
    const parts = [];
    if (project.total_cost != null) parts.push(fmt$(project.total_cost));
    if (project.total_tokens != null) parts.push(fmtTok(project.total_tokens) + ' tok');
    if (project.is_active) parts.push('LIVE');
    parts.push(project.project_path || '');
    meta.textContent = parts.join(' · ');
  }

  // Body
  const lm = project.last_message;
  body.textContent = '';
  if (lm && lm.preview) {
    const summary = document.createElement('div');
    summary.className = 'text-white/90 font-semibold mb-3 leading-snug';
    summary.textContent = (lm.summary_line || lm.preview).slice(0, 200);

    const divider = document.createElement('div');
    divider.className = 'text-[9px] uppercase tracking-widest text-white/30 mb-2';
    divider.textContent = '원문 (' + (lm.timestamp ? fmtTime(lm.timestamp) : '—') + ' · ' + (lm.model || '—') + ')';

    const full = document.createElement('div');
    full.className = 'text-white/70 leading-relaxed';
    full.textContent = lm.preview;

    body.append(summary, divider, full);
  } else {
    const empty = document.createElement('div');
    empty.className = 'text-white/30 text-center py-8';
    empty.textContent = '이 프로젝트에는 아직 assistant 메시지가 없습니다';
    body.appendChild(empty);
  }
  if (updAt) updAt.textContent = fmtTime(new Date().toISOString());

  // Slide in drawer (inline style for transform to bypass JIT class availability)
  panel.setAttribute('aria-hidden', 'false');
  panel.style.transform = 'translateX(0)';
  panel.style.opacity = '1';
  panel.style.pointerEvents = 'auto';
  if (backdrop) {
    backdrop.style.opacity = '1';
    backdrop.style.pointerEvents = 'auto';
  }

  // Focus the first interactive element in the panel
  setTimeout(() => { panel.querySelector('button')?.focus(); }, 100);

  // Highlight active row
  document.querySelectorAll('#topProjectsList > div').forEach(r => {
    const match = r.dataset.projectName === topPreviewState.projectName
               && r.dataset.projectPath === topPreviewState.projectPath;
    r.classList.toggle('ring-1', match);
    r.classList.toggle('ring-accent/30', match);
  });
}

function topPreviewClose() {
  topPreviewState = { projectName: null, projectPath: null };
  const panel    = document.getElementById('topPreviewPanel');
  const backdrop = document.getElementById('topPreviewBackdrop');
  if (!panel) return;
  panel.setAttribute('aria-hidden', 'true');
  panel.style.transform = 'translateX(100%)';
  panel.style.opacity = '0';
  panel.style.pointerEvents = 'none';
  if (backdrop) {
    backdrop.style.opacity = '0';
    backdrop.style.pointerEvents = 'none';
  }
  document.querySelectorAll('#topProjectsList > div').forEach(r => {
    r.classList.remove('ring-1', 'ring-accent/30');
  });
}

// Drill into the full project modal from the preview panel footer button
function topPreviewOpenProjectModal() {
  if (topPreviewState.projectName) {
    showProjectDetail(topPreviewState.projectName, topPreviewState.projectPath);
  }
}

// Called from loadTopProjects AFTER the new list is rendered. If the panel
// is showing a project that's still in the list, refresh its content with
// the newly fetched last_message (realtime update from WS batch refresh).
function topPreviewMaybeRefresh(projects) {
  if (!topPreviewState.projectName) return;
  const match = projects.find(p =>
    p.project_name === topPreviewState.projectName &&
    p.project_path === topPreviewState.projectPath
  );
  if (match) {
    topPreviewOpen(match);
  }
}


// ═══ plan.js ═══
// Claude Dashboard — plan/budget module.
// Extracted from app.js. Loaded as a regular (non-module) script after app.js;
// all functions become window.* globals so inline onclick="openPlanSettings()"
// handlers in index.html continue to resolve.
//
// Dependencies from app.js: state, fetch, reportError, showToast, fmt$,
// fmtTok, fmtN.

// ─── Plan Usage ─────────────────────────────────────────────────────────
let planTimer = null, planData = null;

function clearPlanTimer() {
  if (planTimer) { clearInterval(planTimer); planTimer = null; }
}

async function loadPlanUsage() {
  try {
    const resp = await fetch('/api/plan/usage');
    if (!resp.ok) throw new Error(`HTTP ${resp.status}`);
    planData = await resp.json();
    renderPlanBlock('Daily', planData.daily);
    renderPlanBlock('Weekly', planData.weekly);
    if (planTimer) clearInterval(planTimer);
    planTimer = setInterval(tickPlanCountdown, 1000);
  } catch (e) { reportError('loadPlanUsage', e); }
}

// Small write helper that also clears the .skeleton loader class once real
// data arrives. Only used by the plan module — kept local.
function _writeText(el, txt) {
  if (!el) return;
  el.textContent = txt;
  if (el.classList.contains('skeleton')) el.classList.remove('skeleton');
}

function renderPlanBlock(key, b) {
  if (!b) return;
  const el = id => document.getElementById(`plan${key}${id}`);
  const pctEl = el('Pct'), barEl = el('Bar'), usedEl = el('Used'),
        tokEl = el('Tokens'), msgEl = el('Msgs'),
        remainEl = el('Remain'), resetEl = el('Reset');
  const pct = b.percentage || 0;
  const bw = Math.min(pct, 100);
  const color = planBarColor(pct);
  if (pctEl) { _writeText(pctEl, pct.toFixed(1) + '%'); pctEl.style.color = color; }
  if (barEl) { barEl.style.width = bw + '%'; barEl.style.background = color; }
  _writeText(usedEl,   `${fmt$(b.used_cost)} / ${fmt$(b.limit_cost)}`);
  _writeText(tokEl,    fmtTok(b.used_tokens) + (b.cache_tokens ? ` (캐시 ${fmtTok(b.cache_tokens)})` : ''));
  _writeText(msgEl,    fmtN(b.messages) + '건');
  _writeText(remainEl, fmtDuration(b.remaining_seconds));
  _writeText(resetEl,  fmtResetTime(b.reset_at));
}

const PLAN_C = { green: '#34d399', yellow: '#fbbf24', orange: '#fb923c', red: '#f87171' };
function planBarColor(p) {
  if (p >= 90) return PLAN_C.red;
  if (p >= 75) return PLAN_C.orange;
  if (p >= 50) return PLAN_C.yellow;
  return PLAN_C.green;
}

// checkPlanAlerts — disabled: usage warning popup removed per user request.

function tickPlanCountdown() {
  if (!planData) return;
  planData.daily.remaining_seconds = Math.max(0, planData.daily.remaining_seconds - 1);
  planData.weekly.remaining_seconds = Math.max(0, planData.weekly.remaining_seconds - 1);
  const dr = document.getElementById('planDailyRemain');
  const wr = document.getElementById('planWeeklyRemain');
  if (dr) dr.textContent = fmtDuration(planData.daily.remaining_seconds);
  if (wr) wr.textContent = fmtDuration(planData.weekly.remaining_seconds);
}

function fmtDuration(s) {
  if (s <= 0) return '만료';
  const d = Math.floor(s / 86400);
  const h = Math.floor(s % 86400 / 3600);
  const m = Math.floor(s % 3600 / 60);
  if (d > 0) return `${d}일 ${h}시간`;
  if (h > 0) return `${h}시간 ${m}분`;
  return `${m}분`;
}

function fmtResetTime(iso) {
  if (!iso) return '—';
  const d = new Date(iso);
  if (isNaN(d)) return iso;
  const days = ['일', '월', '화', '수', '목', '금', '토'];
  return d.toLocaleDateString('ko-KR', { month: 'short', day: 'numeric' }) +
         ` (${days[d.getDay()]}) ` +
         d.toLocaleTimeString('ko-KR', { hour: '2-digit', minute: '2-digit' });
}

// ─── Plan Settings modal ───────────────────────────────────────────────
function openPlanSettings() {
  fetch('/api/plan/config').then(r => r.json()).then(cfg => {
    document.getElementById('cfgDailyLimit').value    = cfg.daily_cost_limit  || 50;
    document.getElementById('cfgWeeklyLimit').value   = cfg.weekly_cost_limit || 300;
    document.getElementById('cfgResetHour').value     = cfg.reset_hour         || 0;
    document.getElementById('cfgResetWeekday').value  = cfg.reset_weekday      || 0;
    const tz = cfg.timezone_offset ?? Math.round(-new Date().getTimezoneOffset() / 60);
    document.getElementById('cfgTimezone').value = tz;
    if (cfg.detected?.label) {
      const h = document.getElementById('planDetectedHint');
      if (h) h.textContent = `감지: ${cfg.detected.label}`;
    }
    setSettingsTab('plan');
    document.getElementById('planModal').style.display = 'flex';
  });
}

function setSettingsTab(tab) {
  document.querySelectorAll('.settings-tab').forEach(btn => {
    const active = btn.dataset.settingsTab === tab;
    btn.classList.toggle('text-accent', active);
    btn.classList.toggle('border-accent', active);
    btn.classList.toggle('text-white/35', !active);
    btn.classList.toggle('border-transparent', !active);
  });
  const planTab = document.getElementById('settingsTabPlan');
  const dispTab = document.getElementById('settingsTabDisplay');
  if (planTab) planTab.classList.toggle('hidden', tab !== 'plan');
  if (dispTab) dispTab.classList.toggle('hidden', tab !== 'display');
}

// Bind settings tab clicks once on load
document.querySelectorAll('.settings-tab').forEach(btn => {
  btn.addEventListener('click', () => setSettingsTab(btn.dataset.settingsTab));
});

function closePlanSettings() {
  document.getElementById('planModal').style.display = 'none';
}

async function savePlanConfig() {
  const body = {
    daily_cost_limit:  parseFloat(document.getElementById('cfgDailyLimit').value) || 50,
    weekly_cost_limit: parseFloat(document.getElementById('cfgWeeklyLimit').value) || 300,
    reset_hour:        parseInt(document.getElementById('cfgResetHour').value) || 0,
    reset_weekday:     parseInt(document.getElementById('cfgResetWeekday').value) || 0,
    timezone_offset:   parseInt(document.getElementById('cfgTimezone').value) || 9,
    timezone_name:     'Asia/Seoul',
  };
  try {
    const r = await fetch('/api/plan/config', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(body),
    });
    if (!r.ok) {
      const err = await r.json().catch(() => ({}));
      throw new Error(err.detail || r.statusText);
    }
    closePlanSettings();
    loadPlanUsage();
    showToast('설정이 저장되었습니다', { type: 'success' });
  } catch (e) {
    showToast('저장 실패: ' + (e.message || e), { type: 'error' });
  }
}

function applyPlanPreset(t) {
  const p = { pro: { d: 15, w: 80 }, max5x: { d: 80, w: 400 }, max20x: { d: 300, w: 1500 } };
  const v = p[t];
  if (v) {
    document.getElementById('cfgDailyLimit').value = v.d;
    document.getElementById('cfgWeeklyLimit').value = v.w;
  }
}

// Populate the reset-hour dropdown once on load
(function () {
  const s = document.getElementById('cfgResetHour');
  if (!s) return;
  for (let h = 0; h < 24; h++) {
    const o = document.createElement('option');
    o.value = h;
    o.textContent = String(h).padStart(2, '0') + ':00';
    s.appendChild(o);
  }
})();


// ═══ subagents.js ═══
// Claude Dashboard — subagent analysis module.
// Extracted from app.js. Powers the #/subagents view (heatmap +
// success matrix). Loaded as a regular script after app.js.
//
// Dependencies from app.js: safeFetch, esc, fmtN, fmt$, stopReasonBadge.

// ─── Subagent detail panels (6 remaining sections) ────────────────────
async function loadSubagentDetails() {
  try {
    const d = await safeFetch('/api/subagents/stats');
    _renderByType(d);
    _renderByStopReason(d);
    _renderTopList('subagentTopCost', d.top_by_cost || [], 'cost');
    _renderTopList('subagentTopDuration', d.top_by_duration || [], 'duration');
    _renderTopParents(d.parents_with_most_subs || []);
  } catch (e) { reportError('loadSubagentDetails', e); }
}

function _renderByType(d) {
  const wrap = document.getElementById('subagentByType');
  if (!wrap) return;
  const rows = d.by_type || [];
  const totals = d.totals || {};
  if (!rows.length) { wrap.textContent = '데이터 없음'; return; }
  // NOTE: innerHTML here is safe — all values pass through esc()/fmtN()/fmt$()
  let html = '<table class="text-[10px] min-w-full"><thead><tr class="text-white/35 font-bold">';
  html += '<th class="text-left px-2 py-1">유형</th><th class="text-right px-2 py-1">수</th><th class="text-right px-2 py-1">비용</th><th class="text-right px-2 py-1">평균</th><th class="text-right px-2 py-1">메시지</th>';
  html += '</tr></thead><tbody>';
  rows.forEach(r => {
    html += `<tr><td class="px-2 py-1.5 font-bold text-white/60">${esc(r.agent_type)}</td>`;
    html += `<td class="px-2 py-1.5 text-right tabular-nums text-white/70">${fmtN(r.count)}</td>`;
    html += `<td class="px-2 py-1.5 text-right tabular-nums text-amber-400/80">${fmt$(r.cost)}</td>`;
    html += `<td class="px-2 py-1.5 text-right tabular-nums text-white/50">${fmt$(r.avg_cost)}</td>`;
    html += `<td class="px-2 py-1.5 text-right tabular-nums text-white/50">${fmtN(r.messages)}</td></tr>`;
  });
  html += `<tr class="border-t border-white/[0.05]"><td class="px-2 py-1.5 font-bold text-white/40">합계</td>`;
  html += `<td class="px-2 py-1.5 text-right tabular-nums text-white/50">${fmtN(totals.count)}</td>`;
  html += `<td class="px-2 py-1.5 text-right tabular-nums text-amber-400/60">${fmt$(totals.cost)}</td>`;
  html += `<td></td><td class="px-2 py-1.5 text-right tabular-nums text-white/40">${fmtN(totals.messages)}</td></tr>`;
  html += '</tbody></table>';
  wrap.innerHTML = html;
}

function _renderByStopReason(d) {
  const wrap = document.getElementById('subagentByStopReason');
  if (!wrap) return;
  const rows = d.by_stop_reason || [];
  if (!rows.length) { wrap.textContent = '데이터 없음'; return; }
  const total = rows.reduce((s, r) => s + (r.count || 0), 0);
  // NOTE: innerHTML safe — all dynamic values via esc()/fmtN()/fmt$()/stopReasonBadge()
  let html = '<table class="text-[10px] min-w-full"><thead><tr class="text-white/35 font-bold">';
  html += '<th class="text-left px-2 py-1">종료 사유</th><th class="text-right px-2 py-1">수</th><th class="text-right px-2 py-1">비율</th><th class="text-right px-2 py-1">비용</th>';
  html += '</tr></thead><tbody>';
  rows.forEach(r => {
    const pct = total > 0 ? (r.count / total * 100).toFixed(1) : '0';
    html += `<tr><td class="px-2 py-1.5 font-bold text-white/60">${stopReasonBadge(r.stop_reason)} ${esc(r.stop_reason)}</td>`;
    html += `<td class="px-2 py-1.5 text-right tabular-nums text-white/70">${fmtN(r.count)}</td>`;
    html += `<td class="px-2 py-1.5 text-right tabular-nums text-white/50">${pct}%</td>`;
    html += `<td class="px-2 py-1.5 text-right tabular-nums text-amber-400/80">${fmt$(r.cost)}</td></tr>`;
  });
  html += '</tbody></table>';
  wrap.innerHTML = html;
}

function _renderTopList(containerId, rows, mode) {
  const wrap = document.getElementById(containerId);
  if (!wrap) return;
  if (!rows.length) { wrap.textContent = '데이터 없음'; return; }
  wrap.textContent = '';
  rows.forEach((r, i) => {
    const div = document.createElement('div');
    div.className = 'flex items-center gap-2 py-1.5 border-b border-white/[0.03] last:border-b-0 text-[10px]';
    const rank = document.createElement('span');
    rank.className = 'text-white/25 font-bold w-5 text-center';
    rank.textContent = '#' + (i + 1);
    const info = document.createElement('div');
    info.className = 'flex-1 min-w-0';
    const name = document.createElement('div');
    name.className = 'text-white/60 truncate font-semibold';
    name.textContent = r.agent_type || r.agent_description || r.id || '—';
    name.title = r.id || '';
    const sub = document.createElement('div');
    sub.className = 'text-[9px] text-white/30';
    sub.textContent = (r.message_count || 0) + ' msg';
    info.append(name, sub);
    const val = document.createElement('span');
    val.className = 'tabular-nums font-bold whitespace-nowrap';
    if (mode === 'cost') {
      val.className += ' text-amber-400/80';
      val.textContent = fmt$(r.cost_usd);
    } else {
      val.className += ' text-cyan-400/80';
      val.textContent = fmtDurationSec(r.duration_seconds || 0);
    }
    div.append(rank, info, val);
    wrap.appendChild(div);
  });
}

function _renderTopParents(rows) {
  const wrap = document.getElementById('subagentTopParents');
  if (!wrap) return;
  if (!rows.length) { wrap.textContent = '데이터 없음'; return; }
  wrap.textContent = '';
  rows.forEach((r, i) => {
    const div = document.createElement('div');
    div.className = 'flex items-center gap-2 py-1.5 border-b border-white/[0.03] last:border-b-0 text-[10px]';
    const rank = document.createElement('span');
    rank.className = 'text-white/25 font-bold w-5 text-center';
    rank.textContent = '#' + (i + 1);
    const info = document.createElement('div');
    info.className = 'flex-1 min-w-0';
    const name = document.createElement('div');
    name.className = 'text-white/60 truncate font-semibold';
    name.textContent = r.project || '—';
    name.title = r.parent_session_id || '';
    const sub = document.createElement('div');
    sub.className = 'text-[9px] text-white/30';
    sub.textContent = (r.sub_count || 0) + ' subagents · ' + fmt$(r.total_cost);
    info.append(name, sub);
    const val = document.createElement('span');
    val.className = 'tabular-nums font-bold text-purple-400/80 whitespace-nowrap';
    val.textContent = (r.sub_count || 0) + '개';
    div.append(rank, info, val);
    wrap.appendChild(div);
  });
}

// ─── Subagent success matrix (agentType × stop_reason) ─────────────────
async function loadSubagentSuccessMatrix() {
  const wrap = document.getElementById('subagentSuccessMatrix');
  if (!wrap) return;
  try {
    const d = await safeFetch('/api/subagents/stats');
    const rows = d.by_type_and_stop_reason || [];
    if (!rows.length) {
      wrap.innerHTML = '<div class="text-center text-white/20 text-xs py-6">데이터 없음</div>';
      return;
    }
    const types = [];
    const seenT = new Set();
    const reasons = [];
    const seenR = new Set();
    const cells = {};
    const rowTotals = {};
    for (const r of rows) {
      if (!seenT.has(r.agent_type)) { seenT.add(r.agent_type); types.push(r.agent_type); }
      if (!seenR.has(r.stop_reason)) { seenR.add(r.stop_reason); reasons.push(r.stop_reason); }
      cells[`${r.agent_type}|${r.stop_reason}`] = { count: r.count, cost: r.cost };
      rowTotals[r.agent_type] = (rowTotals[r.agent_type] || 0) + r.count;
    }
    const preferred = ['end_turn', 'tool_use', 'stop_sequence', 'max_tokens', 'refusal', '(missing)'];
    reasons.sort((a, b) => {
      const ia = preferred.indexOf(a), ib = preferred.indexOf(b);
      if (ia !== -1 && ib !== -1) return ia - ib;
      if (ia !== -1) return -1;
      if (ib !== -1) return 1;
      return a.localeCompare(b);
    });

    let html = '<table class="text-[10px] min-w-full"><thead><tr>';
    html += '<th class="text-left px-2 py-1 text-white/35 font-bold sticky left-0 bg-base">agentType \\ stop_reason</th>';
    reasons.forEach(r => {
      const badge = stopReasonBadge(r);
      html += `<th class="px-2 py-1 text-white/35 font-bold whitespace-nowrap">${badge} ${esc(r)}</th>`;
    });
    html += '<th class="px-2 py-1 text-white/50 font-bold whitespace-nowrap">success %</th>';
    html += '</tr></thead><tbody>';
    types.forEach(t => {
      const total = rowTotals[t] || 0;
      const successCount = cells[`${t}|end_turn`]?.count || 0;
      const successPct = total > 0 ? Math.round((successCount / total) * 100) : 0;
      const successCls = successPct >= 90 ? 'text-emerald-400/90'
        : successPct >= 70 ? 'text-amber-400/85'
        : 'text-red-400/80';
      html += `<tr><td class="px-2 py-1 font-bold text-white/60 sticky left-0 bg-base whitespace-nowrap">${esc(t)}</td>`;
      reasons.forEach(r => {
        const cell = cells[`${t}|${r}`];
        if (!cell) {
          html += '<td class="px-2 py-1 text-center text-white/10">·</td>';
        } else {
          const title = `${t} · ${r}: ${cell.count}건, ${fmt$(cell.cost)}`;
          html += `<td class="px-2 py-1 text-center tabular-nums text-white/75" title="${esc(title)}">${fmtN(cell.count)}</td>`;
        }
      });
      html += `<td class="px-2 py-1 text-center tabular-nums font-bold ${successCls}">${successPct}% <span class="text-white/35">(${total})</span></td>`;
      html += '</tr>';
    });
    html += '</tbody></table>';
    wrap.innerHTML = html;
  } catch (e) {
    reportError('loadSubagentSuccessMatrix', e);
    wrap.innerHTML = '<div class="text-center text-red-400/40 text-xs py-6">로딩 실패</div>';
  }
}

// ─── Subagent heatmap (agentType × project) ────────────────────────────
async function loadSubagentHeatmap() {
  const wrap = document.getElementById('subagentHeatmap');
  if (!wrap) return;
  try {
    const d = await safeFetch('/api/subagents/heatmap');
    const projects = d.projects || [];
    const types = d.agent_types || [];
    const cells = d.cells || {};
    if (!projects.length || !types.length) {
      wrap.innerHTML = '<div class="text-center text-white/20 text-xs py-6">데이터 없음</div>';
      return;
    }
    let total = 0, totalCost = 0;
    Object.values(cells).forEach(v => { total += v.count || 0; totalCost += v.cost || 0; });
    const maxCost = Math.max(...Object.values(cells).map(v => v.cost || 0), 1);

    let html = '<table class="text-[10px] min-w-full"><thead><tr>';
    html += '<th class="text-left px-2 py-1 text-white/35 font-bold sticky left-0 bg-base">agentType \\ project</th>';
    projects.forEach(p => {
      html += `<th class="px-2 py-1 text-white/35 font-bold whitespace-nowrap" title="${esc(p)}">${esc(p.length > 14 ? p.slice(0, 12) + '…' : p)}</th>`;
    });
    html += '</tr></thead><tbody>';
    types.forEach(t => {
      html += `<tr><td class="px-2 py-1 font-bold text-white/60 sticky left-0 bg-base whitespace-nowrap">${esc(t)}</td>`;
      projects.forEach(p => {
        const cell = cells[`${t}|${p}`];
        if (!cell) {
          html += '<td class="px-2 py-1 text-center text-white/10">·</td>';
        } else {
          const intensity = Math.min(1, (cell.cost || 0) / maxCost);
          const bg = intensity > 0.66
            ? `rgba(251,113,133,${0.20 + intensity*0.35})`
            : intensity > 0.33
              ? `rgba(251,191,36,${0.15 + intensity*0.35})`
              : `rgba(52,211,153,${0.12 + intensity*0.25})`;
          const title = `${t} × ${p}: ${cell.count} subagents, ${fmt$(cell.cost)}`;
          html += `<td class="px-2 py-1 text-center font-bold tabular-nums text-white/80 cursor-default" style="background:${bg}" title="${esc(title)}">${fmtN(cell.count)}</td>`;
        }
      });
      html += '</tr>';
    });
    html += '</tbody></table>';
    wrap.innerHTML = html;
    const totalEl = document.getElementById('subagentHeatmapTotal');
    if (totalEl) totalEl.textContent = `${fmtN(total)} subagents · ${fmt$(totalCost)} 누적`;
  } catch (e) {
    reportError('loadSubagentHeatmap', e);
    wrap.innerHTML = '<div class="text-center text-red-400/40 text-xs py-6">로딩 실패</div>';
  }
}


// ═══ timeline.js ═══
// Claude Dashboard — work timeline (Gantt) module (v2).
// Loaded as a plain script after app.js + charts.js.
// Depends on: state, safeFetch, reportError, reportSuccess, fmt$, fmtN,
//   fmtDurationSec, fmtTime, shortModel, showView, openConversation,
//   themeColors, grd, tck, tooltipOpts, CC, CHART_D, _prefersReducedMotion,
//   h, esc, savePrefs, _prefs, renderCompareModal.

// ─── Constants ───────────────────────────────────────────────────────────
const MODEL_COLORS = {
  opus:   { bg: 'rgba(167,139,250,A)', border: 'rgba(167,139,250,0.9)' },
  sonnet: { bg: 'rgba(52,211,153,A)',  border: 'rgba(52,211,153,0.9)'  },
  haiku:  { bg: 'rgba(34,211,238,A)',  border: 'rgba(34,211,238,0.9)'  },
  _sub:   { bg: 'rgba(96,165,250,A)',  border: 'rgba(96,165,250,0.9)'  },
  _default:{ bg:'rgba(251,191,36,A)',  border: 'rgba(251,191,36,0.9)'  },
};
const DOW_LABELS = ['\uC77C', '\uC6D4', '\uD654', '\uC218', '\uBAA9', '\uAE08', '\uD1A0'];

// ─── Range state ─────────────────────────────────────────────────────────
let _tlRange = _prefs.tlRange || '7d';
let _tlLastData = null;
let _tlCollapsed = new Set(_prefs.tlCollapsed || []);
let _tlOutlierIds = new Set();   // session ids flagged as $/hr outliers
let _tlOutlierProjs = new Set(); // project names flagged as outliers

function _daysAgo(base, n) {
  const d = new Date(base);
  d.setDate(d.getDate() - n);
  return d.toISOString().slice(0, 10);
}

function _tlDates() {
  const customFrom = document.getElementById('tlDateFrom')?.value;
  const customTo = document.getElementById('tlDateTo')?.value;
  if (customFrom && customTo) return { dateFrom: customFrom, dateTo: customTo };
  const now = new Date();
  const dateTo = now.toISOString().slice(0, 10);
  let dateFrom;
  if (_tlRange === 'today') dateFrom = dateTo;
  else if (_tlRange === '14d') dateFrom = _daysAgo(now, 14);
  else if (_tlRange === '30d') dateFrom = _daysAgo(now, 30);
  else dateFrom = _daysAgo(now, 7);
  return { dateFrom, dateTo };
}

// Compute $/hr outliers (projects where cost_per_hour > mean + 2σ).
// Also flags individual sessions within those projects whose cost > project mean.
function _computeOutliers(data) {
  _tlOutlierIds = new Set();
  _tlOutlierProjs = new Set();
  const sessions = data.sessions || [];
  if (sessions.length < 3) return;
  const byProj = new Map();
  for (const s of sessions) {
    const k = s.project_name || '(unknown)';
    if (!byProj.has(k)) byProj.set(k, []);
    byProj.get(k).push(s);
  }
  const perHrVals = [];
  const projStats = [];
  for (const [name, list] of byProj) {
    const totalCost = list.reduce((a, x) => a + (x.cost_usd || 0), 0);
    const totalDur = list.reduce((a, x) => a + (x.duration_seconds || 0), 0);
    if (totalDur < 300) continue; // skip near-zero-duration projects
    const perHr = totalCost / (totalDur / 3600);
    perHrVals.push(perHr);
    projStats.push({ name, perHr, list });
  }
  if (perHrVals.length < 3) return;
  const mean = perHrVals.reduce((a, b) => a + b, 0) / perHrVals.length;
  const variance = perHrVals.reduce((a, v) => a + (v - mean) ** 2, 0) / perHrVals.length;
  const std = Math.sqrt(variance);
  const threshold = mean + 2 * std;
  for (const p of projStats) {
    if (p.perHr > threshold && p.perHr > 5) { // need meaningful absolute $/hr too
      _tlOutlierProjs.add(p.name);
      // within project, flag top-cost sessions that drove the excess
      const projMean = p.list.reduce((a, x) => a + (x.cost_usd || 0), 0) / p.list.length;
      for (const s of p.list) {
        if ((s.cost_usd || 0) > projMean * 1.5 && (s.cost_usd || 0) > 0.5) _tlOutlierIds.add(s.id);
      }
    }
  }
}

function _modelFamily(model) {
  if (!model) return '_default';
  const m = model.toLowerCase();
  if (m.includes('opus')) return 'opus';
  if (m.includes('sonnet')) return 'sonnet';
  if (m.includes('haiku')) return 'haiku';
  return '_default';
}

// ─── Main loader ─────────────────────────────────────────────────────────
async function loadTimeline() {
  const { dateFrom, dateTo } = _tlDates();
  const showSubs = document.getElementById('tlShowSubagents')?.checked || false;
  const nodeVal = document.getElementById('tlNodeFilter')?.value || '';
  let url = `/api/timeline?date_from=${encodeURIComponent(dateFrom)}&date_to=${encodeURIComponent(dateTo)}&include_subagents=${showSubs}`;
  if (nodeVal) url += '&node=' + encodeURIComponent(nodeVal);
  _populateTlNodeFilter();
  try {
    const data = await safeFetch(url);
    _tlLastData = { data, dateFrom, dateTo };
    _computeOutliers(data);
    _renderTimelineChart(data, dateFrom, dateTo);
    _renderEfficiency(data);
    reportSuccess('loadTimeline');
  } catch (e) {
    _tlLastData = null;
    reportError('loadTimeline', e);
  }
  _loadHeatmap();
  _loadTrend();
  _loadHourlyStacked();
  _loadDelta();
}

// ═══════════════════════════════════════════════════════════════════════════
// 1. GANTT CHART
// ═══════════════════════════════════════════════════════════════════════════

function _renderTimelineChart(data, dateFrom, dateTo) {
  const sessions = data.sessions || [];
  const tzOffsetMs = (data.timezone_offset || 0) * 3600000;

  const projectMap = new Map();
  for (const s of sessions) {
    const key = s.project_name || '(unknown)';
    if (!projectMap.has(key)) projectMap.set(key, []);
    projectMap.get(key).push(s);
  }

  const projects = [...projectMap.entries()]
    .sort((a, b) => {
      const costA = a[1].reduce((sum, x) => sum + (x.cost_usd || 0), 0);
      const costB = b[1].reduce((sum, x) => sum + (x.cost_usd || 0), 0);
      return costB - costA;
    })
    .map(([name]) => name);

  if (!projects.length) { _renderEmptyTimeline(); return; }

  const visibleProjects = projects.filter(p => !_tlCollapsed.has(p));
  const collapsedCount = projects.length - visibleProjects.length;

  const barData = [], barMeta = [], barBg = [], barBorder = [], barBorderW = [];
  const costTimeline = [];
  let cumulCost = 0;

  const allSorted = [...sessions]
    .filter(s => !_tlCollapsed.has(s.project_name || '(unknown)'))
    .sort((a, b) => new Date(a.created_at) - new Date(b.created_at));

  for (const s of allSorted) {
    cumulCost += (s.cost_usd || 0);
    costTimeline.push({ x: new Date(s.created_at).getTime() + tzOffsetMs, y: cumulCost });
  }

  const maxCost = Math.max(...sessions.map(s => s.cost_usd || 0), 0.01);

  for (const proj of visibleProjects) {
    const sorted = [...(projectMap.get(proj) || [])].sort((a, b) =>
      new Date(a.created_at) - new Date(b.created_at));
    for (let i = 0; i < sorted.length; i++) {
      const s = sorted[i];
      const start = new Date(s.created_at).getTime() + tzOffsetMs;
      const end = new Date(s.updated_at).getTime() + tzOffsetMs;
      if (isNaN(start) || isNaN(end) || end <= start) continue;
      const adjustedEnd = Math.max(end, start + 120000);

      if (i > 0) {
        const prevEnd = new Date(sorted[i - 1].updated_at).getTime() + tzOffsetMs;
        const gapMs = start - prevEnd;
        if (gapMs > 1800000) {
          barData.push({ x: [prevEnd, start], y: proj });
          barMeta.push({ _isGap: true, gapMs });
          barBg.push('rgba(255,255,255,0.03)');
          barBorder.push('rgba(255,255,255,0.06)');
          barBorderW.push(1);
        }
      }

      barData.push({ x: [start, adjustedEnd], y: proj });
      barMeta.push(s);
      const family = s.is_subagent ? '_sub' : _modelFamily(s.model);
      const palette = MODEL_COLORS[family] || MODEL_COLORS._default;
      const intensity = Math.min(1, (s.cost_usd || 0) / maxCost);
      const alpha = (0.3 + intensity * 0.5).toFixed(2);
      barBg.push(palette.bg.replace('A', alpha));
      const showOutliers = document.getElementById('tlShowOutliers')?.checked;
      if (showOutliers && _tlOutlierIds.has(s.id)) {
        barBorder.push('rgba(251,113,133,0.95)'); // rose-400 — outlier
        barBorderW.push(2.5);
      } else {
        barBorder.push(palette.border);
        barBorderW.push(1);
      }
    }
  }

  const canvas = document.getElementById('chartTimeline');
  const wrap = document.getElementById('timelineChartWrap');
  wrap.style.height = Math.max(200, visibleProjects.length * 36 + 80) + 'px';
  wrap.querySelectorAll('.tl-empty-msg').forEach(n => n.remove());

  const rangeMin = new Date(dateFrom + 'T00:00:00').getTime() + tzOffsetMs;
  const rangeMax = new Date(dateTo + 'T23:59:59').getTime() + tzOffsetMs;
  const rangeDays = (rangeMax - rangeMin) / 86400000;
  const timeUnit = rangeDays <= 1 ? 'hour' : rangeDays <= 14 ? 'day' : 'week';

  const concurrentZones = _findConcurrentZones(sessions, tzOffsetMs, visibleProjects, projectMap);

  destroyChart('timeline');

  const tc = themeColors();
  const resetBtn = document.getElementById('tlResetZoom');

  const datasets = [{
    type: 'bar', label: 'Sessions', data: barData,
    backgroundColor: barBg, borderColor: barBorder,
    borderWidth: barBorderW, borderRadius: 3, borderSkipped: false,
    barPercentage: 0.7, categoryPercentage: 0.85, yAxisID: 'y', xAxisID: 'x',
  }];

  if (costTimeline.length > 1) {
    datasets.push({
      type: 'line', label: '\uB204\uC801 \uBE44\uC6A9', data: costTimeline,
      borderColor: 'rgba(251,191,36,0.5)', backgroundColor: 'rgba(251,191,36,0.05)',
      fill: true, tension: 0.3, pointRadius: 0, borderWidth: 1.5, borderDash: [4, 2],
      yAxisID: 'yCost', xAxisID: 'x',
    });
  }

  setChart('timeline', new Chart(canvas, {
    data: { labels: visibleProjects, datasets },
    options: {
      responsive: true, maintainAspectRatio: false,
      animation: { duration: _prefersReducedMotion ? 0 : 350 },
      indexAxis: 'y',
      scales: {
        x: {
          type: 'time', min: rangeMin, max: rangeMax,
          time: { unit: timeUnit, displayFormats: { hour: 'HH:mm', day: 'MM/dd', week: 'MM/dd' } },
          grid: { color: tc.gridColor, drawBorder: false },
          ticks: { color: tc.tickColor, font: { size: 11, family: 'Pretendard' }, maxTicksLimit: 12, maxRotation: 0 },
        },
        y: {
          type: 'category', labels: visibleProjects,
          grid: { color: tc.gridColor, drawBorder: false },
          ticks: {
            color: (ctx) => _projColorByName(ctx.tick?.label || visibleProjects[ctx.index] || '', 0.95),
            font: { size: 11, family: 'Pretendard', weight: 'bold' }, autoSkip: false,
          },
        },
        yCost: {
          type: 'linear', position: 'right', display: costTimeline.length > 1,
          grid: { drawOnChartArea: false },
          ticks: { color: 'rgba(251,191,36,0.5)', font: { size: 10, family: 'Pretendard' }, callback: v => '$' + v.toFixed(2) },
        },
      },
      plugins: {
        legend: { display: false },
        tooltip: {
          ...tooltipOpts(),
          filter: (item) => item.datasetIndex === 0 && barMeta[item.dataIndex] && !barMeta[item.dataIndex]._isGap,
          callbacks: {
            title: (items) => { const m = barMeta[items[0]?.dataIndex]; return m ? (m.project_name || '') : ''; },
            label: (ctx) => {
              const s = barMeta[ctx.dataIndex];
              if (!s || s._isGap) return '';
              const node = s.source_node && s.source_node !== 'local' ? ` [${s.source_node}]` : '';
              return ` ${fmtDurationSec(s.duration_seconds||0)} \u00b7 ${fmt$(s.cost_usd)} \u00b7 ${s.model?shortModel(s.model):'\u2014'}${s.is_subagent?' [sub]':''}${node}`;
            },
            afterLabel: (ctx) => { const s = barMeta[ctx.dataIndex]; return s && !s._isGap ? ` ${fmtTime(s.created_at)} ~ ${fmtTime(s.updated_at)}` : ''; },
          },
        },
        zoom: {
          pan: { enabled: true, mode: 'x', onPanComplete: () => { if (resetBtn) resetBtn.classList.remove('hidden'); } },
          zoom: {
            wheel: { enabled: true, modifierKey: 'ctrl' },
            pinch: { enabled: true },
            drag: { enabled: true, backgroundColor: 'rgba(52,211,153,0.08)', borderColor: 'rgba(52,211,153,0.3)', borderWidth: 1 },
            mode: 'x',
            onZoomComplete: () => { if (resetBtn) resetBtn.classList.remove('hidden'); },
          },
        },
      },
      onClick: (_evt, elements) => {
        if (!elements.length || elements[0].datasetIndex !== 0) return;
        const s = barMeta[elements[0].index];
        if (s && !s._isGap) openConversation(s.id, s);
      },
      onHover: (evt, elements) => _handleHoverCard(evt, elements, barMeta),
    },
    plugins: [{
      id: 'concurrentZones',
      beforeDraw: (chart) => {
        if (!concurrentZones.length) return;
        const { ctx } = chart;
        const xScale = chart.scales.x;
        const area = chart.chartArea;
        ctx.save();
        ctx.fillStyle = 'rgba(251,191,36,0.04)';
        for (const z of concurrentZones) {
          const x1 = xScale.getPixelForValue(z.start);
          const x2 = xScale.getPixelForValue(z.end);
          if (x2 < area.left || x1 > area.right) continue;
          ctx.fillRect(Math.max(x1, area.left), area.top, Math.min(x2, area.right) - Math.max(x1, area.left), area.bottom - area.top);
        }
        ctx.restore();
      },
    }, {
      id: 'parentChildLinks',
      afterDatasetsDraw: (chart) => _drawParentLinks(chart, barMeta),
    }],
  }));

  _renderTimelineLegend(sessions, data.truncated, projects.length, collapsedCount, concurrentZones.length);
}

// ─── Hover detail card ───────────────────────────────────────────────────
function _handleHoverCard(evt, elements, barMeta) {
  const card = document.getElementById('tlHoverCard');
  if (!card) return;
  if (!elements.length || elements[0].datasetIndex !== 0) { card.classList.add('hidden'); return; }
  const s = barMeta[elements[0].index];
  if (!s || s._isGap) { card.classList.add('hidden'); return; }

  card.textContent = '';
  const title = document.createElement('div');
  title.className = 'font-bold text-white/90 mb-1 truncate';
  title.textContent = s.project_name || '';
  const details = document.createElement('div');
  details.className = 'text-white/60 space-y-0.5';
  [
    fmtTime(s.created_at) + ' ~ ' + fmtTime(s.updated_at),
    '\uC18C\uC694: ' + fmtDurationSec(s.duration_seconds || 0),
    '\uBE44\uC6A9: ' + fmt$(s.cost_usd) + ' \u00b7 \uBAA8\uB378: ' + (s.model ? shortModel(s.model) : '\u2014'),
  ].forEach(l => { const r = document.createElement('div'); r.textContent = l; details.appendChild(r); });
  if (s.is_subagent) { const sb = document.createElement('div'); sb.textContent = 'Subagent'; sb.className = 'text-blue-300/70'; details.appendChild(sb); }
  if (s.source_node && s.source_node !== 'local') { const nd = document.createElement('div'); nd.textContent = '\uB178\uB4DC: ' + s.source_node; nd.className = 'text-cyan-300/70'; details.appendChild(nd); }
  const hint = document.createElement('div');
  hint.className = 'text-white/25 mt-1.5 text-[9px]';
  hint.textContent = '\uD074\uB9AD\uD558\uC5EC \uB300\uD654 \uC5F4\uAE30';
  card.append(title, details, hint);

  const rect = evt.chart.canvas.getBoundingClientRect();
  let left = rect.left + evt.x + 16;
  let top = rect.top + evt.y - 20;
  if (left + 288 > window.innerWidth) left = rect.left + evt.x - 300;
  if (top + 140 > window.innerHeight) top = window.innerHeight - 150;
  card.style.left = Math.max(0, left) + 'px';
  card.style.top = Math.max(0, top) + 'px';
  card.classList.remove('hidden');
}

// ─── Parent → child (subagent) link arrows ───────────────────────────────
// Draws a subtle curved line from each subagent bar's left edge back to its
// parent session's right edge. Parent must also be visible in the current
// projection (same range, same project not collapsed).
function _drawParentLinks(chart, barMeta) {
  const enabled = document.getElementById('tlShowLinks')?.checked;
  if (!enabled) return;
  const dsMeta = chart.getDatasetMeta(0);
  if (!dsMeta || !dsMeta.data) return;

  // Build lookup: session_id → datapoint index (only real sessions, not gaps)
  const idToIdx = new Map();
  for (let i = 0; i < barMeta.length; i++) {
    const m = barMeta[i];
    if (m && !m._isGap && m.id) idToIdx.set(m.id, i);
  }

  const { ctx, chartArea } = chart;
  ctx.save();
  ctx.strokeStyle = 'rgba(96,165,250,0.45)';  // sky-ish blue
  ctx.fillStyle = 'rgba(96,165,250,0.55)';
  ctx.lineWidth = 1;

  let drawn = 0;
  for (let i = 0; i < barMeta.length; i++) {
    const child = barMeta[i];
    if (!child || child._isGap || !child.is_subagent || !child.parent_session_id) continue;
    const pIdx = idToIdx.get(child.parent_session_id);
    if (pIdx === undefined) continue;

    const parentEl = dsMeta.data[pIdx];
    const childEl = dsMeta.data[i];
    if (!parentEl || !childEl) continue;

    // Parent bar right edge, child bar left edge (horizontal bars)
    const pr = parentEl.getProps(['x', 'y', 'width', 'height', 'base'], false);
    const cr = childEl.getProps(['x', 'y', 'width', 'height', 'base'], false);
    // For horizontal bars: x is the *end* (right edge), base is the *start*
    const px = pr.x;  // parent right edge
    const py = pr.y;
    const cx = cr.base; // child left edge
    const cy = cr.y;

    // Clip to chart area
    if (px < chartArea.left || cx > chartArea.right) continue;
    if (Math.abs(cx - px) < 2 && Math.abs(cy - py) < 2) continue;

    // Curved connector: horizontal offset controls curvature
    const dx = Math.max(18, Math.min(80, Math.abs(cx - px) * 0.4));
    ctx.beginPath();
    ctx.moveTo(px, py);
    ctx.bezierCurveTo(px + dx, py, cx - dx, cy, cx, cy);
    ctx.stroke();

    // Small arrowhead at child side
    const ah = 4;
    ctx.beginPath();
    ctx.moveTo(cx, cy);
    ctx.lineTo(cx - ah, cy - ah * 0.6);
    ctx.lineTo(cx - ah, cy + ah * 0.6);
    ctx.closePath();
    ctx.fill();
    drawn++;
    if (drawn > 300) break; // safety cap
  }
  ctx.restore();
}

// ─── Concurrent work detection ───────────────────────────────────────────
function _findConcurrentZones(sessions, tzOffsetMs, visibleProjects, projectMap) {
  const intervals = [];
  for (const proj of visibleProjects) {
    for (const s of (projectMap.get(proj) || [])) {
      const start = new Date(s.created_at).getTime() + tzOffsetMs;
      const end = new Date(s.updated_at).getTime() + tzOffsetMs;
      if (!isNaN(start) && !isNaN(end) && end > start) intervals.push({ start, end, project: proj });
    }
  }
  intervals.sort((a, b) => a.start - b.start);
  const zones = [];
  for (let i = 0; i < intervals.length; i++) {
    for (let j = i + 1; j < intervals.length; j++) {
      if (intervals[j].start >= intervals[i].end) break;
      if (intervals[j].project === intervals[i].project) continue;
      const os = intervals[j].start, oe = Math.min(intervals[i].end, intervals[j].end);
      const last = zones[zones.length - 1];
      if (last && os <= last.end) last.end = Math.max(last.end, oe);
      else zones.push({ start: os, end: oe });
    }
  }
  return zones;
}

// ─── Project collapse/expand ─────────────────────────────────────────────
function _toggleProjectCollapse(projectName) {
  if (_tlCollapsed.has(projectName)) _tlCollapsed.delete(projectName);
  else _tlCollapsed.add(projectName);
  savePrefs({ tlCollapsed: [..._tlCollapsed] });
  if (_tlLastData) {
    _computeOutliers(_tlLastData.data);
    _renderTimelineChart(_tlLastData.data, _tlLastData.dateFrom, _tlLastData.dateTo);
    _renderEfficiency(_tlLastData.data);
  }
}
function _expandAll() {
  _tlCollapsed.clear();
  savePrefs({ tlCollapsed: [] });
  if (_tlLastData) {
    _computeOutliers(_tlLastData.data);
    _renderTimelineChart(_tlLastData.data, _tlLastData.dateFrom, _tlLastData.dateTo);
    _renderEfficiency(_tlLastData.data);
  }
}

// ─── Empty state ─────────────────────────────────────────────────────────
function _renderEmptyTimeline() {
  destroyChart('timeline');
  const wrap = document.getElementById('timelineChartWrap');
  wrap.style.height = '200px';
  document.getElementById('timelineLegend').textContent = '';
  const canvas = document.getElementById('chartTimeline');
  canvas.getContext('2d').clearRect(0, 0, canvas.width, canvas.height);
  wrap.querySelectorAll('.tl-empty-msg').forEach(n => n.remove());
  const info = document.createElement('div');
  info.className = 'tl-empty-msg absolute inset-0 flex items-center justify-center text-white/25 text-xs';
  info.textContent = '\uC120\uD0DD\uD55C \uAE30\uAC04\uC5D0 \uC138\uC158 \uB370\uC774\uD130\uAC00 \uC5C6\uC2B5\uB2C8\uB2E4';
  wrap.appendChild(info);
}

// ─── Legend ──────────────────────────────────────────────────────────────
function _renderTimelineLegend(sessions, truncated, totalProjects, collapsedCount, concurrentCount) {
  const el = document.getElementById('timelineLegend');
  if (!el) return;
  el.textContent = '';
  const totalCost = sessions.reduce((s, x) => s + (x.cost_usd || 0), 0);
  const subs = sessions.filter(s => s.is_subagent).length;

  const span = (text, cls) => { const s = document.createElement('span'); s.className = cls || ''; s.textContent = text; return s; };
  el.appendChild(span(fmtN(sessions.length) + '\uAC1C \uC138\uC158 \u00b7 ' + fmtN(totalProjects) + '\uAC1C \uD504\uB85C\uC81D\uD2B8 \u00b7 ' + fmt$(totalCost)));
  if (subs > 0) el.appendChild(span('(subagent ' + fmtN(subs) + ')', 'text-blue-300/60'));
  if (concurrentCount > 0) el.appendChild(span('\u26A1 \uB3D9\uC2DC\uC791\uC5C5 ' + fmtN(concurrentCount) + '\uAD6C\uAC04', 'text-amber-300/60'));
  const showOutliers = document.getElementById('tlShowOutliers')?.checked;
  if (showOutliers && _tlOutlierProjs.size > 0) {
    el.appendChild(span('\u26A0 \uC774\uC0C1\uCE58 \uD504\uB85C\uC81D\uD2B8 ' + fmtN(_tlOutlierProjs.size) + '\uAC1C', 'text-rose-300/70 font-bold'));
  }
  if (truncated) el.appendChild(span('(\uBC94\uC704 \uCD08\uACFC \u2014 \uC77C\uBD80\uB9CC \uD45C\uC2DC)', 'text-amber-400/60 font-bold'));
  if (collapsedCount > 0) {
    const btn = document.createElement('button');
    btn.className = 'text-accent/70 hover:text-accent spring font-bold';
    btn.textContent = fmtN(collapsedCount) + '\uAC1C \uC811\uD798 \u2014 \uBAA8\uB450 \uD3BC\uCE58\uAE30';
    btn.addEventListener('click', _expandAll);
    el.appendChild(btn);
  }
  const mkLeg = (color, label) => {
    const w = document.createElement('span'); w.className = 'flex items-center gap-1';
    const dot = document.createElement('span'); dot.className = 'w-2.5 h-2.5 rounded-sm'; dot.style.background = color;
    const txt = document.createElement('span'); txt.textContent = label;
    w.append(dot, txt); return w;
  };
  el.append(mkLeg('rgba(167,139,250,.6)','Opus'), mkLeg('rgba(52,211,153,.6)','Sonnet'), mkLeg('rgba(34,211,238,.6)','Haiku'),
    mkLeg('rgba(96,165,250,.6)','Subagent'), mkLeg('rgba(255,255,255,.06)','\uD734\uC2DD'), mkLeg('rgba(251,191,36,.15)','\uB3D9\uC2DC\uC791\uC5C5'));
  el.appendChild(span('Ctrl+\uD718\uC77C=\uC90C \u00b7 \uB4DC\uB798\uADF8=\uBC94\uC704 \u00b7 \uD074\uB9AD=\uB300\uD654', 'text-white/20 ml-auto'));
}


// ═══════════════════════════════════════════════════════════════════════════
// 2. DAY x HOUR HEATMAP
// ═══════════════════════════════════════════════════════════════════════════

async function _loadHeatmap() {
  const wrap = document.getElementById('tlHeatmapWrap');
  if (!wrap) return;
  try {
    const d = await safeFetch('/api/timeline/heatmap?days=90');
    _renderHeatmap(d, wrap);
  } catch (e) {
    wrap.textContent = '';
    const err = document.createElement('div'); err.className = 'text-center text-red-400/60 text-xs py-4';
    err.textContent = '\uD788\uD2B8\uB9F5 \uB85C\uB4DC \uC2E4\uD328'; wrap.appendChild(err);
  }
}

function _renderHeatmap(data, wrap) {
  const cells = data.cells || {};
  let maxCount = 1;
  for (const v of Object.values(cells)) { if (v.count > maxCount) maxCount = v.count; }

  wrap.textContent = '';
  const table = document.createElement('table');
  table.className = 'w-full text-[10px] border-collapse';
  const thead = document.createElement('thead');
  const htr = document.createElement('tr');
  const corner = document.createElement('th'); corner.className = 'px-1 py-1'; htr.appendChild(corner);
  for (let hr = 0; hr < 24; hr++) {
    const th = document.createElement('th');
    th.className = 'px-0.5 py-1 text-white/25 font-normal text-center';
    th.textContent = String(hr).padStart(2, '0');
    htr.appendChild(th);
  }
  thead.appendChild(htr); table.appendChild(thead);

  const tbody = document.createElement('tbody');
  for (let dow = 0; dow < 7; dow++) {
    const tr = document.createElement('tr');
    const th = document.createElement('th'); th.className = 'px-1 py-1 text-white/40 font-bold text-right'; th.textContent = DOW_LABELS[dow]; tr.appendChild(th);
    for (let hr = 0; hr < 24; hr++) {
      const td = document.createElement('td'); td.className = 'p-0.5';
      const cell = cells[dow + '_' + hr];
      const count = cell ? cell.count : 0;
      const cost = cell ? cell.cost : 0;
      const inner = document.createElement('div');
      inner.className = 'w-full rounded-sm'; inner.style.height = '18px'; inner.style.minWidth = '14px';
      if (count > 0) {
        inner.style.background = 'rgba(52,211,153,' + (0.1 + (count / maxCount) * 0.7).toFixed(2) + ')';
        inner.title = DOW_LABELS[dow] + ' ' + hr + '\uC2DC: ' + fmtN(count) + '\uAC74, ' + fmt$(cost);
        inner.style.cursor = 'pointer';
        inner.addEventListener('click', ((d, h) => () => _heatmapDrillDown(d, h))(dow, hr));
        inner.setAttribute('tabindex', '0');
        inner.setAttribute('role', 'button');
        inner.addEventListener('keydown', ((d, h) => (e) => { if (e.key === 'Enter' || e.key === ' ') { e.preventDefault(); _heatmapDrillDown(d, h); } })(dow, hr));
      } else {
        inner.style.background = 'rgba(255,255,255,0.02)';
      }
      td.appendChild(inner); tr.appendChild(td);
    }
    tbody.appendChild(tr);
  }
  table.appendChild(tbody); wrap.appendChild(table);
}


// ═══════════════════════════════════════════════════════════════════════════
// 3. EFFICIENCY ANALYSIS
// ═══════════════════════════════════════════════════════════════════════════

function _renderEfficiency(data) {
  const el = document.getElementById('tlEfficiency');
  if (!el) return;
  const sessions = data.sessions || [];
  if (!sessions.length) {
    el.textContent = '';
    const empty = document.createElement('div'); empty.className = 'text-center text-white/15 text-xs py-6'; empty.textContent = '\uB370\uC774\uD130 \uC5C6\uC74C'; el.appendChild(empty); return;
  }
  const projectMap = new Map();
  for (const s of sessions) { const k = s.project_name || '(unknown)'; if (!projectMap.has(k)) projectMap.set(k, []); projectMap.get(k).push(s); }

  const rows = [...projectMap.entries()].map(([name, list]) => {
    const totalCost = list.reduce((s, x) => s + (x.cost_usd || 0), 0);
    const totalDur = list.reduce((s, x) => s + (x.duration_seconds || 0), 0);
    const durHr = totalDur / 3600;
    const perHr = durHr > 0 ? totalCost / durHr : 0;
    const earliest = Math.min(...list.map(s => new Date(s.created_at).getTime()));
    const latest = Math.max(...list.map(s => new Date(s.updated_at).getTime()));
    const spanSec = (latest - earliest) / 1000;
    const activeRatio = spanSec > 0 ? Math.min(1, totalDur / spanSec) : 0;
    return { name, totalCost, totalDur, perHr, sessionCount: list.length, activeRatio };
  }).sort((a, b) => b.totalCost - a.totalCost);

  el.textContent = '';
  const table = document.createElement('table'); table.className = 'w-full text-[11px]';

  // Build thead with DOM API (no innerHTML)
  const thead = document.createElement('thead');
  const headTr = document.createElement('tr');
  headTr.className = 'text-[9px] text-white/30 uppercase tracking-widest border-b border-white/[0.05]';
  ['\uD504\uB85C\uC81D\uD2B8', '\uC138\uC158', '\uBE44\uC6A9', '$/hr', '\uD65C\uC131\uBE44', ''].forEach((label, i) => {
    const th = document.createElement('th');
    th.className = (i === 0 ? 'text-left' : i < 5 ? 'text-right' : 'text-center') + ' px-2 py-1.5 font-bold' + (i === 5 ? ' w-8' : '');
    th.textContent = label;
    headTr.appendChild(th);
  });
  thead.appendChild(headTr); table.appendChild(thead);

  const tbody = document.createElement('tbody');
  for (const r of rows.slice(0, 15)) {
    const tr = document.createElement('tr'); tr.className = 'border-b border-white/[0.03] hover:bg-white/[0.03] spring';
    const mkTd = (text, cls) => { const td = document.createElement('td'); td.className = cls; td.textContent = text; return td; };
    const nameCell = document.createElement('td');
    nameCell.className = 'px-2 py-1.5 font-semibold text-white/70 truncate max-w-[180px]';
    nameCell.title = r.name;
    nameCell.appendChild(_projDot(r.name));
    const isOutlier = _tlOutlierProjs.has(r.name) && document.getElementById('tlShowOutliers')?.checked;
    if (isOutlier) {
      const badge = document.createElement('span');
      badge.className = 'inline-block mr-1 px-1 rounded text-[9px] font-bold bg-rose-400/15 text-rose-300 align-middle';
      badge.textContent = '\u26A0';
      badge.title = '$/hr 평균 + 2σ 초과';
      nameCell.appendChild(badge);
    }
    const nameText = document.createElement('span'); nameText.textContent = r.name;
    nameCell.appendChild(nameText);
    tr.appendChild(nameCell);
    tr.appendChild(mkTd(fmtN(r.sessionCount), 'px-2 py-1.5 text-right text-white/50 tabular-nums'));
    tr.appendChild(mkTd(fmt$(r.totalCost), 'px-2 py-1.5 text-right text-amber-400/80 font-bold tabular-nums'));
    const perHrCls = 'px-2 py-1.5 text-right tabular-nums ' + (r.perHr > 50 ? 'text-red-400/80 font-bold' : r.perHr > 20 ? 'text-amber-400/70' : 'text-emerald-400/70');
    tr.appendChild(mkTd(r.totalDur > 0 ? fmt$(r.perHr) : '\u2014', perHrCls));

    // Active ratio bar
    const ratioTd = document.createElement('td'); ratioTd.className = 'px-2 py-1.5 text-right';
    const pct = Math.round(r.activeRatio * 100);
    const barWrap = document.createElement('div'); barWrap.className = 'flex items-center gap-1 justify-end';
    const barBg = document.createElement('div'); barBg.className = 'w-12 h-1.5 bg-white/5 rounded-full overflow-hidden';
    const barFill = document.createElement('div'); barFill.className = 'h-full rounded-full';
    barFill.style.width = pct + '%';
    barFill.style.background = pct > 60 ? '#34d399' : pct > 30 ? '#fbbf24' : '#fb7185';
    barBg.appendChild(barFill);
    const pctLabel = document.createElement('span'); pctLabel.className = 'text-[9px] text-white/40 tabular-nums w-7 text-right'; pctLabel.textContent = pct + '%';
    barWrap.append(barBg, pctLabel); ratioTd.appendChild(barWrap); tr.appendChild(ratioTd);

    const colTd = document.createElement('td'); colTd.className = 'px-1 py-1.5 text-center';
    const colBtn = document.createElement('button'); colBtn.className = 'text-white/20 hover:text-white/50 spring text-[10px]';
    colBtn.textContent = _tlCollapsed.has(r.name) ? '\u25B6' : '\u25BC';
    colBtn.title = _tlCollapsed.has(r.name) ? '\uD3BC\uCE58\uAE30' : '\uC811\uAE30';
    colBtn.addEventListener('click', () => _toggleProjectCollapse(r.name));
    colTd.appendChild(colBtn); tr.appendChild(colTd);
    tbody.appendChild(tr);
  }
  table.appendChild(tbody); el.appendChild(table);
}


// ═══════════════════════════════════════════════════════════════════════════
// 4. DAILY REPORT  +  (A) HOURLY ACCORDION
// ═══════════════════════════════════════════════════════════════════════════

// Shared project colour palette for stacked chart & accordion
const _PROJ_PALETTE = [
  'rgba(52,211,153,A)',  'rgba(167,139,250,A)', 'rgba(34,211,238,A)',
  'rgba(251,191,36,A)',  'rgba(244,114,182,A)', 'rgba(96,165,250,A)',
  'rgba(248,113,113,A)', 'rgba(163,230,53,A)',  'rgba(232,121,249,A)',
  'rgba(45,212,191,A)',  'rgba(253,186,116,A)', 'rgba(129,140,248,A)',
];
function _projColor(idx, alpha) { return (_PROJ_PALETTE[idx % _PROJ_PALETTE.length]).replace('A', String(alpha ?? 0.6)); }
// Deterministic project → palette color. Same name always maps to same slot
// regardless of current sort order, so users learn the color=project association
// once and it stays stable across views (Gantt y-axis, efficiency, delta, hourly).
function _projColorByName(name, alpha) {
  let h = 0;
  const s = name || '';
  for (let i = 0; i < s.length; i++) h = (h * 131 + s.charCodeAt(i)) >>> 0;
  return _PROJ_PALETTE[h % _PROJ_PALETTE.length].replace('A', String(alpha ?? 0.85));
}
// Small colored dot element for table labels.
function _projDot(name, size) {
  const d = document.createElement('span');
  d.className = 'inline-block rounded-sm align-middle mr-1.5 flex-shrink-0';
  const px = size || 8;
  d.style.width = px + 'px';
  d.style.height = px + 'px';
  d.style.background = _projColorByName(name, 0.9);
  return d;
}
let _hourlyCache = {};
const _HOURLY_CACHE_MAX = 10;

async function _fetchHourly(dateStr) {
  if (_hourlyCache[dateStr]) return _hourlyCache[dateStr];
  const d = await safeFetch('/api/timeline/hourly?date=' + encodeURIComponent(dateStr));
  // LRU eviction: drop oldest entries when cache exceeds max
  const keys = Object.keys(_hourlyCache);
  while (keys.length >= _HOURLY_CACHE_MAX) {
    delete _hourlyCache[keys.shift()];
  }
  _hourlyCache[dateStr] = d;
  return d;
}

async function _loadDailyReport(dateStr) {
  const el = document.getElementById('tlDailyReport');
  if (!el || !dateStr) return;
  el.textContent = '';
  const loading = document.createElement('div'); loading.className = 'text-center text-white/15 text-xs py-4 dots'; loading.textContent = '\uB85C\uB529 \uC911'; el.appendChild(loading);
  try {
    const [d, hourlyData] = await Promise.all([
      safeFetch('/api/timeline?date_from=' + dateStr + '&date_to=' + dateStr),
      _fetchHourly(dateStr),
    ]);
    const sessions = d.sessions || [];
    el.textContent = '';
    if (!sessions.length) {
      const empty = document.createElement('div'); empty.className = 'text-center text-white/20 text-xs py-6'; empty.textContent = '\uD574\uB2F9 \uB0A0\uC9DC\uC5D0 \uC138\uC158\uC774 \uC5C6\uC2B5\uB2C8\uB2E4'; el.appendChild(empty); return;
    }
    const totalCost = sessions.reduce((s, x) => s + (x.cost_usd || 0), 0);
    const totalDur = sessions.reduce((s, x) => s + (x.duration_seconds || 0), 0);
    const projects = new Set(sessions.map(s => s.project_name));
    const grid = document.createElement('div'); grid.className = 'grid grid-cols-4 gap-2 mb-3';
    const mkCard = (label, value, cls) => {
      const c = document.createElement('div'); c.className = 'bg-white/[0.03] rounded-lg p-2 text-center';
      const v = document.createElement('div'); v.className = 'text-sm font-bold ' + (cls || 'text-white/80'); v.textContent = value;
      const l = document.createElement('div'); l.className = 'text-[9px] text-white/30 mt-0.5'; l.textContent = label;
      c.append(v, l); return c;
    };
    grid.append(mkCard('\uC138\uC158', fmtN(sessions.length)), mkCard('\uD504\uB85C\uC81D\uD2B8', fmtN(projects.size), 'text-cyan-400/80'),
      mkCard('\uBE44\uC6A9', fmt$(totalCost), 'text-amber-400/80'), mkCard('\uC18C\uC694\uC2DC\uAC04', fmtDurationSec(totalDur), 'text-emerald-400/80'));
    el.appendChild(grid);

    const projMap = new Map();
    for (const s of sessions) { const k = s.project_name || '(unknown)'; if (!projMap.has(k)) projMap.set(k, []); projMap.get(k).push(s); }
    const list = [...projMap.entries()].sort((a, b) => b[1].reduce((s, x) => s + (x.cost_usd||0), 0) - a[1].reduce((s, x) => s + (x.cost_usd||0), 0));
    for (const [name, ss] of list) {
      const cost = ss.reduce((s, x) => s + (x.cost_usd || 0), 0);
      const dur = ss.reduce((s, x) => s + (x.duration_seconds || 0), 0);
      const row = document.createElement('div'); row.className = 'flex items-center justify-between py-1.5 border-b border-white/[0.03] text-[11px]';
      const left = document.createElement('span'); left.className = 'text-white/65 font-semibold truncate flex items-center';
      left.appendChild(_projDot(name));
      const leftTxt = document.createElement('span'); leftTxt.textContent = name; left.appendChild(leftTxt);
      const right = document.createElement('span'); right.className = 'text-white/40 tabular-nums flex gap-3';
      const s1 = document.createElement('span'); s1.textContent = fmtN(ss.length) + '\uAC74';
      const s2 = document.createElement('span'); s2.className = 'text-amber-400/70'; s2.textContent = fmt$(cost);
      const s3 = document.createElement('span'); s3.textContent = fmtDurationSec(dur);
      right.append(s1, s2, s3);
      row.append(left, right); el.appendChild(row);
    }
    // ── (A) Hourly accordion ──
    _renderHourlyAccordion(el, hourlyData);
  } catch (e) {
    el.textContent = '';
    const err = document.createElement('div'); err.className = 'text-center text-red-400/60 text-xs py-4'; err.textContent = '\uB9AC\uD3EC\uD2B8 \uB85C\uB4DC \uC2E4\uD328'; el.appendChild(err);
  }
}

function _renderHourlyAccordion(container, hourlyData) {
  const hours = (hourlyData.hours || []).filter(h => h.message_count > 0);
  if (!hours.length) return;

  const section = document.createElement('div');
  section.className = 'mt-4 border-t border-white/[0.05] pt-3';
  const title = document.createElement('div');
  title.className = 'text-[10px] font-bold text-white/30 uppercase tracking-widest mb-2';
  title.textContent = '\uC2DC\uAC04\uBCC4 \uC0C1\uC138 (' + hours.length + '\uAC1C \uC2DC\uAC04\uB300)';
  section.appendChild(title);

  for (const slot of hours) {
    const wrap = document.createElement('div');
    wrap.className = 'border-b border-white/[0.03]';
    const header = document.createElement('button');
    header.className = 'w-full flex items-center justify-between py-2 px-1 text-[11px] hover:bg-white/[0.02] spring group';
    const left = document.createElement('div');
    left.className = 'flex items-center gap-2';
    const arrow = document.createElement('span');
    arrow.className = 'text-white/20 text-[9px] spring group-hover:text-white/40';
    arrow.textContent = '\u25B6';
    const hourLabel = document.createElement('span');
    hourLabel.className = 'font-bold text-white/60 tabular-nums';
    hourLabel.textContent = slot.hour + ':00';
    const projCount = document.createElement('span');
    projCount.className = 'text-white/25 text-[9px]';
    const pNames = Object.keys(slot.projects);
    projCount.textContent = pNames.length + '\uAC1C \uD504\uB85C\uC81D\uD2B8';
    left.append(arrow, hourLabel, projCount);
    const right = document.createElement('div');
    right.className = 'flex items-center gap-3 text-white/40 tabular-nums';
    const msgSpan = document.createElement('span'); msgSpan.textContent = fmtN(slot.message_count) + '\uAC74';
    const costSpan = document.createElement('span'); costSpan.className = 'text-amber-400/70 font-bold'; costSpan.textContent = fmt$(slot.cost_usd);
    right.append(msgSpan, costSpan);
    header.append(left, right);

    const detail = document.createElement('div');
    detail.className = 'hidden pb-2 px-1';
    header.addEventListener('click', () => {
      const open = !detail.classList.contains('hidden');
      detail.classList.toggle('hidden');
      arrow.textContent = open ? '\u25B6' : '\u25BC';
    });

    for (const [pName, pData] of Object.entries(slot.projects)) {
      const pRow = document.createElement('div');
      pRow.className = 'flex items-center justify-between py-1 pl-5 text-[10px]';
      const pLeft = document.createElement('span');
      pLeft.className = 'text-white/50 truncate max-w-[150px] inline-flex items-center';
      pLeft.appendChild(_projDot(pName, 6));
      const pLeftTxt = document.createElement('span'); pLeftTxt.textContent = pName; pLeft.appendChild(pLeftTxt);
      pLeft.title = pName;
      const pRight = document.createElement('div');
      pRight.className = 'flex items-center gap-3 text-white/35 tabular-nums';
      const pm = document.createElement('span'); pm.textContent = fmtN(pData.session_count) + '\uC138\uC158';
      const pc = document.createElement('span'); pc.className = 'text-amber-400/60'; pc.textContent = fmt$(pData.cost_usd);
      const pt = document.createElement('span'); pt.className = 'text-white/25';
      pt.textContent = fmtN((pData.input_tokens || 0) + (pData.output_tokens || 0)) + ' tok';
      pRight.append(pm, pc, pt); pRow.append(pLeft, pRight); detail.appendChild(pRow);
    }

    if (slot.sessions.length) {
      const sesTitle = document.createElement('div');
      sesTitle.className = 'text-[9px] text-white/20 uppercase tracking-wider mt-1.5 mb-1 pl-5';
      sesTitle.textContent = '\uD65C\uC131 \uC138\uC158';
      detail.appendChild(sesTitle);
      for (const ses of slot.sessions.slice(0, 10)) {
        const sRow = document.createElement('div');
        sRow.className = 'flex items-center justify-between py-0.5 pl-5 text-[10px] hover:bg-white/[0.02] spring cursor-pointer rounded';
        sRow.addEventListener('click', () => openConversation(ses.session_id));
        const sLeft = document.createElement('div');
        sLeft.className = 'flex items-center gap-1.5 text-white/40 truncate';
        const sProj = document.createElement('span'); sProj.className = 'truncate max-w-[100px]'; sProj.textContent = ses.project_name;
        const sModel = document.createElement('span'); sModel.className = 'text-white/20 text-[9px]'; sModel.textContent = ses.model ? shortModel(ses.model) : '';
        sLeft.append(sProj, sModel);
        if (ses.is_subagent) { const sb = document.createElement('span'); sb.className = 'text-blue-300/50 text-[8px]'; sb.textContent = 'sub'; sLeft.appendChild(sb); }
        const sRight = document.createElement('span');
        sRight.className = 'text-amber-400/50 tabular-nums'; sRight.textContent = fmt$(ses.cost_usd);
        sRow.append(sLeft, sRight); detail.appendChild(sRow);
      }
      if (slot.sessions.length > 10) {
        const more = document.createElement('div');
        more.className = 'text-[9px] text-white/15 pl-5 mt-0.5';
        more.textContent = '+' + (slot.sessions.length - 10) + '\uAC1C \uC138\uC158 \uB354';
        detail.appendChild(more);
      }
    }
    wrap.append(header, detail); section.appendChild(wrap);
  }
  container.appendChild(section);
}


// ═════════════════════════��══════════════════════════════════���══════════════
// 5. TREND COMPARISON (this week vs last week)
// ═══════════════════════════════════════════════════════════════════════════

async function _loadTrend() {
  try {
    const now = new Date();
    const [thisW, lastW] = await Promise.all([
      safeFetch('/api/timeline?date_from=' + _daysAgo(now, 6) + '&date_to=' + now.toISOString().slice(0, 10)),
      safeFetch('/api/timeline?date_from=' + _daysAgo(now, 13) + '&date_to=' + _daysAgo(now, 7)),
    ]);
    _renderTrendChart(thisW, lastW);
  } catch (e) { console.error('trend:', e); }
}

function _renderTrendChart(thisWeekData, lastWeekData) {
  const aggregate = (data) => {
    const daily = new Array(7).fill(0);
    for (const s of (data.sessions || [])) { daily[new Date(s.created_at).getDay()] += (s.cost_usd || 0); }
    return [...daily.slice(1), daily[0]];
  };
  const thisData = aggregate(thisWeekData), lastData = aggregate(lastWeekData);
  const labels = ['\uC6D4', '\uD654', '\uC218', '\uBAA9', '\uAE08', '\uD1A0', '\uC77C'];

  destroyChart('trend');
  const canvas = document.getElementById('chartTrend');
  if (!canvas) return;
  const tc = themeColors();

  setChart('trend', new Chart(canvas, {
    type: 'bar',
    data: { labels, datasets: [
      { label: '\uC774\uBC88 \uC8FC', data: thisData, backgroundColor: 'rgba(52,211,153,0.35)', borderColor: CC.emerald, borderWidth: 1, borderRadius: 3 },
      { label: '\uC800\uBC88 \uC8FC', data: lastData, backgroundColor: 'rgba(255,255,255,0.06)', borderColor: 'rgba(255,255,255,0.15)', borderWidth: 1, borderRadius: 3 },
    ]},
    options: {
      ...CHART_D,
      plugins: {
        legend: { display: true, position: 'top', align: 'end', labels: { color: tc.legendColor, boxWidth: 10, font: { size: 11, family: 'Pretendard' } } },
        tooltip: tooltipOpts({ callbacks: { label: c => ' ' + c.dataset.label + ': ' + fmt$(c.raw) } }),
      },
      scales: { x: { grid: grd(), ticks: tck() }, y: { grid: grd(), ticks: { ...tck(), callback: v => '$' + v.toFixed(2) } } },
    },
  }));
}


// ═══════════════════════════════════════════════════════════════════════════
// 5b. DELTA VIEW (yesterday → today per-project)
// ═══════════════════════════════════════════════════════════════════════════

function _aggByProject(sessions) {
  const m = new Map();
  for (const s of sessions || []) {
    const k = s.project_name || '(unknown)';
    const prev = m.get(k) || { cost: 0, sessions: 0, duration: 0 };
    prev.cost += s.cost_usd || 0;
    prev.sessions += 1;
    prev.duration += s.duration_seconds || 0;
    m.set(k, prev);
  }
  return m;
}

function _deltaBaseDate() {
  const input = document.getElementById('tlDeltaDate');
  if (input && input.value) return input.value;
  return new Date().toISOString().slice(0, 10);
}

async function _loadDelta() {
  const body = document.getElementById('tlDeltaBody');
  const summary = document.getElementById('tlDeltaSummary');
  const rangeLabel = document.getElementById('tlDeltaRange');
  if (!body || !summary) return;

  const today = _deltaBaseDate();
  const ymd = new Date(today + 'T00:00:00Z');
  ymd.setUTCDate(ymd.getUTCDate() - 1);
  const yesterday = ymd.toISOString().slice(0, 10);
  if (rangeLabel) rangeLabel.textContent = yesterday + '  →  ' + today;

  body.textContent = '';
  summary.textContent = '';
  const loading = document.createElement('div');
  loading.className = 'text-center text-white/15 text-xs py-6 dots';
  loading.textContent = '\uB85C\uB529 \uC911';
  body.appendChild(loading);

  try {
    const [todayD, yestD] = await Promise.all([
      safeFetch('/api/timeline?date_from=' + today + '&date_to=' + today),
      safeFetch('/api/timeline?date_from=' + yesterday + '&date_to=' + yesterday),
    ]);
    _renderDelta(todayD.sessions || [], yestD.sessions || [], summary, body);
  } catch (e) {
    body.textContent = '';
    const err = document.createElement('div');
    err.className = 'text-center text-red-400/60 text-xs py-4';
    err.textContent = '\uB378\uD0C0 \uB85C\uB4DC \uC2E4\uD328';
    body.appendChild(err);
  }
}

function _renderDelta(todaySessions, yestSessions, summaryEl, bodyEl) {
  const todayAgg = _aggByProject(todaySessions);
  const yestAgg = _aggByProject(yestSessions);
  const totalToday = { cost: 0, sessions: todaySessions.length, duration: 0 };
  for (const v of todayAgg.values()) { totalToday.cost += v.cost; totalToday.duration += v.duration; }
  const totalYest = { cost: 0, sessions: yestSessions.length, duration: 0 };
  for (const v of yestAgg.values()) { totalYest.cost += v.cost; totalYest.duration += v.duration; }

  summaryEl.textContent = '';
  const mkSummary = (label, todayVal, yestVal, formatter, colorPositive) => {
    const card = document.createElement('div');
    card.className = 'bg-white/[0.03] rounded-lg p-2.5';
    const lbl = document.createElement('div');
    lbl.className = 'text-[9px] text-white/30 uppercase tracking-widest mb-1';
    lbl.textContent = label;
    const valRow = document.createElement('div');
    valRow.className = 'flex items-baseline gap-1.5';
    const val = document.createElement('div');
    val.className = 'text-sm font-bold text-white/85 tabular-nums';
    val.textContent = formatter(todayVal);
    valRow.appendChild(val);

    const delta = todayVal - yestVal;
    const pct = yestVal > 0 ? (delta / yestVal) * 100 : (todayVal > 0 ? 100 : 0);
    const sign = delta > 0 ? '+' : '';
    const deltaEl = document.createElement('span');
    const goodDirection = colorPositive ? delta > 0 : delta < 0;
    deltaEl.className = 'text-[10px] tabular-nums ' + (delta === 0 ? 'text-white/30' : goodDirection ? 'text-emerald-300/80' : 'text-rose-300/80');
    if (delta === 0) deltaEl.textContent = '=';
    else deltaEl.textContent = sign + formatter(delta) + ' (' + sign + pct.toFixed(0) + '%)';
    valRow.appendChild(deltaEl);

    const yestRow = document.createElement('div');
    yestRow.className = 'text-[9px] text-white/25 mt-0.5';
    yestRow.textContent = '\uC5B4\uC81C ' + formatter(yestVal);

    card.append(lbl, valRow, yestRow);
    return card;
  };

  summaryEl.append(
    mkSummary('\uBE44\uC6A9', totalToday.cost, totalYest.cost, fmt$, true),
    mkSummary('\uC138\uC158', totalToday.sessions, totalYest.sessions, fmtN, true),
    mkSummary('\uC18C\uC694', totalToday.duration, totalYest.duration, fmtDurationSec, true),
    mkSummary('\uD504\uB85C\uC81D\uD2B8', todayAgg.size, yestAgg.size, fmtN, true),
  );

  bodyEl.textContent = '';
  if (todayAgg.size === 0 && yestAgg.size === 0) {
    const empty = document.createElement('div');
    empty.className = 'text-center text-white/20 text-xs py-6';
    empty.textContent = '\uB450 \uB0A0\uC9DC \uBAA8\uB450 \uB370\uC774\uD130 \uC5C6\uC74C';
    bodyEl.appendChild(empty);
    return;
  }

  // Union of projects
  const allProj = new Set([...todayAgg.keys(), ...yestAgg.keys()]);
  const rows = [...allProj].map(name => {
    const t = todayAgg.get(name) || { cost: 0, sessions: 0, duration: 0 };
    const y = yestAgg.get(name) || { cost: 0, sessions: 0, duration: 0 };
    return {
      name,
      todayCost: t.cost, yestCost: y.cost,
      todaySes: t.sessions, yestSes: y.sessions,
      deltaCost: t.cost - y.cost,
      isNew: t.cost > 0 && y.cost === 0 && y.sessions === 0,
      isEnded: t.cost === 0 && t.sessions === 0 && y.cost > 0,
    };
  });

  // Sort: new first, then by absolute |deltaCost| desc
  rows.sort((a, b) => {
    if (a.isNew !== b.isNew) return a.isNew ? -1 : 1;
    return Math.abs(b.deltaCost) - Math.abs(a.deltaCost);
  });

  const newCount = rows.filter(r => r.isNew).length;
  const endedCount = rows.filter(r => r.isEnded).length;

  // Header strip for new/ended counts
  if (newCount + endedCount > 0) {
    const strip = document.createElement('div');
    strip.className = 'flex items-center gap-3 text-[10px] mb-2';
    if (newCount > 0) {
      const s = document.createElement('span'); s.className = 'text-emerald-300/80 font-bold';
      s.textContent = '\uC2E0\uADDC ' + fmtN(newCount) + '\uAC1C';
      strip.appendChild(s);
    }
    if (endedCount > 0) {
      const s = document.createElement('span'); s.className = 'text-white/30';
      s.textContent = '\uC911\uB2E8 ' + fmtN(endedCount) + '\uAC1C';
      strip.appendChild(s);
    }
    bodyEl.appendChild(strip);
  }

  // Find max absolute delta for bar scaling
  const maxAbs = Math.max(1e-6, ...rows.map(r => Math.abs(r.deltaCost)));

  const table = document.createElement('table');
  table.className = 'w-full text-[11px]';
  const thead = document.createElement('thead');
  const htr = document.createElement('tr');
  htr.className = 'text-[9px] text-white/30 uppercase tracking-widest border-b border-white/[0.05]';
  ['\uD504\uB85C\uC81D\uD2B8', '\uC5B4\uC81C', '\uC624\uB298', '\uBCC0\uD654', ''].forEach((t, i) => {
    const th = document.createElement('th');
    th.className = (i === 0 ? 'text-left' : 'text-right') + ' px-2 py-1.5 font-bold';
    th.textContent = t;
    htr.appendChild(th);
  });
  thead.appendChild(htr); table.appendChild(thead);

  const tbody = document.createElement('tbody');
  for (const r of rows.slice(0, 20)) {
    const tr = document.createElement('tr');
    tr.className = 'border-b border-white/[0.03] hover:bg-white/[0.03] spring';

    const nameTd = document.createElement('td');
    nameTd.className = 'px-2 py-1.5 truncate max-w-[220px]';
    nameTd.title = r.name;
    nameTd.appendChild(_projDot(r.name));
    if (r.isNew) {
      const b = document.createElement('span');
      b.className = 'inline-block mr-1 px-1 rounded text-[8px] font-bold bg-emerald-400/15 text-emerald-300 align-middle';
      b.textContent = 'NEW';
      nameTd.appendChild(b);
    } else if (r.isEnded) {
      const b = document.createElement('span');
      b.className = 'inline-block mr-1 px-1 rounded text-[8px] font-bold bg-white/5 text-white/40 align-middle';
      b.textContent = 'END';
      nameTd.appendChild(b);
    }
    const nameSpan = document.createElement('span');
    nameSpan.className = r.isEnded ? 'text-white/40' : 'text-white/75 font-semibold';
    nameSpan.textContent = r.name;
    nameTd.appendChild(nameSpan);
    tr.appendChild(nameTd);

    const mkNumTd = (text, cls) => {
      const td = document.createElement('td');
      td.className = 'px-2 py-1.5 text-right tabular-nums ' + cls;
      td.textContent = text;
      return td;
    };
    tr.appendChild(mkNumTd(r.yestCost > 0 ? fmt$(r.yestCost) : '\u2014',
      'text-white/40'));
    tr.appendChild(mkNumTd(r.todayCost > 0 ? fmt$(r.todayCost) : '\u2014',
      'text-amber-400/80 font-bold'));

    // Delta bar (signed, centered)
    const dTd = document.createElement('td');
    dTd.className = 'px-2 py-1.5';
    const dWrap = document.createElement('div');
    dWrap.className = 'flex items-center gap-2 justify-end';
    const dText = document.createElement('span');
    const delta = r.deltaCost;
    const sign = delta > 0 ? '+' : '';
    dText.className = 'tabular-nums text-[10px] ' + (Math.abs(delta) < 0.005 ? 'text-white/30' : delta > 0 ? 'text-emerald-300/85' : 'text-rose-300/85');
    dText.textContent = Math.abs(delta) < 0.005 ? '=' : (sign + fmt$(delta));
    const barWrap = document.createElement('div');
    barWrap.className = 'relative w-20 h-2 bg-white/[0.04] rounded-full overflow-hidden';
    const bar = document.createElement('div');
    const mag = Math.min(1, Math.abs(delta) / maxAbs);
    bar.style.position = 'absolute';
    bar.style.top = '0'; bar.style.bottom = '0';
    bar.style.width = (mag * 50).toFixed(1) + '%';
    if (delta >= 0) { bar.style.left = '50%'; bar.style.background = 'rgba(52,211,153,0.55)'; }
    else { bar.style.right = '50%'; bar.style.background = 'rgba(251,113,133,0.55)'; }
    // midline
    const mid = document.createElement('div');
    mid.style.position = 'absolute'; mid.style.left = '50%'; mid.style.top = '0'; mid.style.bottom = '0';
    mid.style.width = '1px'; mid.style.background = 'rgba(255,255,255,0.1)';
    barWrap.append(bar, mid);
    dWrap.append(dText, barWrap);
    dTd.appendChild(dWrap);
    tr.appendChild(dTd);

    const spark = document.createElement('td');
    spark.className = 'px-2 py-1.5 text-right text-[9px] text-white/25 tabular-nums';
    const sesDelta = r.todaySes - r.yestSes;
    spark.textContent = r.yestSes + '\u2192' + r.todaySes + '\uC138\uC158';
    if (sesDelta !== 0) {
      const ssign = sesDelta > 0 ? '+' : '';
      spark.textContent += ' (' + ssign + sesDelta + ')';
    }
    tr.appendChild(spark);
    tbody.appendChild(tr);
  }
  table.appendChild(tbody);
  bodyEl.appendChild(table);

  if (rows.length > 20) {
    const more = document.createElement('div');
    more.className = 'text-[9px] text-white/20 text-center mt-2';
    more.textContent = '+' + (rows.length - 20) + '\uAC1C \uB354';
    bodyEl.appendChild(more);
  }
}


// ═══════════════════════════════════════════════════════════════════════════
// 6. (B) HOURLY STACKED BAR CHART
// ═══════════════════════════════════════════════════════════════════════════

let _hourlyStackedChart = null;

function cleanupTimelineCharts() {
  if (_hourlyStackedChart) { _hourlyStackedChart.destroy(); _hourlyStackedChart = null; }
}

async function _loadHourlyStacked(dateStr) {
  const canvas = document.getElementById('chartHourlyStacked');
  if (!canvas) return;
  if (!dateStr) {
    dateStr = new Date().toISOString().slice(0, 10);
    const dateInput = document.getElementById('tlHourlyDate');
    if (dateInput && !dateInput.value) dateInput.value = dateStr;
  }
  try {
    const data = await _fetchHourly(dateStr);
    _renderHourlyStacked(data);
  } catch (e) { console.error('hourlyStacked:', e); }
}

function _renderHourlyStacked(data) {
  const hours = data.hours || [];
  const metric = document.getElementById('tlHourlyMetric')?.value || 'cost';

  // Collect all project names across all hours, sorted by total cost desc
  const projTotals = new Map();
  for (const h of hours) {
    for (const [name, d] of Object.entries(h.projects)) {
      projTotals.set(name, (projTotals.get(name) || 0) + (d.cost_usd || 0));
    }
  }
  const projects = [...projTotals.entries()].sort((a, b) => b[1] - a[1]).map(e => e[0]);
  if (!projects.length) {
    if (_hourlyStackedChart) { _hourlyStackedChart.destroy(); _hourlyStackedChart = null; }
    return;
  }

  const labels = hours.map(h => h.hour + ':00');
  const datasets = projects.map((proj) => ({
    label: proj,
    data: hours.map(h => {
      const p = h.projects[proj];
      if (!p) return 0;
      if (metric === 'messages') return p.message_count || 0;
      if (metric === 'tokens') return (p.input_tokens || 0) + (p.output_tokens || 0);
      return p.cost_usd || 0;
    }),
    backgroundColor: _projColorByName(proj, 0.55),
    borderColor: _projColorByName(proj, 0.85),
    borderWidth: 1,
    borderRadius: 2,
  }));

  if (_hourlyStackedChart) { _hourlyStackedChart.destroy(); _hourlyStackedChart = null; }
  const canvas = document.getElementById('chartHourlyStacked');
  if (!canvas) return;
  const tc = themeColors();

  const yCallback = metric === 'cost' ? (v => '$' + v.toFixed(2))
    : metric === 'tokens' ? (v => v >= 1000 ? (v / 1000).toFixed(0) + 'k' : v)
    : (v => v);
  const tooltipLabel = (ctx) => {
    const v = ctx.raw;
    if (metric === 'cost') return ' ' + ctx.dataset.label + ': ' + fmt$(v);
    if (metric === 'tokens') return ' ' + ctx.dataset.label + ': ' + fmtN(v) + ' tok';
    return ' ' + ctx.dataset.label + ': ' + fmtN(v) + '\uAC74';
  };

  _hourlyStackedChart = new Chart(canvas, {
    type: 'bar',
    data: { labels, datasets },
    options: {
      responsive: true, maintainAspectRatio: false,
      animation: { duration: _prefersReducedMotion ? 0 : 350 },
      plugins: {
        legend: { display: false },
        tooltip: tooltipOpts({ callbacks: { label: tooltipLabel } }),
      },
      scales: {
        x: {
          stacked: true,
          grid: { color: tc.gridColor, drawBorder: false },
          ticks: { color: tc.tickColor, font: { size: 10, family: 'Pretendard' }, maxRotation: 0 },
        },
        y: {
          stacked: true,
          grid: { color: tc.gridColor, drawBorder: false },
          ticks: { color: tc.tickColor, font: { size: 10, family: 'Pretendard' }, callback: yCallback },
        },
      },
    },
  });

  // Legend
  const legendEl = document.getElementById('tlHourlyLegend');
  if (legendEl) {
    legendEl.textContent = '';
    for (let i = 0; i < Math.min(projects.length, 8); i++) {
      const w = document.createElement('span'); w.className = 'inline-flex items-center gap-1 mr-3';
      const dot = document.createElement('span'); dot.className = 'w-2 h-2 rounded-sm inline-block'; dot.style.background = _projColorByName(projects[i], 0.75);
      const txt = document.createElement('span'); txt.textContent = projects[i];
      w.append(dot, txt); legendEl.appendChild(w);
    }
    if (projects.length > 8) {
      const more = document.createElement('span'); more.className = 'text-white/15';
      more.textContent = '+' + (projects.length - 8) + '\uAC1C \uD504\uB85C\uC81D\uD2B8';
      legendEl.appendChild(more);
    }
  }
}


// ═══════════════════════════════════════════════════════════════════════════
// 7. (C) HEATMAP DRILL-DOWN
// ═══════════════════════════════════════════════════════════════════════════

function _heatmapDrillDown(dow, hour) {
  const drillEl = document.getElementById('tlHeatmapDrill');
  if (!drillEl) return;
  drillEl.classList.remove('hidden');
  drillEl.textContent = '';

  const loading = document.createElement('div');
  loading.className = 'text-center text-white/15 text-xs py-3 dots';
  loading.textContent = '\uB85C\uB529 \uC911';
  drillEl.appendChild(loading);

  // Find the most recent date matching this dow within 90 days, then load its hourly data
  const now = new Date();
  const candidates = [];
  for (let i = 0; i < 90; i++) {
    const d = new Date(now);
    d.setDate(d.getDate() - i);
    if (d.getDay() === dow) candidates.push(d.toISOString().slice(0, 10));
  }

  // Load aggregated data for the last 4 matching days
  const datesToLoad = candidates.slice(0, 4);
  Promise.all(datesToLoad.map(date => _fetchHourly(date).catch(() => null)))
    .then(results => {
      drillEl.textContent = '';
      const valid = results.filter(Boolean);
      if (!valid.length) {
        const empty = document.createElement('div');
        empty.className = 'text-center text-white/20 text-xs py-3';
        empty.textContent = '\uB370\uC774\uD130 \uC5C6\uC74C';
        drillEl.appendChild(empty);
        return;
      }

      // Header with close button
      const headerRow = document.createElement('div');
      headerRow.className = 'flex items-center justify-between mb-2';
      const titleText = document.createElement('span');
      titleText.className = 'text-[10px] font-bold text-white/40 uppercase tracking-widest';
      titleText.textContent = DOW_LABELS[dow] + ' ' + hour + '\uC2DC \uC0C1\uC138 (\uCD5C\uADFC ' + valid.length + '\uC8FC)';
      const closeBtn = document.createElement('button');
      closeBtn.className = 'text-white/25 hover:text-white/50 text-xs spring';
      closeBtn.textContent = '\u2715';
      closeBtn.addEventListener('click', () => { drillEl.classList.add('hidden'); drillEl.textContent = ''; });
      headerRow.append(titleText, closeBtn);
      drillEl.appendChild(headerRow);

      // Aggregate the specific hour across the loaded dates
      const projAgg = new Map();
      let totalMsg = 0, totalCost = 0;
      for (const data of valid) {
        const hSlot = (data.hours || []).find(h => parseInt(h.hour, 10) === hour);
        if (!hSlot || !hSlot.message_count) continue;
        totalMsg += hSlot.message_count;
        totalCost += hSlot.cost_usd || 0;
        for (const [name, p] of Object.entries(hSlot.projects)) {
          const prev = projAgg.get(name) || { msg: 0, cost: 0, sessions: 0 };
          prev.msg += p.message_count || 0;
          prev.cost += p.cost_usd || 0;
          prev.sessions += p.session_count || 0;
          projAgg.set(name, prev);
        }
      }

      // Summary cards
      const grid = document.createElement('div');
      grid.className = 'grid grid-cols-3 gap-2 mb-2';
      const mkC = (label, val, cls) => {
        const c = document.createElement('div'); c.className = 'bg-white/[0.03] rounded-lg p-1.5 text-center';
        const v = document.createElement('div'); v.className = 'text-xs font-bold ' + (cls || 'text-white/70'); v.textContent = val;
        const l = document.createElement('div'); l.className = 'text-[8px] text-white/25 mt-0.5'; l.textContent = label;
        c.append(v, l); return c;
      };
      grid.append(
        mkC('\uBA54\uC2DC\uC9C0', fmtN(totalMsg) + '\uAC74'),
        mkC('\uBE44\uC6A9', fmt$(totalCost), 'text-amber-400/70'),
        mkC('\uD504\uB85C\uC81D\uD2B8', fmtN(projAgg.size) + '\uAC1C', 'text-cyan-400/70'),
      );
      drillEl.appendChild(grid);

      // Per-project breakdown
      const sorted = [...projAgg.entries()].sort((a, b) => b[1].cost - a[1].cost);
      for (const [name, agg] of sorted) {
        const row = document.createElement('div');
        row.className = 'flex items-center justify-between py-1 text-[10px] border-b border-white/[0.02]';
        const rLeft = document.createElement('span');
        rLeft.className = 'text-white/50 truncate max-w-[140px]'; rLeft.textContent = name; rLeft.title = name;
        const rRight = document.createElement('div');
        rRight.className = 'flex items-center gap-2 text-white/35 tabular-nums';
        const rm = document.createElement('span'); rm.textContent = fmtN(agg.msg) + '\uAC74';
        const rc = document.createElement('span'); rc.className = 'text-amber-400/60'; rc.textContent = fmt$(agg.cost);
        const rs = document.createElement('span'); rs.className = 'text-white/20'; rs.textContent = fmtN(agg.sessions) + '\uC138\uC158';
        rRight.append(rm, rc, rs);
        row.append(rLeft, rRight); drillEl.appendChild(row);
      }

      // Per-date breakdown
      const dateSection = document.createElement('div');
      dateSection.className = 'mt-2 pt-2 border-t border-white/[0.04]';
      const dateTitle = document.createElement('div');
      dateTitle.className = 'text-[9px] text-white/20 uppercase tracking-wider mb-1';
      dateTitle.textContent = '\uB0A0\uC9DC\uBCC4';
      dateSection.appendChild(dateTitle);
      for (let i = 0; i < valid.length; i++) {
        const data = valid[i];
        const hSlot = (data.hours || []).find(h => parseInt(h.hour, 10) === hour);
        if (!hSlot || !hSlot.message_count) continue;
        const dRow = document.createElement('div');
        dRow.className = 'flex items-center justify-between py-0.5 text-[10px]';
        const dLeft = document.createElement('span'); dLeft.className = 'text-white/40 tabular-nums'; dLeft.textContent = datesToLoad[i];
        const dRight = document.createElement('div'); dRight.className = 'flex gap-2 text-white/30 tabular-nums';
        const dm = document.createElement('span'); dm.textContent = fmtN(hSlot.message_count) + '\uAC74';
        const dc = document.createElement('span'); dc.className = 'text-amber-400/50'; dc.textContent = fmt$(hSlot.cost_usd);
        dRight.append(dm, dc); dRow.append(dLeft, dRight);
        dateSection.appendChild(dRow);
      }
      drillEl.appendChild(dateSection);
    });
}


// ─── Timeline node filter population ─────────────────────────────────
let _tlNodePopulated = false;
function _populateTlNodeFilter() {
  const sel = document.getElementById('tlNodeFilter');
  if (!sel || _tlNodePopulated) return;
  if (!state.nodes || !state.nodes.length) {
    // Retry after loadNodes completes
    if (typeof loadNodes === 'function') {
      loadNodes().then(() => { _tlNodePopulated = false; _populateTlNodeFilter(); });
    }
    return;
  }
  _tlNodePopulated = true;
  const cur = sel.value;
  sel.textContent = '';
  const all = document.createElement('option');
  all.value = ''; all.textContent = '\uC804\uCCB4 \uB178\uB4DC'; sel.appendChild(all);
  for (const n of state.nodes) {
    const o = document.createElement('option');
    o.value = n.node_id;
    o.textContent = (n.label || n.node_id) + (n.session_count ? ' (' + n.session_count + ')' : '');
    sel.appendChild(o);
  }
  sel.value = cur;
}


